{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/01_meta/schemas/project.schema.json",
  "title": "DSET project manifest",
  "type": "object",
  "required": ["schema_version", "project", "supportability", "structure", "packages", "profiles", "change_contract", "commit_provenance", "verification", "canonical_command"],
  "properties": {
    "schema_version": {"oneOf": [{"enum": [1.0, 1.1]}, {"type": "string", "pattern": "^1\\.(?:0|1)-draft$"}, {"enum": ["1.2", "1.3", "1.4", "1.5"]}]},
    "artifacts": {
      "type": "object",
      "required": ["subtype_in_names", "creation_strictness"],
      "properties": {
        "subtype_in_names": {"type": "boolean"},
        "creation_strictness": {"enum": ["medium", "high"]}
      },
      "additionalProperties": false
    },
    "workflows": {"type": "object"},
    "changes": {"type": "object"},
    "delegation": {"type": "object"},
    "priority": {"type": "object"},
    "project": {
      "type": "object",
      "required": ["key", "id", "name", "repository_slug", "repository_role"],
      "properties": {
        "key": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*$"},
        "id": {"$ref": "#/$defs/kebab"},
        "name": {"type": "string", "minLength": 1},
        "repository_slug": {"$ref": "#/$defs/kebab"},
        "repository_role": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "supportability": {
      "type": "object",
      "required": ["status", "reason", "authority", "runbook"],
      "properties": {
        "status": {"enum": ["not-applicable", "applicable"]},
        "reason": {"type": "string", "minLength": 1},
        "authority": {"type": "string", "minLength": 1},
        "runbook": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "release": {
      "type": "object",
      "required": ["status"],
      "properties": {
        "status": {"enum": ["not-applicable", "applicable"]},
        "integration_branch": {"type": "string", "minLength": 1},
        "protected_branch": {"type": "string", "minLength": 1},
        "publisher": {"type": "string", "minLength": 1},
        "tag_pattern": {"type": "string", "maxLength": 128, "pattern": "^[A-Za-z0-9._/-]*\\{product_version\\}[A-Za-z0-9._/-]*$"},
        "reason": {"type": "string", "minLength": 1}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"const": "applicable"}}},
          "then": {"required": ["integration_branch", "protected_branch", "publisher", "tag_pattern"]},
          "else": {"required": ["reason"]}
        }
      ],
      "additionalProperties": false
    },
    "work_items": {
      "type": "object",
      "properties": {
        "registry": {"type": "string", "minLength": 1},
        "atomic_scopes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}}
      },
      "oneOf": [{"required": ["registry"]}, {"required": ["atomic_scopes"]}],
      "additionalProperties": false
    },
    "contracts": {"$ref": "#/$defs/contract_ids"},
    "stories": {"$ref": "#/$defs/story_ids"},
    "outcomes": {"$ref": "#/$defs/outcome_ids"},
    "work_areas": {"$ref": "#/$defs/work_areas"},
    "structure": {
      "type": "object"
    },
    "packages": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object"
      }
    },
    "profiles": {
      "type": "object",
      "required": ["runtime_risk", "durability_topology", "enforcement"],
      "properties": {
        "runtime_risk": {"type": "string", "minLength": 1},
        "durability_topology": {"type": "string", "minLength": 1},
        "enforcement": {"type": "string", "minLength": 1},
        "artifact": {"type": ["string", "null"], "minLength": 1},
        "repository_governance": {"type": ["string", "null"], "minLength": 1},
        "implementation": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/implementation_profile_selection"}}
      },
      "additionalProperties": false
    },
    "change_contract": {
      "type": "object"
    },
    "commit_provenance": {
      "type": "object",
      "required": ["start_commit"],
      "properties": {
        "start_commit": {
          "oneOf": [
            {"enum": ["root", "manifest-addition"]},
            {"type": "string", "pattern": "^[0-9a-f]{40}$"}
          ]
        },
        "corrections": {
          "type": "array",
          "uniqueItems": true,
          "items": {"$ref": "#/$defs/commit_provenance_correction"}
        }
      },
      "additionalProperties": false
    },
    "verification": {
      "type": "object",
      "required": ["commands"],
      "properties": {
        "commands": {
          "type": "array",
          "minItems": 1,
          "items": {"type": "string", "minLength": 1}
        }
      },
      "additionalProperties": false
    },
    "canonical_command": {"type": "string", "minLength": 1}
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"enum": ["1.2", "1.3", "1.4", "1.5"]}}, "required": ["schema_version"]},
      "then": {
        "required": ["release", "work_items", "work_areas"],
        "not": {
          "anyOf": [
            {"required": ["contracts"]},
            {"required": ["stories"]},
            {"required": ["outcomes"]}
          ]
        },
        "properties": {
          "structure": {"$ref": "#/$defs/layered_structure"},
          "packages": {"type": "array", "minItems": 1, "items": {"$ref": "#/$defs/layered_package"}},
          "work_items": {"type": "object"},
          "change_contract": {"$ref": "#/$defs/layered_change_contract"}
        }
      },
      "else": {
        "not": {"required": ["work_areas"]},
        "properties": {
          "structure": {"$ref": "#/$defs/legacy_structure"},
          "packages": {"type": "array", "minItems": 1, "items": {"$ref": "#/$defs/legacy_package"}},
          "change_contract": {"$ref": "#/$defs/legacy_change_contract"}
        }
      }
    },
    {
      "if": {"properties": {"schema_version": {"enum": [1.1, "1.1-draft"]}}},
      "then": {
        "required": ["release", "work_items", "contracts"],
        "properties": {
          "work_items": {"properties": {"registry": {"enum": ["dset/intake.toml", "dset/intake.yaml"]}}}
        }
      }
    }
  ],
  "$defs": {
    "kebab": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
    "layer": {"enum": ["meta", "gov", "tool", "skill", "implementation", "ops"]},
    "implementation_profile_selection": {
      "type": "object",
      "required": ["id", "version", "work_areas"],
      "properties": {
        "id": {"$ref": "#/$defs/kebab"},
        "version": {"type": "string", "minLength": 1},
        "work_areas": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/kebab"}}
      },
      "additionalProperties": false
    },
    "legacy_structure": {
      "type": "object",
      "required": ["mode", "accepted_truth_root", "active_changes_root", "archive_root", "global_truth_root"],
      "properties": {
        "mode": {"enum": ["single-package", "multi-package"]},
        "accepted_truth_root": {"type": "string"},
        "active_changes_root": {"type": "string"},
        "archive_root": {"type": "string"},
        "global_truth_root": {"type": ["string", "null"]}
      },
      "additionalProperties": false
    },
    "layered_structure": {
      "type": "object",
      "required": ["layout"],
      "properties": {"layout": {"enum": ["layered-v1", "slim-v1", "numbered-layers-v1", "recursive-framework-v1", "separated-methodology-v1"]}},
      "additionalProperties": false
    },
    "legacy_package": {
      "type": "object",
      "required": ["id", "path", "status"],
      "properties": {
        "id": {"$ref": "#/$defs/kebab"},
        "path": {"type": "string"},
        "status": {"enum": ["active", "retired"]}
      },
      "additionalProperties": false
    },
    "layered_package": {
      "type": "object",
      "required": ["id", "status", "layers"],
      "properties": {
        "id": {"$ref": "#/$defs/kebab"},
        "status": {"enum": ["active", "retired"]},
        "layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/layer"}}
      },
      "additionalProperties": false
    },
    "legacy_change_contract": {
      "type": "object",
      "required": ["change_id_format", "pull_request_required_before_archive", "archive_requires_fresh_verification", "keep_pull_request_draft_until_archive_ready"],
      "properties": {
        "change_id_format": {"const": "kebab-case"},
        "pull_request_required_before_archive": {"const": true},
        "archive_requires_fresh_verification": {"const": true},
        "keep_pull_request_draft_until_archive_ready": {"const": true}
      },
      "additionalProperties": false
    },
    "layered_change_contract": {
      "type": "object",
      "required": ["change_id_format", "change_slug_format", "pull_request_required_before_archive", "archive_requires_fresh_verification", "keep_pull_request_draft_until_archive_ready"],
      "properties": {
        "change_id_format": {"const": "project-type-layer-sequence"},
        "change_slug_format": {"const": "kebab-case"},
        "pull_request_required_before_archive": {"const": true},
        "archive_requires_fresh_verification": {"const": true},
        "keep_pull_request_draft_until_archive_ready": {"const": true}
      },
      "additionalProperties": false
    },
    "work_areas": {
      "$comment": "Each id and path must also be unique across the array; repository validation enforces property-level uniqueness.",
      "type": "array",
      "uniqueItems": true,
      "items": {"$ref": "#/$defs/work_area"}
    },
    "work_area": {
      "type": "object",
      "required": ["id", "path"],
      "properties": {
        "id": {"$ref": "#/$defs/kebab"},
        "path": {"$ref": "#/$defs/repository_relative_path"}
      },
      "additionalProperties": false
    },
    "repository_relative_path": {
      "type": "string",
      "minLength": 1,
      "pattern": "^(?!/)(?![A-Za-z]:)(?!.*\\\\)(?!.*//)(?!\\.{1,2}(?:/|$))(?!.*[/]\\.{1,2}(?:/|$))[^/]+(?:/[^/]+)*$"
    },
    "commit_provenance_correction": {
      "type": "object",
      "required": ["commit", "original_message_sha256", "mode", "decision_ids", "verifies", "resolves", "session", "rationale"],
      "properties": {
        "commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"},
        "original_message_sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"},
        "mode": {"enum": ["implementation", "evidence"]},
        "decision_ids": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}},
        "verifies": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}},
        "resolves": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}},
        "session": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"},
        "rationale": {"type": "string", "minLength": 1}
      },
      "allOf": [
        {
          "if": {"properties": {"mode": {"const": "implementation"}}, "required": ["mode"]},
          "then": {"properties": {"verifies": {"maxItems": 0}}},
          "else": {"properties": {"verifies": {"minItems": 1}}}
        }
      ],
      "additionalProperties": false
    },
    "contract_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "story_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "outcome_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}}
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/01_meta/schemas/version.schema.json",
  "title": "DSET product version contract",
  "type": "object",
  "required": ["schema_version", "framework", "python_package", "schemas", "released_validator", "candidate_validator", "bootstrap"],
  "properties": {
    "schema_version": {"oneOf": [{"enum": [1.0, 1.1]}, {"const": "1.2"}]},
    "framework": {"oneOf": [{"$ref": "#/$defs/legacy_framework"}, {"$ref": "#/$defs/current_framework"}]},
    "python_package": {"oneOf": [{"$ref": "#/$defs/legacy_python_package"}, {"$ref": "#/$defs/current_python_package"}]},
    "schemas": {
      "type": "object",
      "required": ["version", "versioning"],
      "properties": {
        "version": {"type": "string"},
        "versioning": {"const": "independent"}
      },
      "additionalProperties": false
    },
    "released_validator": {"$ref": "#/$defs/validator"},
    "candidate_validator": {
      "type": "object",
      "required": ["command"],
      "properties": {"command": {"type": "string", "minLength": 1}},
      "additionalProperties": false
    },
    "bootstrap": {
      "type": "object",
      "required": ["manifest", "governance_registry", "precedence"],
      "properties": {
        "manifest": {"type": "string", "minLength": 1},
        "governance_registry": {"type": "string", "minLength": 1},
        "precedence": {"const": "project-local-rule-then-selected-local-profile-then-failure"}
      },
      "additionalProperties": false
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"const": 1.0}}},
      "then": {"properties": {"framework": {"$ref": "#/$defs/legacy_framework"}, "python_package": {"$ref": "#/$defs/legacy_python_package"}}},
      "else": {"properties": {"framework": {"$ref": "#/$defs/current_framework"}, "python_package": {"$ref": "#/$defs/current_python_package"}}}
    },
    {
      "if": {"properties": {"schema_version": {"const": "1.2"}}, "required": ["schema_version"]},
      "then": {
        "properties": {
          "bootstrap": {
            "properties": {
              "manifest": {"enum": [".dset/dset_settings.toml", "dset/scopes/meta/dset.toml", "dset/scopes/meta/dset.yaml"]},
              "governance_registry": {"enum": ["00_project/governance.toml", "dset/scopes/gov/governance.toml", "dset/scopes/gov/governance.yaml"]}
            }
          }
        }
      },
      "else": {
        "properties": {
          "bootstrap": {
            "properties": {
              "manifest": {"enum": ["dset/dset.toml", "dset/dset.yaml"]},
              "governance_registry": {"enum": ["dset/governance.toml", "dset/governance.yaml"]}
            }
          }
        }
      }
    }
  ],
  "$defs": {
    "legacy_framework": {
      "type": "object",
      "required": ["milestone", "status", "versioning"],
      "properties": {
        "milestone": {"const": "0.2"},
        "status": {"enum": ["candidate", "released"]},
        "versioning": {"const": "independent-framework-milestone"}
      },
      "additionalProperties": false
    },
    "current_framework": {
      "type": "object",
      "required": ["version", "versioning"],
      "properties": {
        "version": {"$ref": "#/$defs/semver"},
        "versioning": {"const": "coordinated-product-package"}
      },
      "additionalProperties": false
    },
    "legacy_python_package": {
      "type": "object",
      "required": ["name", "version", "versioning"],
      "properties": {
        "name": {"const": "dset-spec-loops"},
        "version": {"$ref": "#/$defs/pep440"},
        "versioning": {"const": "independent"}
      },
      "additionalProperties": false
    },
    "current_python_package": {
      "type": "object",
      "required": ["name", "version", "versioning"],
      "properties": {
        "name": {"const": "dset-spec-loops"},
        "version": {"$ref": "#/$defs/pep440"},
        "versioning": {"const": "coordinated-product-package"}
      },
      "additionalProperties": false
    },
    "semver": {
      "type": "string",
      "pattern": "^(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)(?:-rc\\.[1-9][0-9]*)?$"
    },
    "pep440": {
      "type": "string",
      "pattern": "^(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)(?:rc[1-9][0-9]*)?$"
    },
    "validator": {
      "type": "object",
      "required": ["identity", "commit", "command"],
      "properties": {
        "identity": {"type": "string", "minLength": 1},
        "commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"},
        "command": {"type": "string", "minLength": 1},
        "assurance": {"enum": ["published-release", "bootstrap-transition"]}
      },
      "allOf": [
        {
          "if": {"properties": {"identity": {"pattern": "not-release$"}}, "required": ["identity"]},
          "then": {"required": ["assurance"], "properties": {"assurance": {"const": "bootstrap-transition"}}}
        }
      ],
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files..dset/000_dset_methodology/02_gov/120_sc:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/02_gov/schemas/atom.schema.json",
  "title": "DSET semantic atom frontmatter",
  "type": "object",
  "required": ["artifact_type", "artifact_id", "type", "semantic_id", "status", "priority", "authority", "claim", "scope", "promotion", "llm_session_ids"],
  "properties": {
    "artifact_type": {"const": "atomic_record"},
    "artifact_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-ATOMIC-RECORD-[0-9]{3,}$"},
    "type": {"enum": ["decision", "question", "problem", "qa"]},
    "subtype": {"enum": ["requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant", "conflict", "risk", "opportunity", "defect", "gap", "debt", "test", "evaluation"]},
    "semantic_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"},
    "status": {"enum": ["proposed", "accepted"]},
    "priority": {"type": "string", "minLength": 1},
    "authority": {"type": "string", "pattern": "^(operator|repository|external):[A-Za-z0-9._:-]+$"},
    "claim": {"type": "string", "minLength": 1},
    "scope": {
      "type": "object",
      "required": ["kind", "id"],
      "properties": {
        "kind": {"enum": ["project", "layer", "feature_group", "feature"]},
        "id": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "promotion": {
      "type": "object",
      "required": ["parent_scope"],
      "properties": {
        "parent_scope": {
          "oneOf": [
            {"type": "null"},
            {
              "type": "object",
              "required": ["kind", "id"],
              "properties": {
                "kind": {"enum": ["project", "feature_group"]},
                "id": {"type": "string", "minLength": 1}
              },
              "additionalProperties": false
            }
          ]
        },
        "applies_unchanged": {"type": "boolean"},
        "local_context_required": {"type": "boolean"},
        "affected_children": {"type": "array", "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
        "disposition": {"enum": ["keep_local", "promote"]}
      },
      "additionalProperties": false
    },
    "relations": {"type": "array", "minItems": 1, "items": {"$ref": "#/$defs/relation"}},
    "child_of": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
    "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 4096},
    "boundary": {"type": "string", "minLength": 1},
    "lineage": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}},
    "conflict_state": {"enum": ["clear", "unresolved"]},
    "verification_obligation": {"type": "string", "minLength": 1},
    "unknowns": {"type": "array"}
  },
  "allOf": [
    {
      "if": {"properties": {"type": {"const": "qa"}}, "required": ["type"]},
      "then": {"required": ["subtype"], "properties": {"subtype": {"enum": ["test", "evaluation"]}}}
    },
    {
      "if": {"properties": {"type": {"const": "decision"}}, "required": ["type", "subtype"]},
      "then": {"properties": {"subtype": {"enum": ["requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant"]}}}
    },
    {
      "if": {"properties": {"type": {"const": "question"}}, "required": ["type", "subtype"]},
      "then": {"properties": {"subtype": {"enum": ["conflict", "risk", "opportunity"]}}}
    },
    {
      "if": {"properties": {"type": {"const": "problem"}}, "required": ["type", "subtype"]},
      "then": {"properties": {"subtype": {"enum": ["defect", "gap", "debt"]}}}
    },
    {
      "not": {"required": ["relations", "child_of"]}
    }
  ],
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"},
    "relation_type": {"enum": ["child_of", "analysis_of", "projection_of", "implementation_of", "check_of", "evidence_for", "resolution_of", "override_of", "replacement_of", "relates_to"]},
    "relation": {
      "oneOf": [
        {
          "type": "object",
          "required": ["type", "target"],
          "properties": {
            "type": {"$ref": "#/$defs/relation_type"},
            "target": {"$ref": "#/$defs/id"}
          },
          "additionalProperties": false
        },
        {
          "type": "object",
          "required": ["type", "range"],
          "properties": {
            "type": {"const": "projection_of"},
            "range": {"$ref": "#/$defs/projection_range"}
          },
          "additionalProperties": false
        }
      ]
    },
    "projection_range": {
      "type": "object",
      "required": ["semantic_type", "scope", "through"],
      "properties": {
        "semantic_type": {"enum": ["decision", "question", "problem", "qa"]},
        "subtype": {"enum": ["none", "requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant", "conflict", "risk", "opportunity", "defect", "gap", "debt", "test", "evaluation"]},
        "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
        "scope": {
          "type": "object",
          "required": ["kind", "id"],
          "properties": {
            "kind": {"enum": ["project", "layer", "feature_group", "feature"]},
            "id": {"type": "string", "minLength": 1}
          },
          "additionalProperties": false
        },
        "through": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-ATOMIC-RECORD-[0-9]{3,}$"}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/02_gov/schemas/change.schema.json",
  "title": "DSET change manifest",
  "type": "object",
  "required": ["schema_version", "id", "profile", "status", "packages", "pull_request", "requirements", "tests", "evals"],
  "properties": {
    "schema_version": {"oneOf": [{"enum": [1.0, 1.1]}, {"type": "string", "pattern": "^1\\.(?:0|1)-draft$"}, {"const": "1.2"}]},
    "id": {"type": "string", "minLength": 1},
    "slug": {"$ref": "#/$defs/kebab"},
    "profile": {"enum": ["small", "standard", "large", "defect", "adoption"]},
    "status": {"enum": ["proposed", "in-progress", "failed", "verified", "archive-ready", "archived"]},
    "primary_layer": {"$ref": "#/$defs/layer"},
    "affected_layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/layer"}},
    "workspace": {"$ref": "#/$defs/workspace"},
    "dependencies": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/dependency"}},
    "priority": {"$ref": "#/$defs/priority"},
    "llm_session_ids": {"$ref": "#/$defs/llm_session_ids"},
    "rationale": {"$ref": "#/$defs/rationale"},
    "target": {"$ref": "#/$defs/target"},
    "packages": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string"}},
    "pull_request": {"$ref": "#/$defs/pr"},
    "release": {"oneOf": [{"$ref": "#/$defs/release"}, {"$ref": "#/$defs/layered_release"}]},
    "intake": {"$ref": "#/$defs/intake_ids"},
    "related_pull_requests": {"type": "array", "items": {"$ref": "#/$defs/related_pr"}},
    "requirements": {"$ref": "#/$defs/legacy_ids"},
    "tests": {"$ref": "#/$defs/legacy_ids"},
    "evals": {"$ref": "#/$defs/legacy_ids"},
    "adrs": {"$ref": "#/$defs/legacy_ids"},
    "decisions": {"$ref": "#/$defs/decision_ids"},
    "contracts": {"$ref": "#/$defs/contract_ids"},
    "stories": {"$ref": "#/$defs/story_ids"},
    "outcomes": {"$ref": "#/$defs/outcome_ids"},
    "archive": {"oneOf": [{"$ref": "#/$defs/legacy_archive"}, {"$ref": "#/$defs/layered_archive"}]}
  },
  "$defs": {
    "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
    "kebab": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
    "sha_or_pending": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
    "change_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|IMPL|OPS)-[0-9]{3,}$"},
    "trace_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:DECISION|REQUIREMENT|CONSTRAINT|CONTRACT|STORY|OUTCOME|SCENARIO|INVARIANT|QUESTION|CONFLICT|RISK|OPPORTUNITY|PROBLEM|DEFECT|GAP|DEBT|TEST|EVAL|EVALUATION|TASK|CHANGE)(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"},
    "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 4096},
    "priority": {"type": "string", "minLength": 1},
    "legacy_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"}},
    "requirement_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-REQUIREMENT(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "test_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-TEST(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "eval_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:EVAL|EVALUATION)(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "intake_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:QUESTION|CONFLICT|RISK|OPPORTUNITY|PROBLEM|DEFECT|GAP|DEBT)(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "decision_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-DECISION(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "contract_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "story_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "outcome_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|IMPL|OPS))?-[0-9]{3,}$"}},
    "pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"oneOf": [{"type": "integer", "minimum": 1}, {"const": "pending"}]},
        "url": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "exact_pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"type": "integer", "minimum": 1},
        "url": {"type": "string", "format": "uri", "pattern": "^https://"}
      },
      "additionalProperties": false
    },
    "workspace": {
      "type": "object",
      "required": ["isolation", "branch", "base_ref", "base_commit", "head_commit"],
      "properties": {
        "isolation": {"enum": ["integration-branch", "branch-worktree"]},
        "branch": {"type": "string", "minLength": 1},
        "base_ref": {"type": "string", "minLength": 1},
        "base_commit": {"$ref": "#/$defs/sha_or_pending"},
        "head_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "dependency": {
      "type": "object",
      "required": ["change_id", "pull_request", "required_commit", "consumes", "claim", "use", "evidence", "checked_at", "reopen_when", "status"],
      "properties": {
        "change_id": {"$ref": "#/$defs/change_id"},
        "pull_request": {"$ref": "#/$defs/pr"},
        "required_commit": {"$ref": "#/$defs/sha_or_pending"},
        "consumes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/trace_id"}},
        "claim": {"type": "string", "minLength": 1},
        "use": {"type": "string", "minLength": 1},
        "evidence": {"type": "string", "minLength": 1},
        "checked_at": {"type": "string", "format": "date"},
        "reopen_when": {"type": "string", "minLength": 1},
        "status": {"enum": ["planned", "available", "integrated", "blocked", "stale"]}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"enum": ["available", "integrated"]}}, "required": ["status"]},
          "then": {
            "properties": {
              "pull_request": {"$ref": "#/$defs/exact_pr"},
              "required_commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"}
            }
          }
        }
      ],
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/kebab"}}
      },
      "oneOf": [
        {
          "properties": {
            "repository": {"const": true},
            "work_areas": {"maxItems": 0}
          }
        },
        {
          "properties": {
            "repository": {"const": false},
            "work_areas": {"minItems": 1}
          }
        }
      ],
      "additionalProperties": false
    },
    "related_pr": {
      "type": "object",
      "required": ["number", "role"],
      "properties": {
        "number": {"type": "integer", "minimum": 1},
        "role": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "release": {
      "oneOf": [
        {"$ref": "#/$defs/release_declaration"},
        {"$ref": "#/$defs/release_reference"}
      ]
    },
    "release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"const": "dset/governance/release.md"},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {
          "type": "object",
          "required": ["ref", "commit", "version"],
          "properties": {
            "ref": {"type": "string", "minLength": 1},
            "commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
            "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
          },
          "additionalProperties": false
        },
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {
          "oneOf": [
            {"const": "pending"},
            {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._-]*\\.md$"}
          ]
        },
        "candidate_commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]}
      },
      "additionalProperties": false
    },
    "release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {
        "owner_change": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}
      },
      "additionalProperties": false
    },
    "layered_release": {
      "oneOf": [
        {"$ref": "#/$defs/layered_release_declaration"},
        {"$ref": "#/$defs/layered_release_reference"}
      ]
    },
    "layered_release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"enum": ["dset/scopes/ops/governance/release.md", ".dset/000_dset_methodology/06_ops/procedure-release.md"]},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {"$ref": "#/$defs/release_base"},
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {
          "oneOf": [
            {"const": "pending"},
            {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._-]*\\.md$"}
          ]
        },
        "candidate_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "layered_release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {"owner_change": {"$ref": "#/$defs/change_id"}},
      "additionalProperties": false
    },
    "release_base": {
      "type": "object",
      "required": ["ref", "commit", "version"],
      "properties": {
        "ref": {"type": "string", "minLength": 1},
        "commit": {"$ref": "#/$defs/sha_or_pending"},
        "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
      },
      "additionalProperties": false
    },
    "semver": {
      "type": "string",
      "pattern": "^(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)(?:-rc\\.[1-9][0-9]*)?$"
    },
    "legacy_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    },
    "layered_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/(?:meta|gov|tool|skill|ops)/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"enum": [1.0, "1.0-draft"]}}},
      "then": {
        "required": ["adrs"],
        "not": {"required": ["decisions"]}
      },
      "else": {
        "required": ["release", "intake", "decisions", "contracts", "llm_session_ids"],
        "not": {"required": ["adrs"]},
        "properties": {
          "requirements": {"$ref": "#/$defs/requirement_ids"},
          "tests": {"$ref": "#/$defs/test_ids"},
          "evals": {"$ref": "#/$defs/eval_ids"},
          "intake": {"$ref": "#/$defs/intake_ids"},
          "decisions": {"$ref": "#/$defs/decision_ids"},
          "contracts": {"$ref": "#/$defs/contract_ids"},
          "stories": {"$ref": "#/$defs/story_ids"},
          "outcomes": {"$ref": "#/$defs/outcome_ids"}
        }
      }
    },
    {
      "if": {"properties": {"schema_version": {"const": "1.2"}}, "required": ["schema_version"]},
      "then": {
        "required": ["slug", "stories", "outcomes", "primary_layer", "affected_layers", "workspace", "dependencies", "target"],
        "properties": {
          "id": {"$ref": "#/$defs/change_id"},
          "release": {"$ref": "#/$defs/layered_release"},
          "archive": {"$ref": "#/$defs/layered_archive"}
        }
      },
      "else": {
        "not": {
          "anyOf": [
            {"required": ["slug"]},
            {"required": ["primary_layer"]},
            {"required": ["affected_layers"]},
            {"required": ["workspace"]},
            {"required": ["dependencies"]},
            {"required": ["target"]}
          ]
        },
        "properties": {
          "id": {"$ref": "#/$defs/kebab"},
          "release": {"$ref": "#/$defs/release"},
          "archive": {"$ref": "#/$defs/legacy_archive"}
        }
      }
    }
  ],
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/02_gov/schemas/compilation.schema.json",
  "title": "DSET active authority compilation index",
