    "fragment": {"type": "object", "required": ["kind", "line", "sha256"], "properties": {"kind": {"enum": ["section", "table-row", "labeled-block"]}, "line": {"type": "integer", "minimum": 1}, "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"}}, "additionalProperties": false},
    "projection": {"type": "object", "required": ["carrier", "sha256", "fragments"], "properties": {"carrier": {"type": "string", "pattern": "^[^/\\\\]+$"}, "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"}, "fragments": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/fragment"}}}, "additionalProperties": false},
    "record": {"type": "object", "required": ["id", "source", "projections"], "properties": {"id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}, "source": {"$ref": "#/$defs/identity"}, "projections": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/projection"}}}, "additionalProperties": false}
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/02_gov/schemas/conflict-candidate.schema.json",
  "title": "DSET governed conflict candidate",
  "type": "object",
  "required": ["left", "right", "context"],
  "properties": {
    "left": {"$ref": "#/$defs/party"},
    "right": {"$ref": "#/$defs/party"},
    "context": {
      "type": "object",
      "required": ["applicable", "same_scope", "same_concern", "same_effective_time", "evidence"],
      "properties": {
        "applicable": {"type": "boolean"},
        "same_scope": {"type": "boolean"},
        "same_concern": {"type": "boolean"},
        "same_effective_time": {"type": "boolean"},
        "evidence": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/identity"}}
      },
      "additionalProperties": false
    },
    "relation": {"enum": ["none", "source_projection", "absorption"]},
    "relation_winner": {"$ref": "#/$defs/id"},
    "selectable": {"type": "boolean"},
    "precedence": {"$ref": "#/$defs/id"},
    "conflict_atom": {"$ref": "#/$defs/conflict_atom"}
  },
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"},
    "identity": {
      "type": "object",
      "required": ["carrier", "sha256"],
      "properties": {
        "carrier": {"type": "string", "pattern": "^[^/\\\\]+$"},
        "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"}
      },
      "additionalProperties": false
    },
    "priority": {"type": "string", "minLength": 1},
    "party": {
      "type": "object",
      "required": ["id"],
      "properties": {
        "id": {"$ref": "#/$defs/id"},
        "source": {"$ref": "#/$defs/identity"},
        "role": {"enum": ["atomic_authority", "evergreen_projection", "external_authority", "implementation", "qa", "evidence", "verification", "readiness", "derived_view"]},
        "priority": {"$ref": "#/$defs/priority"},
        "priority_source": {"type": "string", "minLength": 1},
        "immutable": {"type": "boolean"},
        "external": {"type": "boolean"},
        "scope": {"$ref": "#/$defs/scope"},
        "current_status": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "scope": {
      "type": "object",
      "required": ["kind", "id"],
      "properties": {
        "kind": {"type": "string", "minLength": 1},
        "id": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "conflict_atom": {
      "type": "object",
      "required": ["artifact_id", "semantic_id", "authority", "claim", "scope", "llm_session_ids", "material_links", "promotion", "acceptance", "priority", "lineage"],
      "properties": {
        "artifact_id": {"$ref": "#/$defs/id"},
        "semantic_id": {"$ref": "#/$defs/id"},
        "authority": {"type": "string", "minLength": 1},
        "claim": {"type": "string", "minLength": 1},
        "type": {"const": "question"},
        "subtype": {"const": "conflict"},
        "scope": {"$ref": "#/$defs/scope"},
        "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
        "material_links": {"type": "array", "minItems": 2, "maxItems": 2, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
        "promotion": {"type": "object"},
        "acceptance": {"enum": ["proposed", "accepted"]},
        "priority": {"$ref": "#/$defs/priority"},
        "lineage": {"type": "array", "minItems": 2, "maxItems": 2, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
        "rationale": {"type": "string", "minLength": 1, "maxLength": 4096},
        "boundary": {"type": "string", "minLength": 1},
        "conflict_state": {"type": "string", "minLength": 1},
        "verification_obligation": {"type": "string", "minLength": 1},
        "unknowns": {"type": "array"}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/000_dset_methodology/02_gov/schemas/evidence-record.schema.json",
  "title": "DSET native Evidence Record TOML frontmatter",
  "type": "object",
  "required": [
    "schema_version",
    "artifact_type",
    "artifact_subtype",
    "artifact_id",
    "priority",
    "llm_session_ids",
    "subject",
    "producer",
    "method",
    "context",
    "evidence_location",
    "polarity",
    "currentness",
    "reopen_when",
    "relations"
  ],
  "properties": {
    "schema_version": {"const": "1.0"},
    "artifact_type": {"const": "evidence_record"},
    "artifact_subtype": {
      "enum": ["test_result", "evaluation_result", "review_report", "run_record"]
    },
    "artifact_id": {"$ref": "#/$defs/id"},
    "priority": {"type": "string", "minLength": 1},
    "llm_session_ids": {
      "type": "array",
      "uniqueItems": true,
      "items": {
        "type": "string",
        "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"
      }
    },
    "subject": {"$ref": "#/$defs/subject"},
    "producer": {"$ref": "#/$defs/producer"},
    "method": {"$ref": "#/$defs/method"},
    "context": {
      "type": "array",
      "minItems": 1,
      "items": {"type": "string", "minLength": 1}
    },
    "observed_at": {"type": "string", "format": "date-time"},
    "validity_window": {"$ref": "#/$defs/validity_window"},
    "evidence_location": {"type": "string", "minLength": 1},
    "polarity": {
      "enum": ["supports", "contradicts", "mixed", "inconclusive"]
    },
