from __future__ import annotations

import sys
from pathlib import Path


def _project_root(start: Path) -> Path:
    for candidate in start.resolve().parents:
        if (candidate / ".dset" / "dset_settings.toml").is_file():
            return candidate
    raise FileNotFoundError("DSET project root is unavailable")


def main() -> int:
    sys.dont_write_bytecode = True
    carrier = Path(__file__).resolve()
    local_package_root = carrier.parent
    project_root = _project_root(carrier)
    package_root = (
        local_package_root
        if (local_package_root / "dset_toolchain").is_dir()
        else project_root
    )
    sys.path.insert(0, str(package_root))

    from dset_toolchain.cli import main as dset_main

    return dset_main()


if __name__ == "__main__":
    raise SystemExit(main())

from __future__ import annotations

import re
from collections.abc import Mapping, Sequence
from pathlib import Path
from typing import Any

from .layout import LAYERS, discover_layout
from .lineage import collect_artifact_relations
from .semantic_types import SEMANTIC_SUBTYPES, build_semantic_classification_index
from .settings import load_project_settings
from .yaml_subset import load

SESSION_PATTERN = re.compile(r"^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$")
AUTHORITY_PATTERN = re.compile(r"^(?:operator|repository|external):[A-Za-z0-9._:-]+$")

MEDIUM_FIELDS = (
    "authority",
    "claim",
    "type",
    "scope",
    "llm_session_ids",
    "material_links",
    "priority",
    "acceptance",
    "promotion",
)
HIGH_FIELDS = (
    "boundary",
    "lineage",
    "conflict_state",
    "verification_obligation",
)
FIELD_QUESTIONS = {
    "authority": "Who or what authorizes this atomic claim?",
    "claim": "What is the one precise primary claim to preserve?",
    "type": "Which one semantic Type owns this claim?",
    "scope": "What is the narrowest structural scope that owns this claim?",
    "llm_session_ids": "Which explicit LLM session IDs produced this candidate?",
    "material_links": "Which material parent or related artifact IDs apply?",
    "promotion": "What is the immediately broader enabled scope, if any?",
    "boundary": "What exact boundary and exclusions make the claim immutable?",
    "priority": "What effective project priority applies to this artifact?",
    "lineage": "Which immediate parent IDs apply, including an explicit empty list?",
    "acceptance": "What is the explicit acceptance or recording state?",
    "conflict_state": "Is any applicable authority conflict unresolved?",
    "verification_obligation": "What proof obligation applies, including none?",
}
ALLOWED_PROMOTION_STEPS = frozenset(
    {
        ("feature", "feature_group"),
        ("feature", "project"),
        ("feature_group", "project"),
        ("layer", "project"),
    }
)


def assess_artifact_candidate(
    root: Path, candidate: Mapping[str, Any]
) -> dict[str, Any]:
    settings, settings_issues = load_project_settings(root)
    if settings_issues:
        raise ValueError("; ".join(settings_issues))
    strictness = settings.artifact_creation_strictness
    fields = MEDIUM_FIELDS + (HIGH_FIELDS if strictness == "high" else ())
    diagnostics: list[dict[str, str]] = []
    questions: list[str] = []

    for field in fields:
        if not _has_explicit_value(candidate, field):
            diagnostics.append(
                {
                    "code": "DSET-ARTIFACT-MISSING",
                    "field": field,
                    "message": f"material field is not explicit: {field}",
                }
            )
            questions.append(FIELD_QUESTIONS[field])

    diagnostics.extend(_semantic_diagnostics(candidate))
    diagnostics.extend(_shape_diagnostics(candidate))
    diagnostics.extend(_value_diagnostics(root, candidate, settings.priority_scale))
    unknown_diagnostics, unknown_questions = _unknown_diagnostics(candidate)
    diagnostics.extend(unknown_diagnostics)
    questions.extend(unknown_questions)

    scope_model, scope_diagnostics = _repository_scope_model(root)
    diagnostics.extend(scope_diagnostics)
    promotion = _assess_promotion(candidate, scope_model)
    if promotion["status"] == "invalid":
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-PROMOTION",
                "field": "promotion.parent_scope",
                "message": str(
                    promotion.get("reason", "promotion assessment is invalid")
                ),
            }
        )
    elif promotion["status"] == "proposal-required":
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-PROMOTION-AUTHORITY",
                "field": "promotion.disposition",
                "message": (
                    "eligible broader-scope promotion needs operator disposition"
                ),
            }
        )
        questions.append(str(promotion["question"]))
    elif promotion["status"] == "promote-before-emission":
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-PROMOTE-FIRST",
                "field": "scope",
                "message": "rebuild the candidate at the accepted broader scope",
            }
        )

    return {
        "schema_version": "1.0",
        "strictness": strictness,
        "emission_allowed": not diagnostics,
        "diagnostics": diagnostics,
        "questions": _unique(questions),
        "promotion": promotion,
        "writes_performed": False,
    }


def _has_explicit_value(candidate: Mapping[str, Any], field: str) -> bool:
    if field not in candidate:
        return False
    value = candidate[field]
    if value is None:
        return False
    if isinstance(value, str):
        return bool(value.strip())
    return True


def _semantic_diagnostics(candidate: Mapping[str, Any]) -> list[dict[str, str]]:
    semantic_type = candidate.get("type")
    subtype = candidate.get("subtype")
    if semantic_type not in SEMANTIC_SUBTYPES:
        return [
            {
                "code": "DSET-ARTIFACT-TYPE",
                "field": "type",
                "message": "type must be decision, question, problem, or qa",
            }
        ]
    if subtype is not None and subtype not in SEMANTIC_SUBTYPES[str(semantic_type)]:
        return [
            {
                "code": "DSET-ARTIFACT-SUBTYPE",
                "field": "subtype",
                "message": f"subtype is not valid for {semantic_type}",
            }
        ]
    if semantic_type == "qa" and subtype is None:
        return [
            {
                "code": "DSET-ARTIFACT-SUBTYPE",
                "field": "subtype",
                "message": "qa requires test or evaluation subtype",
            }
        ]
    return []


def _shape_diagnostics(candidate: Mapping[str, Any]) -> list[dict[str, str]]:
    diagnostics: list[dict[str, str]] = []
    for field in ("llm_session_ids", "material_links", "lineage"):
        if field in candidate and not _is_string_sequence(candidate[field]):
            diagnostics.append(
                {
                    "code": "DSET-ARTIFACT-SHAPE",
                    "field": field,
                    "message": f"{field} must be a list of strings",
                }
            )
    scope = candidate.get("scope")
    if scope is not None and not _valid_scope(scope):
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-SCOPE",
                "field": "scope",
                "message": "scope must contain non-empty kind and id strings",
            }
        )
    if "promotion" in candidate and not isinstance(candidate["promotion"], Mapping):
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-PROMOTION",
                "field": "promotion",
                "message": "promotion must be an object",
            }
        )
    return diagnostics


def _value_diagnostics(
    root: Path, candidate: Mapping[str, Any], priorities: Sequence[str]
) -> list[dict[str, str]]:
    diagnostics: list[dict[str, str]] = []
    authority = candidate.get("authority")
    if isinstance(authority, str) and not AUTHORITY_PATTERN.fullmatch(authority):
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-AUTHORITY",
                "field": "authority",
                "message": (
                    "authority must use operator:, repository:, or external: "
                    "with a stable authority ID"
                ),
            }
        )
    sessions = candidate.get("llm_session_ids")
    if _is_string_sequence(sessions):
        assert isinstance(sessions, Sequence) and not isinstance(sessions, str)
        normalized = [str(item) for item in sessions]
        if len(normalized) != len(set(normalized)) or any(
            not SESSION_PATTERN.fullmatch(item) for item in normalized
        ):
            diagnostics.append(
                {
                    "code": "DSET-ARTIFACT-SESSION",
                    "field": "llm_session_ids",
                    "message": "LLM session IDs must be unique provider:id values",
                }
            )
    priority = candidate.get("priority")
    if isinstance(priority, str) and priority not in {*priorities, "unknown"}:
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-PRIORITY",
                "field": "priority",
                "message": "priority is not in the repository priority scale",
            }
        )
    acceptance = candidate.get("acceptance")
    if isinstance(acceptance, str) and acceptance not in {"proposed", "accepted"}:
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-ACCEPTANCE",
                "field": "acceptance",
                "message": "acceptance must be proposed or accepted",
            }
        )
    conflict_state = candidate.get("conflict_state")
    if isinstance(conflict_state, str) and conflict_state not in {
        "clear",
        "unresolved",
    }:
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-CONFLICT",
                "field": "conflict_state",
                "message": "conflict_state must be clear or unresolved",
            }
        )
    diagnostics.extend(_link_diagnostics(root, candidate))
    return diagnostics


def _link_diagnostics(root: Path, candidate: Mapping[str, Any]) -> list[dict[str, str]]:
    requested: set[str] = set()
    for field in ("material_links", "lineage"):
        value = candidate.get(field)
        if _is_string_sequence(value):
            assert isinstance(value, Sequence) and not isinstance(value, str)
            requested.update(str(item) for item in value)
    if not requested:
        return []
    known: set[str] = set()
    try:
        known.update(
            str(row["id"]) for row in build_semantic_classification_index(root)
        )
        nodes, relation_issues = collect_artifact_relations(root)
        if not relation_issues:
            for node in nodes.values():
                known.update((node.id, node.artifact_id))
    except (OSError, ValueError):
        pass
    missing = sorted(requested - known)
    if not missing:
        return []
    return [
        {
            "code": "DSET-ARTIFACT-LINK",
            "field": "material_links",
            "message": f"linked artifact IDs do not resolve: {', '.join(missing)}",
        }
    ]


def _unknown_diagnostics(
    candidate: Mapping[str, Any],
) -> tuple[list[dict[str, str]], list[str]]:
    raw_unknowns = candidate.get("unknowns", [])
    if not isinstance(raw_unknowns, Sequence) or isinstance(raw_unknowns, str):
        return (
            [
                {
                    "code": "DSET-ARTIFACT-SHAPE",
                    "field": "unknowns",
                    "message": "unknowns must be a list of objects",
                }
            ],
            ["Which candidate details remain unknown, and are they material?"],
        )
    diagnostics: list[dict[str, str]] = []
    questions: list[str] = []
    for index, item in enumerate(raw_unknowns):
        if not isinstance(item, Mapping):
            diagnostics.append(
                {
                    "code": "DSET-ARTIFACT-SHAPE",
                    "field": f"unknowns[{index}]",
                    "message": "unknown entry must be an object",
                }
            )
            continue
        if item.get("material") is not True:
            continue
        field = str(item.get("field", f"unknowns[{index}]"))
        question = str(item.get("question", "")).strip()
        diagnostics.append(
            {
                "code": "DSET-ARTIFACT-AMBIGUOUS",
                "field": field,
                "message": "material ambiguity blocks immutable emission",
            }
        )
        questions.append(question or f"What precise value resolves {field}?")
    return diagnostics, questions


def _assess_promotion(
    candidate: Mapping[str, Any], scope_model: Mapping[str, Any] | None
) -> dict[str, Any]:
    raw = candidate.get("promotion")
    if not isinstance(raw, Mapping):
        return {"status": "not-assessed", "eligible": False}
    scope = candidate.get("scope")
    if not _valid_scope(scope):
        return {"status": "invalid", "eligible": False}
    assert isinstance(scope, Mapping)
    current_key = (str(scope["kind"]), str(scope["id"]))
    if scope_model is None or current_key not in scope_model["scopes"]:
        return {
            "status": "invalid",
            "eligible": False,
            "reason": "scope is not enabled by the repository manifest",
        }
    parent = raw.get("parent_scope")
    if parent is None:
        if scope_model["parents"].get(current_key) is not None:
            return {
                "status": "invalid",
                "eligible": False,
                "reason": "the enabled local scope requires its immediate parent",
            }
        return {
            "status": "not-applicable",
            "eligible": False,
            "reason": "no broader enabled scope",
        }
    if not _valid_scope(parent):
        return {"status": "invalid", "eligible": False}
    assert isinstance(parent, Mapping)
    current_kind = str(scope["kind"])
    parent_kind = str(parent["kind"])
    parent_key = (parent_kind, str(parent["id"]))
    actual_parent = scope_model["parents"].get(current_key)
    if actual_parent != parent_key:
        return {
            "status": "invalid",
            "eligible": False,
            "reason": "parent_scope is not the manifest-defined immediate parent",
        }
    if (current_kind, parent_kind) not in ALLOWED_PROMOTION_STEPS:
        return {
            "status": "invalid",
            "eligible": False,
            "reason": "parent_scope is not an allowed immediate broader step",
        }
    affected = raw.get("affected_children")
    actual_children = scope_model["children"].get(parent_key, ())
    affected_items: tuple[str, ...] = ()
    if _is_string_sequence(affected):
        assert isinstance(affected, Sequence) and not isinstance(affected, str)
        affected_items = tuple(str(item) for item in affected)
    affected_matches = set(affected_items) == set(actual_children)
    eligible = (
        raw.get("applies_unchanged") is True
        and raw.get("local_context_required") is False
        and affected_matches
        and bool(actual_children)
    )
    if not eligible:
        return {
            "status": "keep-local",
            "eligible": False,
            "reason": "claim changes across children or requires local context",
        }
    disposition = raw.get("disposition")
    affected_children = list(affected_items)
    proposal = (
        f"Promote the unchanged claim from {scope['kind']}:{scope['id']} to "
        f"{parent['kind']}:{parent['id']} for {', '.join(affected_children)}?"
    )
    if disposition == "keep_local":
        status = "declined"
    elif disposition == "promote":
        status = "promote-before-emission"
    else:
        status = "proposal-required"
    return {
        "status": status,
        "eligible": True,
        "from_scope": dict(scope),
        "to_scope": dict(parent),
        "affected_children": affected_children,
        "question": proposal,
        "automatic": False,
    }


def _repository_scope_model(
    root: Path,
) -> tuple[dict[str, Any] | None, list[dict[str, str]]]:
    try:
        layout = discover_layout(root)
        manifest = load(layout.manifest_path)
    except (OSError, ValueError) as error:
        return None, [
            {
                "code": "DSET-ARTIFACT-REPOSITORY",
                "field": "scope",
                "message": f"repository scope authority is unavailable: {error}",
            }
        ]
    project = manifest.get("project") if isinstance(manifest, Mapping) else None
    project_id = project.get("id") if isinstance(project, Mapping) else None
    if not isinstance(project_id, str) or not project_id.strip():
        return None, [
            {
                "code": "DSET-ARTIFACT-REPOSITORY",
                "field": "scope",
                "message": "project manifest requires project.id",
            }
        ]
    project_key = ("project", project_id)
    scopes: set[tuple[str, str]] = {project_key}
    parents: dict[tuple[str, str], tuple[str, str]] = {}
    children: dict[tuple[str, str], tuple[str, ...]] = {}
    if layout.layered:
        layer_keys = [("layer", layer) for layer in LAYERS]
        scopes.update(layer_keys)
        parents.update({key: project_key for key in layer_keys})
        children[project_key] = LAYERS
    return {
        "scopes": scopes,
        "parents": parents,
        "children": children,
    }, []


def _valid_scope(value: object) -> bool:
    return (
        isinstance(value, Mapping)
        and isinstance(value.get("kind"), str)
        and bool(str(value["kind"]).strip())
        and isinstance(value.get("id"), str)
        and bool(str(value["id"]).strip())
    )


def _is_string_sequence(value: object) -> bool:
    return (
        isinstance(value, Sequence)
        and not isinstance(value, str)
        and all(isinstance(item, str) and bool(item.strip()) for item in value)
    )


def _unique(values: Sequence[str]) -> list[str]:
    return list(dict.fromkeys(value for value in values if value))

"""Read and validate the legacy aggregate transitions authorized by GOV-018."""

from __future__ import annotations

import hashlib
import json
import os
import re
import subprocess
from copy import deepcopy
from pathlib import Path
from typing import Any
from urllib.parse import unquote

from .frontmatter import parse as parse_frontmatter
from .frontmatter import render as render_frontmatter
from .toml_codec import dumps as dump_toml
from .toml_codec import loads as load_toml
from .yaml_subset import load as load_structured

SCHEMA_VERSION = "1.0"
AUTHORITY_DECISION = "DSET-DECISION-GOV-018"
LAYOUT_AUTHORITY = "DSET-REQUIREMENT-GOV-041"
AUTHORITY_DECISIONS = frozenset(
    {
        AUTHORITY_DECISION,
        LAYOUT_AUTHORITY,
        "DSET-REQUIREMENT-GOV-044",
        "DSET-DECISION-GOV-022",
    }
)
SESSION_ID = "codex:019f591f-04f6-70f2-8de7-828b7cccc69d"
LEDGER_RELATIVE = Path(".dset/100_project/legacy/migrations/carrier-transitions.toml")
LEGACY_LEDGER_RELATIVES = (
    Path("00_project/migrations/carrier-transitions.toml"),
    Path("dset/scopes/gov/migrations/carrier-transitions.toml"),
    Path("dset/migrations/carrier-transitions.toml"),
)
_NULL_SENTINEL = "__DSET_EXPLICIT_NULL__"
_MARKDOWN_LINK = re.compile(r"(?<!!)\[([^\]]+)\]\(([^)]+)\)")


class CarrierTransitionError(ValueError):
    """A carrier transition is missing, lossy, ambiguous, or tampered."""


def ledger_path(root: Path) -> Path:
    current = root / LEDGER_RELATIVE
    if current.is_file():
        return current
    for relative in LEGACY_LEDGER_RELATIVES:
        legacy = root / relative
        if legacy.is_file():
            return legacy
    return current


def transition_id(original_path: str, original_sha256: str) -> str:
    digest = hashlib.sha256(f"{original_path}\0{original_sha256}".encode()).hexdigest()
    return f"DSET-CARRIER-TRANSITION-{digest[:16].upper()}"


def semantic_sha256(value: Any) -> str:
    try:
        payload = json.dumps(
            value,
            sort_keys=True,
            separators=(",", ":"),
            ensure_ascii=False,
            allow_nan=False,
        )
    except (TypeError, ValueError) as error:
        raise CarrierTransitionError(
            f"semantic value is not deterministically serializable: {error}"
        ) from error
    return hashlib.sha256(payload.encode()).hexdigest()


def encode_nulls(value: Any) -> tuple[Any, list[str]]:
    paths: list[str] = []

    def visit(item: Any, path: tuple[str, ...]) -> Any:
        if item is None:
            paths.append(_render_null_path(path))
            return _NULL_SENTINEL
        if isinstance(item, dict):
            encoded: dict[str, Any] = {}
            for key, child in item.items():
                rendered_key = str(key)
                if child is None:
                    paths.append(_render_null_path(path + (rendered_key,)))
                    continue
                encoded[rendered_key] = visit(child, path + (rendered_key,))
            return encoded
        if isinstance(item, list):
            return [
                visit(child, path + (str(index),)) for index, child in enumerate(item)
            ]
        return item

    return visit(deepcopy(value), ()), sorted(paths)


def decode_nulls(value: Any, null_paths: list[str]) -> Any:
    decoded = deepcopy(value)
    for rendered in null_paths:
        parts = _parse_null_path(rendered)
        current = decoded
        for part in parts[:-1]:
            current = current[int(part)] if isinstance(current, list) else current[part]
        final = parts[-1] if parts else ""
        if isinstance(current, list):
            if not final.isdigit() or int(final) >= len(current):
                raise CarrierTransitionError(
                    f"invalid null reconstruction path: {rendered}"
                )
            current[int(final)] = None
        elif isinstance(current, dict):
            current[final] = None
        else:
            raise CarrierTransitionError(
                f"invalid null reconstruction path: {rendered}"
            )
    return decoded


def historical_envelope(
    root: Path, source: Path, target: Path
) -> tuple[str, dict[str, Any]]:
    value = load_structured(source)
    encoded, null_paths = encode_nulls(value)
    _validate_null_paths(source, null_paths, markdown=False)
    original_path = source.relative_to(root).as_posix()
    original_digest = hashlib.sha256(source.read_bytes()).hexdigest()
    semantic_digest = semantic_sha256(value)
    identifier = transition_id(original_path, original_digest)
    envelope = {
        "schema_version": SCHEMA_VERSION,
        "transition_id": identifier,
        "authority_decision": AUTHORITY_DECISION,
        "original_path": original_path,
        "original_format": source.suffix.lstrip("."),
        "original_sha256": original_digest,
        "semantic_sha256": semantic_digest,
        "null_paths": null_paths,
        "declared_loss": [],
        "payload": encoded,
    }
    rendered = dump_toml(envelope)
    reconstructed = decode_historical_envelope(rendered)
    if semantic_sha256(reconstructed) != semantic_digest:
        raise CarrierTransitionError(f"semantic drift while converting {original_path}")
    return rendered, transition_record(
        root,
        source,
        target,
        rendered,
        semantic_digest,
        null_paths,
        kind="structured_yaml",
    )


def decode_historical_envelope(text: str) -> Any:
    data = load_toml(text)
    payload = data.get("payload")
    null_paths = data.get("null_paths")
    if not isinstance(null_paths, list) or not all(
        isinstance(item, str) for item in null_paths
    ):
        raise CarrierTransitionError("historical envelope null_paths must be strings")
    return decode_nulls(payload, null_paths)


def markdown_transition(root: Path, source: Path) -> tuple[str, dict[str, Any]]:
    before = source.read_text(encoding="utf-8")
    parsed = parse_frontmatter(before)
    if parsed is None or parsed[2] != "yaml":
        raise CarrierTransitionError(f"expected YAML frontmatter: {source}")
    metadata, body, _format = parsed
    encoded, null_paths = encode_nulls(metadata)
    _validate_null_paths(source, null_paths, markdown=True)
    if not isinstance(encoded, dict):
        raise CarrierTransitionError(f"frontmatter root changed type: {source}")
    if _contains_null_sentinel(encoded):
        raise CarrierTransitionError(
            f"live TOML frontmatter cannot contain a null sentinel: {source}"
        )
    rendered = render_frontmatter(encoded, body, format="toml")
    reparsed = parse_frontmatter(rendered)
    if reparsed is None:
        raise CarrierTransitionError(f"TOML frontmatter disappeared: {source}")
    source_semantics = {"metadata": metadata, "body": body}
    target_semantics = {
        "metadata": decode_nulls(reparsed[0], null_paths),
        "body": reparsed[1],
    }
    semantic_digest = semantic_sha256(source_semantics)
    if semantic_sha256(target_semantics) != semantic_digest:
        raise CarrierTransitionError(f"semantic drift while converting {source}")
    if semantic_sha256(decode_nulls(encoded, null_paths)) != semantic_sha256(metadata):
        raise CarrierTransitionError(f"null reconstruction failed: {source}")
    return rendered, transition_record(
        root,
        source,
        source,
        rendered,
        semantic_digest,
        null_paths,
        kind="markdown_frontmatter",
    )


def markdown_link_transition(
    root: Path, source: Path, mapping: dict[Path, Path]
) -> tuple[str, dict[str, Any]] | None:
    """Rewrite physical legacy links while preserving their logical targets."""

    before = source.read_text(encoding="utf-8")
    rewrites: list[dict[str, str]] = []

    def replace(match: re.Match[str]) -> str:
        label, raw_target = match.groups()
        wrapped = raw_target.startswith("<") and raw_target.endswith(">")
        target_text = raw_target[1:-1] if wrapped else raw_target
        path_text, marker, anchor = target_text.partition("#")
        if not path_text or path_text.startswith(("http://", "https://", "mailto:")):
            return match.group(0)
        resolved = (source.parent / unquote(path_text)).resolve()
        current = mapping.get(resolved)
        if current is None:
            return match.group(0)
        relative = os.path.relpath(current, source.parent).replace(os.sep, "/")
        replacement_target = relative + (f"#{anchor}" if marker else "")
        if wrapped:
            replacement_target = f"<{replacement_target}>"
        rewrites.append(
            {
                "source": raw_target,
                "target": replacement_target,
                "original_path": resolved.relative_to(root).as_posix(),
                "current_path": current.relative_to(root).as_posix(),
            }
        )
        return f"[{label}]({replacement_target})"

    rendered = _MARKDOWN_LINK.sub(replace, before)
    if rendered == before:
        return None
    reconstructed = rendered
    for rewrite in reversed(rewrites):
        reconstructed = reconstructed.replace(rewrite["target"], rewrite["source"])
    if reconstructed != before:
        raise CarrierTransitionError(
            f"Markdown link transition is not exactly reversible: {source}"
        )
    semantic_digest = semantic_sha256({"body": before})
    record = transition_record(
        root,
        source,
        source,
        rendered,
        semantic_digest,
        [],
        kind="markdown_links",
    )
    record["link_rewrites"] = rewrites
    return rendered, record


def transition_record(
    root: Path,
    source: Path,
    target: Path,
    rendered: str,
    semantic_digest: str,
    null_paths: list[str],
    *,
    kind: str,
) -> dict[str, Any]:
    original_path = source.relative_to(root).as_posix()
    original_digest = hashlib.sha256(source.read_bytes()).hexdigest()
    target_digest = hashlib.sha256(rendered.encode()).hexdigest()
    commit = git_head(root)
    if commit is None:
        raise CarrierTransitionError("carrier transition requires a Git HEAD")
    blob = git_blob(root, original_path)
    if blob is None:
        raise CarrierTransitionError(
            f"carrier transition requires a source Git blob: {original_path}"
        )
    return {
        "id": transition_id(original_path, original_digest),
        "kind": kind,
        "authority_decision": AUTHORITY_DECISION,
        "original_path": original_path,
        "original_format": (
            "markdown_yaml_frontmatter"
            if kind == "markdown_frontmatter"
            else "markdown"
            if kind == "markdown_links"
            else source.suffix.lstrip(".")
        ),
        "original_sha256": original_digest,
        "source_git_blob": blob,
        "current_path": target.relative_to(root).as_posix(),
        "current_format": (
            "markdown_toml_frontmatter"
            if kind == "markdown_frontmatter"
            else "markdown"
            if kind == "markdown_links"
            else "toml"
        ),
        "current_sha256": target_digest,
        "source_semantic_sha256": semantic_digest,
        "current_semantic_sha256": semantic_digest,
        "null_paths": null_paths,
        "declared_loss": [],
        "source_commit": commit,
        "transitioned_at": git_commit_time(root),
        "llm_session_ids": [SESSION_ID],
    }


def relocation_record(
    root: Path,
    source: Path,
    target: Path,
    *,
    carrier_ids: list[str] | None = None,
    semantic_ids: list[str] | None = None,
    authority: str = LAYOUT_AUTHORITY,
    session_id: str = SESSION_ID,
) -> dict[str, Any]:
    """Describe a byte-exact carrier move without changing its semantics."""

    if authority not in AUTHORITY_DECISIONS:
        raise CarrierTransitionError(f"unsupported relocation authority: {authority}")
    original_path = source.relative_to(root).as_posix()
    original_digest = hashlib.sha256(source.read_bytes()).hexdigest()
    blob = git_blob(root, original_path)
    if blob is None:
        raise CarrierTransitionError(
            f"carrier relocation requires a source Git blob: {original_path}"
        )
    semantic_digest = semantic_sha256({"carrier_sha256": original_digest})
    return {
        "id": transition_id(original_path, original_digest),
        "kind": "carrier_relocation",
        "authority_decision": authority,
        "original_path": original_path,
        "original_format": source.suffix.lstrip("."),
        "original_sha256": original_digest,
        "source_git_blob": blob,
        "current_path": target.relative_to(root).as_posix(),
        "current_format": target.suffix.lstrip("."),
        "current_sha256": original_digest,
        "source_semantic_sha256": semantic_digest,
        "current_semantic_sha256": semantic_digest,
        "null_paths": [],
        "declared_loss": [],
        "source_commit": git_head(root),
        "transitioned_at": git_commit_time(root),
        "llm_session_ids": [session_id],
        "carrier_ids": sorted(set(carrier_ids or [])),
        "semantic_ids": sorted(set(semantic_ids or [])),
    }


def git_head(root: Path) -> str | None:
    return _git_value(root, ["rev-parse", "HEAD"])


def git_blob(root: Path, relative: str) -> str | None:
    return _git_value(root, ["rev-parse", f"HEAD:{relative}"])


def git_commit_time(root: Path) -> str:
    value = _git_value(root, ["show", "-s", "--format=%cI", "HEAD"])
    if value is None:
        raise CarrierTransitionError("carrier transition requires a commit timestamp")
    return value


def load_ledger(root: Path) -> dict[str, Any]:
    path = ledger_path(root)
    if not path.is_file():
        return {"schema_version": SCHEMA_VERSION, "transitions": []}
    value = load_structured(path)
    if not isinstance(value, dict):
        raise CarrierTransitionError("carrier transition ledger must be a mapping")
    transitions = value.get("transitions")
    if str(value.get("schema_version")) != SCHEMA_VERSION or not isinstance(
        transitions, list
    ):
        raise CarrierTransitionError("invalid carrier transition ledger")
    return value


def render_ledger(root: Path, additions: list[dict[str, Any]]) -> str:
    ledger = deepcopy(load_ledger(root))
    existing = ledger["transitions"]
    assert isinstance(existing, list)
    by_id = {item.get("id"): item for item in existing if isinstance(item, dict)}
    for item in additions:
        current = by_id.get(item["id"])
        if current is not None and current != item:
            raise CarrierTransitionError(
                f"transition ledger entry changed: {item['id']}"
            )
        if current is None:
            existing.append(item)
            by_id[item["id"]] = item
    existing.sort(
        key=lambda item: str(item.get("id", "")) if isinstance(item, dict) else ""
    )
    return dump_toml(ledger)


def transition_aliases(root: Path) -> dict[Path, Path]:
    """Return original-to-current logical link aliases from the sealed ledger."""

    try:
        data = load_ledger(root)
    except (OSError, UnicodeError, ValueError):
        return {}
    transitions = data.get("transitions")
    if not isinstance(transitions, list):
        return {}
    aliases: dict[Path, Path] = {}
    for item in transitions:
        if not isinstance(item, dict):
            continue
        original = item.get("original_path")
        current = item.get("current_path")
        if (
            isinstance(original, str)
            and isinstance(current, str)
            and original != current
        ):
            aliases[(root / original).resolve()] = (root / current).resolve()
    return {
        original: _resolve_transition_target(root, target.as_posix(), aliases)
        for original, target in aliases.items()
    }


def _resolve_transition_target(
    root: Path, current: str, aliases: dict[Path, Path]
) -> Path:
    target = (root / current).resolve()
    seen: set[Path] = set()
    while target in aliases:
        if target in seen:
            raise CarrierTransitionError(f"carrier relocation cycle: {current}")
        seen.add(target)
        target = aliases[target]
    return target


def validate_carrier_transition_ledger(root: Path) -> list[str]:
    """Validate append-only transition identity, bytes, semantics, and Git return."""

    path = ledger_path(root)
    if not path.is_file():
        return []
    try:
        data = load_ledger(root)
    except (OSError, UnicodeError, ValueError) as error:
        return [str(error)]
    transitions = data.get("transitions")
    assert isinstance(transitions, list)
    errors: list[str] = []
    seen: set[str] = set()
    aliases = transition_aliases(root)
    required = {
        "id",
        "kind",
        "authority_decision",
        "carrier_ids",
        "semantic_ids",
        "original_path",
        "original_format",
        "original_sha256",
        "source_git_blob",
        "current_path",
        "current_format",
        "current_sha256",
        "source_semantic_sha256",
        "current_semantic_sha256",
        "null_paths",
        "declared_loss",
        "source_commit",
        "transitioned_at",
        "llm_session_ids",
    }
    for item in transitions:
        if not isinstance(item, dict) or not required.issubset(item):
            errors.append("transition record has missing required fields")
            continue
        identifier = item.get("id")
        original = item.get("original_path")
        original_digest = item.get("original_sha256")
        current = item.get("current_path")
        current_digest = item.get("current_sha256")
        null_paths = item.get("null_paths")
        if (
            not all(
                isinstance(value, str)
                for value in (
                    identifier,
                    original,
                    original_digest,
                    current,
                    current_digest,
                )
            )
            or not isinstance(null_paths, list)
            or not all(isinstance(value, str) for value in null_paths)
        ):
            errors.append("transition record has invalid identity fields")
            continue
        assert isinstance(identifier, str)
        assert isinstance(original, str)
        assert isinstance(original_digest, str)
        assert isinstance(current, str)
        assert isinstance(current_digest, str)
        if identifier in seen:
            errors.append(f"duplicate transition ID: {identifier}")
        seen.add(identifier)
        if identifier != transition_id(original, original_digest):
            errors.append(f"transition identity changed: {identifier}")
        if item.get("authority_decision") not in AUTHORITY_DECISIONS:
            errors.append(f"transition authority changed: {identifier}")
        if item.get("declared_loss") != []:
            errors.append(f"transition declares semantic loss: {identifier}")
        carrier_ids = item.get("carrier_ids")
        semantic_ids = item.get("semantic_ids")
        sessions = item.get("llm_session_ids")
        if not _canonical_ids(carrier_ids) or not _canonical_ids(semantic_ids):
            errors.append(f"transition identities are invalid: {identifier}")
        if (
            not isinstance(sessions, list)
            or not sessions
            or any(
                not isinstance(value, str)
                or re.fullmatch(r"[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+", value) is None
                for value in sessions
            )
        ):
            errors.append(f"transition session provenance is invalid: {identifier}")
        if item.get("source_semantic_sha256") != item.get("current_semantic_sha256"):
            errors.append(f"transition semantic digests differ: {identifier}")
        try:
            target = _resolve_transition_target(root, current, aliases)
        except CarrierTransitionError as error:
            errors.append(str(error))
            continue
        if not _within(root, target) or not target.is_file():
            errors.append(f"transition current carrier is missing: {current}")
            continue
        if hashlib.sha256(target.read_bytes()).hexdigest() != current_digest:
            errors.append(f"transition current carrier digest changed: {current}")
            continue
        try:
            if item.get("kind") == "carrier_relocation":
                semantics = {"carrier_sha256": current_digest}
            elif item.get("kind") == "structured_yaml":
                semantics = decode_historical_envelope(
                    target.read_text(encoding="utf-8")
                )
            elif item.get("kind") == "markdown_frontmatter":
                parsed = parse_frontmatter(target.read_text(encoding="utf-8"))
                if parsed is None or parsed[2] != "toml":
                    raise CarrierTransitionError("current Markdown is not TOML")
                semantics = {
                    "metadata": decode_nulls(parsed[0], null_paths),
                    "body": parsed[1],
                }
            elif item.get("kind") == "markdown_links":
                rendered = target.read_text(encoding="utf-8")
                rewrites = item.get("link_rewrites")
                if not isinstance(rewrites, list):
                    raise CarrierTransitionError("link_rewrites must be a list")
                reconstructed = rendered
                for rewrite in reversed(rewrites):
                    if not isinstance(rewrite, dict) or not all(
                        isinstance(rewrite.get(field), str)
                        for field in (
                            "source",
                            "target",
                            "original_path",
                            "current_path",
                        )
                    ):
                        raise CarrierTransitionError("invalid link rewrite")
                    reconstructed = reconstructed.replace(
                        str(rewrite["target"]), str(rewrite["source"])
                    )
                semantics = {"body": reconstructed}
            else:
                raise CarrierTransitionError("unknown transition kind")
        except (OSError, UnicodeError, ValueError) as error:
            errors.append(f"cannot reconstruct {identifier}: {error}")
            continue
        if semantic_sha256(semantics) != item.get("current_semantic_sha256"):
            errors.append(f"transition semantic reconstruction changed: {identifier}")
        blob = item.get("source_git_blob")
        source_bytes = _git_blob_bytes(root, blob) if isinstance(blob, str) else None
        if source_bytes is None:
            errors.append(f"transition source Git blob is missing: {identifier}")
        elif hashlib.sha256(source_bytes).hexdigest() != original_digest:
            errors.append(f"transition source Git blob digest changed: {identifier}")
    return errors


def _git_value(root: Path, arguments: list[str]) -> str | None:
    completed = subprocess.run(
        ["git", *arguments],
        cwd=root,
        check=False,
        capture_output=True,
        text=True,
    )
    value = completed.stdout.strip()
    return value if completed.returncode == 0 and value else None


def _git_blob_bytes(root: Path, identifier: str) -> bytes | None:
    completed = subprocess.run(
        ["git", "cat-file", "blob", identifier],
        cwd=root,
        check=False,
        capture_output=True,
    )
    return completed.stdout if completed.returncode == 0 else None


def _within(root: Path, path: Path) -> bool:
    try:
        path.relative_to(root.resolve())
    except ValueError:
        return False
    return True


def _canonical_ids(value: object) -> bool:
    return (
        isinstance(value, list)
        and len(value) == len(set(value))
        and all(
            isinstance(item, str)
            and re.fullmatch(r"[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+", item) is not None
            for item in value
        )
    )


def _validate_null_paths(
    source: Path, null_paths: list[str], *, markdown: bool
) -> None:
    for rendered in null_paths:
        parts = _parse_null_path(rendered)
        allowed = markdown and parts[-2:] == ("promotion", "parent_scope")
        allowed = allowed or (
            source.name in {"intake.yaml", "intake.yml"}
            and len(parts) == 3
            and parts[0] == "items"
            and parts[2] == "decision"
        )
        allowed = allowed or (
            source.name in {"pull-requests.yaml", "pull-requests.yml"}
            and len(parts) == 3
            and parts[0] == "pull_requests"
            and parts[2] == "merge_commit"
        )
        if not allowed:
            raise CarrierTransitionError(
                f"undeclared null normalization in {source}: {rendered}"
            )


def _contains_null_sentinel(value: Any) -> bool:
    if value == _NULL_SENTINEL:
        return True
    if isinstance(value, dict):
        return any(_contains_null_sentinel(item) for item in value.values())
    if isinstance(value, list):
        return any(_contains_null_sentinel(item) for item in value)
    return False


def _render_null_path(path: tuple[str, ...]) -> str:
    return "/" + "/".join(item.replace("~", "~0").replace("/", "~1") for item in path)


def _parse_null_path(path: str) -> tuple[str, ...]:
    if not path.startswith("/"):
        raise CarrierTransitionError(f"invalid null reconstruction path: {path}")
    if path == "/":
        return ()
    return tuple(
        item.replace("~1", "/").replace("~0", "~") for item in path[1:].split("/")
    )

from __future__ import annotations

import hashlib
import re
import subprocess
from collections.abc import Mapping
from dataclasses import dataclass
from pathlib import Path
from typing import Any

from .diagnostics import Diagnostic
from .layout import discover_layout
from .semantic_types import build_semantic_classification_index
from .yaml_subset import load

ID_PATTERN = re.compile(r"[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+")
SESSION_PATTERN = re.compile(r"^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$")
COMMIT_PATTERN = re.compile(r"^[0-9a-f]{40}$")
DIGEST_PATTERN = re.compile(r"^[0-9a-f]{64}$")
CORRECTION_FIELDS = {
    "commit",
    "original_message_sha256",
    "mode",
    "decision_ids",
    "verifies",
    "resolves",
    "session",
    "rationale",
}


@dataclass(frozen=True)
class CommitRecord:
    commit: str
    message: str
    message_sha256: str


def validate_commit_provenance(root: Path) -> list[Diagnostic]:
    root = root.resolve()
    if not (root / ".git").exists():
        return []
    manifest_path = discover_layout(root).manifest_path
    manifest = load(manifest_path)
    raw_policy = (
        manifest.get("commit_provenance") if isinstance(manifest, dict) else None
    )
    if not isinstance(raw_policy, Mapping):
        return [
            Diagnostic(
                "DSET-E168",
                manifest_path,
                "project manifest requires commit_provenance policy",
            )
        ]
    start = raw_policy.get("start_commit")
    if not isinstance(start, str) or not start:
        return [
            Diagnostic(
                "DSET-E168",
                manifest_path,
                "commit_provenance.start_commit is required",
            )
        ]
    if not _has_head(root):
        return []
    try:
        base = _resolve_base(root, manifest_path, start)
        commits = _commits_after(root, base)
        known = {
            str(row["id"]): (str(row["type"]), str(row["subtype"]))
            for row in build_semantic_classification_index(root)
        }
    except (OSError, ValueError, subprocess.CalledProcessError) as error:
        return [Diagnostic("DSET-E168", manifest_path, str(error))]
    return [
        Diagnostic("DSET-E168", manifest_path, problem)
        for problem in validate_commit_history(
            commits, known, raw_policy.get("corrections", [])
        )
    ]


def validate_commit_history(
    commits: list[CommitRecord],
    known: Mapping[str, tuple[str, str]],
    raw_corrections: object,
) -> list[str]:
    corrections, problems = _parse_corrections(raw_corrections, commits)
    for record in commits:
        original_problems = validate_commit_message(record.message, known)
        correction = corrections.get(record.commit)
        if correction is None:
            problems.extend(
                f"commit {record.commit[:12]}: {problem}"
                for problem in original_problems
            )
            continue
        if not original_problems:
            problems.append(
                f"correction for commit {record.commit} is unnecessary because "
                "the original provenance is valid"
            )
            continue
        corrected_message = _corrected_message(correction)
        problems.extend(
            f"correction for commit {record.commit}: {problem}"
            for problem in validate_commit_message(corrected_message, known)
        )
    return problems


def validate_commit_message(
    message: str, known: Mapping[str, tuple[str, str]]
) -> list[str]:
    trailers = _trailers(message)
    sessions = trailers.get("Session", [])
    if len(sessions) != 1 or not SESSION_PATTERN.fullmatch(sessions[0]):
        session_problem = "requires exactly one valid Session trailer"
    else:
        session_problem = ""
    implements = _ids(trailers.get("Implements", []))
    decisions = _ids(trailers.get("Decision", []))
    verifies = _ids(trailers.get("Verifies", []))
    problems: list[str] = [session_problem] if session_problem else []
    if implements and (decisions or verifies):
        problems.append("cannot mix implementation and evidence provenance modes")
    elif implements:
        problems.extend(_decision_reference_problems("Implements", implements, known))
    elif decisions and verifies:
        problems.extend(_decision_reference_problems("Decision", decisions, known))
        problems.extend(_known_reference_problems("Verifies", verifies, known))
    else:
        problems.append(
            "requires Implements, or the evidence pair Decision and Verifies"
        )
    resolves = _ids(trailers.get("Resolves", []))
    for identifier in resolves:
        classification = known.get(identifier)
        if classification is None:
            problems.append(f"Resolves references unknown ID: {identifier}")
        elif classification[0] != "problem":
            problems.append(f"Resolves must reference a Problem: {identifier}")
    return problems


def _parse_corrections(
    raw_corrections: object, commits: list[CommitRecord]
) -> tuple[dict[str, Mapping[str, Any]], list[str]]:
    if not isinstance(raw_corrections, list):
        return {}, ["commit_provenance.corrections must be a list"]
    records = {record.commit: record for record in commits}
    corrections: dict[str, Mapping[str, Any]] = {}
    problems: list[str] = []
    for index, raw in enumerate(raw_corrections, start=1):
        prefix = f"commit_provenance.corrections[{index}]"
        if not isinstance(raw, Mapping):
            problems.append(f"{prefix} must be a mapping")
            continue
        fields = set(raw)
        if fields != CORRECTION_FIELDS:
            missing = sorted(CORRECTION_FIELDS - fields)
            extra = sorted(fields - CORRECTION_FIELDS)
            details: list[str] = []
            if missing:
                details.append(f"missing {', '.join(missing)}")
            if extra:
                details.append(f"unknown {', '.join(extra)}")
            problems.append(f"{prefix} fields are invalid: {'; '.join(details)}")
            continue
        commit = raw.get("commit")
        if not isinstance(commit, str) or not COMMIT_PATTERN.fullmatch(commit):
            problems.append(f"{prefix}.commit requires one full lowercase SHA")
            continue
        if commit in corrections:
            problems.append(f"duplicate provenance correction for commit {commit}")
            continue
        record = records.get(commit)
        if record is None:
            problems.append(
                f"provenance correction commit is outside the validated range: {commit}"
            )
            continue
        digest = raw.get("original_message_sha256")
        if not isinstance(digest, str) or not DIGEST_PATTERN.fullmatch(digest):
            problems.append(f"{prefix}.original_message_sha256 is invalid")
            continue
        if digest != record.message_sha256:
            problems.append(
                f"provenance correction message digest mismatch for commit {commit}"
            )
            continue
        mode = raw.get("mode")
        if mode not in {"implementation", "evidence"}:
            problems.append(f"{prefix}.mode must be implementation or evidence")
            continue
        if not _valid_id_list(raw.get("decision_ids"), allow_empty=False):
            problems.append(f"{prefix}.decision_ids requires unique canonical IDs")
            continue
        verifies = raw.get("verifies")
        if not _valid_id_list(verifies, allow_empty=mode == "implementation"):
            problems.append(
                f"{prefix}.verifies must be empty for implementation or contain "
                "unique canonical IDs for evidence"
            )
            continue
        if mode == "implementation" and verifies:
            problems.append(f"{prefix}.verifies must be empty for implementation")
            continue
        if not _valid_id_list(raw.get("resolves"), allow_empty=True):
            problems.append(f"{prefix}.resolves must contain unique canonical IDs")
            continue
        session = raw.get("session")
        if not isinstance(session, str) or not SESSION_PATTERN.fullmatch(session):
            problems.append(f"{prefix}.session requires exactly one valid session ID")
            continue
        rationale = raw.get("rationale")
        if not isinstance(rationale, str) or not rationale.strip():
            problems.append(f"{prefix}.rationale requires non-empty text")
            continue
        corrections[commit] = raw
    return corrections, problems


def _valid_id_list(value: object, *, allow_empty: bool) -> bool:
    if not isinstance(value, list) or (not allow_empty and not value):
        return False
    if not all(isinstance(item, str) and ID_PATTERN.fullmatch(item) for item in value):
        return False
    return len(value) == len(set(value))


def _corrected_message(correction: Mapping[str, Any]) -> str:
    label = "Implements" if correction["mode"] == "implementation" else "Decision"
    lines = [f"{label}: {', '.join(correction['decision_ids'])}"]
    if correction["verifies"]:
        lines.append(f"Verifies: {', '.join(correction['verifies'])}")
    if correction["resolves"]:
        lines.append(f"Resolves: {', '.join(correction['resolves'])}")
    lines.append(f"Session: {correction['session']}")
    return "\n".join(lines)


def _resolve_base(root: Path, manifest_path: Path, start: str) -> str | None:
    if start == "root":
        return None
    if start == "manifest-addition":
        relative = manifest_path.relative_to(root).as_posix()
        completed = subprocess.run(
            [
                "git",
                "log",
                "--reverse",
                "--format=%H",
                "--diff-filter=A",
                "--",
                relative,
            ],
            cwd=root,
            check=True,
            capture_output=True,
            text=True,
        )
        commits = completed.stdout.split()
        return commits[0] if commits else None
    completed = subprocess.run(
        ["git", "rev-parse", "--verify", f"{start}^{{commit}}"],
        cwd=root,
        check=True,
        capture_output=True,
        text=True,
    )
    return completed.stdout.strip()


def _commits_after(root: Path, base: str | None) -> list[CommitRecord]:
    revision = f"{base}..HEAD" if base else "HEAD"
    completed = subprocess.run(
        ["git", "rev-list", "--no-merges", "--reverse", revision],
        cwd=root,
        check=True,
        capture_output=True,
        text=True,
    )
    return [_read_commit(root, commit) for commit in completed.stdout.split()]


def _read_commit(root: Path, commit: str) -> CommitRecord:
    completed = subprocess.run(
        ["git", "cat-file", "commit", commit],
        cwd=root,
        check=True,
        capture_output=True,
    )
    _headers, separator, message = completed.stdout.partition(b"\n\n")
    if not separator:
        raise ValueError(f"commit object has no message boundary: {commit}")
    return CommitRecord(
        commit=commit,
        message=message.decode("utf-8", errors="surrogateescape"),
        message_sha256=hashlib.sha256(message).hexdigest(),
    )


def _has_head(root: Path) -> bool:
    completed = subprocess.run(
        ["git", "rev-parse", "--verify", "HEAD"],
        cwd=root,
        check=False,
        capture_output=True,
        text=True,
    )
    return completed.returncode == 0


def _trailers(message: str) -> dict[str, list[str]]:
    found: dict[str, list[str]] = {}
    for line in message.splitlines():
        key, separator, value = line.partition(":")
        if separator and key in {
            "Implements",
            "Decision",
            "Verifies",
            "Resolves",
            "Session",
        }:
            found.setdefault(key, []).append(value.strip())
    return found


def _ids(values: list[str]) -> set[str]:
    return {identifier for value in values for identifier in ID_PATTERN.findall(value)}


def _decision_reference_problems(
    label: str,
    identifiers: set[str],
    known: Mapping[str, tuple[str, str]],
) -> list[str]:
    problems = _known_reference_problems(label, identifiers, known)
    for identifier in identifiers:
        if identifier in known and known[identifier][0] != "decision":
            problems.append(f"{label} must reference a Decision: {identifier}")
    return problems


def _known_reference_problems(
    label: str,
    identifiers: set[str],
    known: Mapping[str, tuple[str, str]],
) -> list[str]:
    if not identifiers:
        return [f"{label} requires at least one canonical ID"]
    return [
        f"{label} references unknown ID: {identifier}"
        for identifier in sorted(identifiers)
        if identifier not in known
    ]

from __future__ import annotations

import hashlib
import re
from pathlib import Path
from typing import Any

from .identity import iter_control_files, logical_part
from .layout import LAYERS, discover_layout
from .project_data import lifecycle_events
from .semantic_atoms import collect_semantic_atoms
from .yaml_subset import YamlSubsetError, dump, load

DECISION_FIELDS = ("requirements", "contracts", "stories", "outcomes")
INACTIVE_EVENTS = frozenset({"absorbed", "rejected", "retired", "withdrawn"})
IGNORED_PARTS = frozenset(
    {
        ".git",
        ".cache",
        ".venv",
        "__pycache__",
        "dist",
        "generated",
        "templates",
    }
)


def build_compilation_index(root: Path) -> dict[str, Any]:
    root = root.resolve()
    sources = _authority_sources(root)
    projections = _projection_paths(root)
    records: list[dict[str, Any]] = []
    missing: list[str] = []
    for identifier, source in sorted(sources.items()):
        owners = [
            (path, _projection_fragments(path, identifier)) for path in projections
        ]
        owners = [(path, fragments) for path, fragments in owners if fragments]
        if not owners:
            missing.append(identifier)
            continue
        records.append(
            {
                "id": identifier,
                "source": {
                    "carrier": source.name,
                    "sha256": _digest(source),
                },
                "projections": [
                    {
                        "carrier": path.name,
                        "sha256": _digest(path),
                        "fragments": fragments,
                    }
                    for path, fragments in owners
                ],
            }
        )
    if missing:
        raise ValueError(
            "active Decision authority lacks an evergreen projection: "
            + ", ".join(missing)
        )
    return {
        "schema_version": "1.0",
        "records": records,
    }


def compilation_path(root: Path) -> Path:
    layout = discover_layout(root.resolve())
    generated = (
        layout.traceability_path.parent
        if layout.layered
        else layout.dset_root / "generated"
    )
    suffix = ".toml" if layout.manifest_path.suffix == ".toml" else ".yaml"
    return layout.structured_file(generated, f"compilation{suffix}")


def rendered_compilation(root: Path) -> str:
    return dump(build_compilation_index(root), compilation_path(root))


def compilation_is_fresh(root: Path) -> bool:
    path = compilation_path(root)
    try:
        rendered = rendered_compilation(root)
    except ValueError:
        return False
    return path.is_file() and path.read_text(encoding="utf-8") == rendered


def write_compilation(root: Path) -> Path:
    path = compilation_path(root)
    content = rendered_compilation(root)
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_suffix(path.suffix + ".tmp")
    temporary.write_text(content, encoding="utf-8")
    temporary.replace(path)
    return path


def active_authority_ids(root: Path) -> set[str]:
    return set(_authority_sources(root.resolve()))


def projected_authority_ids(root: Path) -> set[str]:
    """Return authorities with an explicit evergreen claim fragment."""
    root = root.resolve()
    sources = _authority_sources(root)
    projections = _projection_paths(root)
    return {
        identifier
        for identifier in sources
        if any(_projection_fragments(path, identifier) for path in projections)
    }


def _authority_sources(root: Path) -> dict[str, Path]:
    lifecycle = _lifecycle_status(root)
    sources: dict[str, Path] = {}
    atoms, diagnostics = collect_semantic_atoms(root)
    if diagnostics:
        raise ValueError(diagnostics[0].message)
    for atom in atoms.values():
        if (
            atom.semantic_type == "decision"
            and atom.emission_status == "accepted"
            and lifecycle.get(atom.semantic_id) not in INACTIVE_EVENTS
        ):
            sources[atom.semantic_id] = root / atom.path
    layout = discover_layout(root)
    paths = iter_control_files(root, "*.md") if layout.separated else root.rglob("*.md")
    for path in paths:
        if _ignored(root, path) or (
            path.parent.name != "decision"
            and not path.name.lower().startswith("decision-")
        ):
            continue
        text = _read(path)
        match = re.search(r"\*\*Decision ID:\*\*\s*`([^`]+)`", text)
        if not match or "**Status:** accepted" not in text:
            continue
        identifier = match.group(1)
        if lifecycle.get(identifier) not in INACTIVE_EVENTS:
            sources[identifier] = path
    for path in discover_layout(root).structured_named_files(root, "package"):
        if _ignored(root, path) or "specs" not in path.parts:
            continue
        try:
            data = load(path)
        except (OSError, UnicodeError, YamlSubsetError):
            continue
        if not isinstance(data, dict):
            continue
        for field in DECISION_FIELDS:
            values = data.get(field, [])
            if not isinstance(values, list):
                continue
            for identifier in values:
                if (
                    isinstance(identifier, str)
                    and lifecycle.get(identifier) not in INACTIVE_EVENTS
                ):
                    sources.setdefault(identifier, path)
    return sources


def _projection_paths(root: Path) -> list[Path]:
    layout = discover_layout(root)
    if layout.recursive or layout.separated:
        prefixes = ("specification-", "procedure-", "plan-", "navigation-")
        owners = (
            layout.project_root,
            *(layout.layer_root(layer) for layer in LAYERS),
            layout.dset_root,
        )
        return [
            path
            for owner in owners
            for path in sorted(owner.rglob("*.md"))
            if not _ignored(root, path) and path.name.lower().startswith(prefixes)
        ]
    if layout.slim:
        prefixes = (
            "specification-",
            "procedure-",
            "plan-",
            "dset-specification-",
        )
        return [
            path
            for path in sorted(layout.dset_root.rglob("*.md"))
            if not _ignored(root, path) and path.name.lower().startswith(prefixes)
        ]
    return [
        path
        for path in sorted(root.rglob("*.md"))
        if not _ignored(root, path)
        and ("specs" in path.parts or "governance" in path.parts)
    ]


def _lifecycle_status(root: Path) -> dict[str, str]:
    return {
        str(item.get("atom_id")): str(item.get("event"))
        for item in lifecycle_events(root)
    }


def _ignored(root: Path, path: Path) -> bool:
    relative = path.relative_to(root)
    if relative.parts[:1] == (".dset_runtime",) or relative.parts[:2] == (
        ".dset",
        "runtime",
    ):
        return True
    return any(
        logical_part(part) in IGNORED_PARTS
        or (part.startswith(".") and part not in {".github", ".dset"})
        for part in relative.parts
    )


def _read(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8")
    except (OSError, UnicodeError):
        return ""


def _projection_fragments(path: Path, identifier: str) -> list[dict[str, Any]]:
    """Extract only explicit evergreen claim structures, never loose mentions."""
    lines = _read(path).splitlines()
    fragments: list[dict[str, Any]] = []
    escaped = re.escape(identifier)
    heading = re.compile(rf"^(#{{1,6}})\s+`?{escaped}`?(?:\s|$)")
    table = re.compile(rf"^\|\s*`?{escaped}`?\s*\|")
    labeled = re.compile(rf"^\*\*[^*\n]*\b{escaped}\b[^*\n]*:\*\*")
    for index, line in enumerate(lines):
        match = heading.match(line)
        kind: str | None = None
        end = index + 1
        if match:
            kind = "section"
            level = len(match.group(1))
            while end < len(lines):
                next_heading = re.match(r"^(#{1,6})\s+", lines[end])
                if next_heading and len(next_heading.group(1)) <= level:
                    break
                end += 1
        elif table.match(line):
            kind = "table-row"
        elif labeled.match(line):
            kind = "labeled-block"
            while end < len(lines) and lines[end].strip():
                end += 1
        if kind is None:
            continue
        content = "\n".join(lines[index:end]).strip()
        fragments.append(
            {
                "kind": kind,
                "line": index + 1,
                "sha256": hashlib.sha256(content.encode()).hexdigest(),
            }
        )
    return fragments


def _digest(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()

from __future__ import annotations

import re
from datetime import date
from pathlib import Path
from typing import Any

from .diagnostics import Diagnostic
from .layout import discover_layout
from .yaml_subset import YamlSubsetError, load

PACKAGE_BLOCK = re.compile(r"(?ms)^\[\[package\]\]\n(.*?)(?=^\[\[package\]\]|\Z)")
NAME = re.compile(r'^name = "([^"]+)"$', re.MULTILINE)
VERSION = re.compile(r'^version = "([^"]+)"$', re.MULTILINE)
REGISTRY = re.compile(r'^source = \{ registry = "([^"]+)" \}$', re.MULTILINE)
SPDX = re.compile(r"^[A-Za-z0-9][A-Za-z0-9.+-]*$")


def dependency_policy_path(root: Path) -> Path:
    layout = discover_layout(root.resolve())
    owner = layout.layer_root("implementation") if layout.layered else layout.dset_root
    local = layout._numbered_file(owner, "dependency-policy.toml")
    if local.is_file():
        return local
    if _repository_role(layout.manifest_path) == "framework-source-and-adopter":
        return layout._numbered_file(
            layout.framework_layer_root("implementation"),
            "dependency-policy.toml",
        )
    return local


def validate_dependency_policy(
    root: Path,
    *,
    policy_path: Path | None = None,
    today: date | None = None,
) -> list[Diagnostic]:
    root = root.resolve()
    path = policy_path or dependency_policy_path(root)
    if not path.is_file():
        return []
    current_date = today or date.today()
    try:
        data = load(path)
    except (OSError, UnicodeError, YamlSubsetError) as error:
        return [_diag(path, f"dependency policy cannot be parsed: {error}")]
    if not isinstance(data, dict):
        return [_diag(path, "dependency policy must be a mapping")]
    required = {
        "schema_version",
        "policy_id",
        "version",
        "authority",
        "exception_authority",
        "ecosystems",
        "allow",
        "deny",
        "exceptions",
    }
    diagnostics: list[Diagnostic] = []
    if set(data) != required or data.get("schema_version") != "1.0":
        return [_diag(path, "dependency policy envelope is invalid")]
    for field in ("policy_id", "version", "authority", "exception_authority"):
        if not isinstance(data.get(field), str) or not str(data[field]).strip():
            diagnostics.append(_diag(path, f"dependency policy {field} is required"))
    ecosystems = _ecosystems(root, path, data.get("ecosystems"), diagnostics)
    allowed = _records(path, data.get("allow"), "allow", diagnostics)
    denied = _records(path, data.get("deny"), "deny", diagnostics, sparse=True)
    exceptions = _exceptions(
        path,
        data.get("exceptions"),
        str(data.get("exception_authority", "")),
        current_date,
        diagnostics,
    )
    _unique_records(path, allowed, "allow", diagnostics)
    _unique_records(path, denied, "deny", diagnostics)
    _unique_records(path, exceptions, "exception", diagnostics)
    for ecosystem, config in ecosystems.items():
        if ecosystem != "python-uv":
            diagnostics.append(_diag(path, f"unsupported ecosystem: {ecosystem}"))
            continue
        locked = _uv_packages(root / config["lockfile"], diagnostics)
        local_name = _project_name(root / config["manifest"])
        locked = {key: value for key, value in locked.items() if key != local_name}
        policy_for_ecosystem = {
            (item["name"], item["version"]): item
            for item in allowed
            if item["ecosystem"] == ecosystem
        }
        active_exceptions = {
            (item["name"], item["version"]): item
            for item in exceptions
            if item["ecosystem"] == ecosystem and item["active"]
        }
        denied_names = {
            (item["name"], item.get("version"))
            for item in denied
            if item["ecosystem"] == ecosystem
        }
        for name, locked_item in locked.items():
            key = (name, locked_item["version"])
            exception = active_exceptions.get(key)
            if (
                (name, None) in denied_names or key in denied_names
            ) and exception is None:
                diagnostics.append(_diag(path, f"denied dependency is locked: {name}"))
                continue
            record = policy_for_ecosystem.get(key) or exception
            if record is None:
                diagnostics.append(
                    _diag(
                        path,
                        f"locked dependency is not allowed exactly: {name}=={key[1]}",
                    )
                )
                continue
            if record["registry"] != config["registry"]:
                diagnostics.append(
                    _diag(
                        path,
                        f"dependency violates ecosystem registry: {name}=={key[1]}",
                    )
                )
            if record["registry"] != locked_item["registry"]:
                diagnostics.append(
                    _diag(path, f"dependency registry drift: {name}=={key[1]}")
                )
        locked_keys = {(name, item["version"]) for name, item in locked.items()}
        for key in policy_for_ecosystem:
            if key not in locked_keys:
                diagnostics.append(
                    _diag(
                        path,
                        "allowed dependency is absent from lockfile: "
                        f"{key[0]}=={key[1]}",
                    )
                )
    return sorted(set(diagnostics))


def dependency_summary(root: Path) -> dict[str, Any]:
    path = dependency_policy_path(root)
    diagnostics = validate_dependency_policy(root, policy_path=path)
    data = load(path) if path.is_file() else {}
    return {
        "policy": path.relative_to(root.resolve()).as_posix(),
        "status": "pass" if not diagnostics else "fail",
        "allowed": len(data.get("allow", [])) if isinstance(data, dict) else 0,
        "denied": len(data.get("deny", [])) if isinstance(data, dict) else 0,
        "exceptions": len(data.get("exceptions", [])) if isinstance(data, dict) else 0,
        "diagnostics": [item.message for item in diagnostics],
    }


def _ecosystems(
    root: Path,
    path: Path,
    value: object,
    diagnostics: list[Diagnostic],
) -> dict[str, dict[str, str]]:
    if not isinstance(value, list) or not value:
        diagnostics.append(_diag(path, "ecosystems must be a non-empty list"))
        return {}
    result: dict[str, dict[str, str]] = {}
    for item in value:
        fields = {"id", "manifest", "lockfile", "registry"}
        if not isinstance(item, dict) or set(item) != fields:
            diagnostics.append(_diag(path, "ecosystem entry is invalid"))
            continue
        if not all(isinstance(item[field], str) and item[field] for field in fields):
            diagnostics.append(_diag(path, "ecosystem values must be non-empty"))
            continue
        identifier = str(item["id"])
        if identifier in result:
            diagnostics.append(_diag(path, f"duplicate ecosystem: {identifier}"))
            continue
        for field in ("manifest", "lockfile"):
            target = root / str(item[field])
            if not target.is_file():
                diagnostics.append(
                    _diag(path, f"dependency {field} is missing: {item[field]}")
                )
        result[identifier] = {field: str(item[field]) for field in fields}
    return result


def _records(
    path: Path,
    value: object,
    label: str,
    diagnostics: list[Diagnostic],
    *,
    sparse: bool = False,
) -> list[dict[str, str]]:
    if not isinstance(value, list):
        diagnostics.append(_diag(path, f"{label} must be a list"))
        return []
    records: list[dict[str, str]] = []
    full = {
        "ecosystem",
        "name",
        "version",
        "registry",
        "license",
        "provenance",
        "rationale",
    }
    sparse_fields = {"ecosystem", "name", "version", "rationale"}
    for item in value:
        if not isinstance(item, dict) or (
            set(item) != full
            and not (
                sparse
                and set(item) in ({"ecosystem", "name", "rationale"}, sparse_fields)
            )
        ):
            diagnostics.append(_diag(path, f"{label} dependency entry is invalid"))
            continue
        if not all(isinstance(raw, str) and raw.strip() for raw in item.values()):
            diagnostics.append(
                _diag(path, f"{label} dependency values must be non-empty")
            )
            continue
        if not sparse:
            if not SPDX.fullmatch(str(item["license"])):
                diagnostics.append(
                    _diag(path, f"{label} dependency license must be SPDX")
                )
            if not str(item["provenance"]).startswith("https://"):
                diagnostics.append(
                    _diag(path, f"{label} dependency provenance must use HTTPS")
                )
        records.append({str(key): str(raw) for key, raw in item.items()})
    return records


def _exceptions(
    path: Path,
    value: object,
    authority: str,
    current_date: date,
    diagnostics: list[Diagnostic],
) -> list[dict[str, Any]]:
    if not isinstance(value, list):
        diagnostics.append(_diag(path, "exceptions must be a list"))
        return []
    records: list[dict[str, Any]] = []
    required = {
        "id",
        "ecosystem",
        "name",
        "version",
        "registry",
        "license",
        "provenance",
        "authority",
        "expires_on",
        "rationale",
    }
    for item in value:
        if not isinstance(item, dict) or set(item) != required:
            diagnostics.append(_diag(path, "dependency exception entry is invalid"))
            continue
        if not all(isinstance(raw, str) and raw.strip() for raw in item.values()):
            diagnostics.append(
                _diag(path, "dependency exception values must be non-empty")
            )
            continue
        try:
            expiry = date.fromisoformat(str(item["expires_on"]))
        except ValueError:
            diagnostics.append(_diag(path, f"invalid exception expiry: {item['id']}"))
            continue
        active = expiry >= current_date
        if not active:
            diagnostics.append(
                _diag(path, f"dependency exception expired: {item['id']}")
            )
        if item["authority"] != authority:
            diagnostics.append(
                _diag(path, f"dependency exception authority mismatch: {item['id']}")
            )
        if not SPDX.fullmatch(str(item["license"])):
            diagnostics.append(
                _diag(path, f"dependency exception license must be SPDX: {item['id']}")
            )
        if not str(item["provenance"]).startswith("https://"):
            diagnostics.append(
                _diag(
                    path,
                    f"dependency exception provenance must use HTTPS: {item['id']}",
                )
            )
        record = {str(key): raw for key, raw in item.items()}
        record["active"] = active
        records.append(record)
    return records


def _unique_records(
    path: Path,
    records: list[dict[str, Any]],
    label: str,
    diagnostics: list[Diagnostic],
) -> None:
    keys = [
        (item.get("ecosystem"), item.get("name"), item.get("version"))
        for item in records
    ]
    if len(keys) != len(set(keys)):
        diagnostics.append(_diag(path, f"duplicate {label} dependency entry"))


def _uv_packages(
    path: Path, diagnostics: list[Diagnostic]
) -> dict[str, dict[str, str]]:
    if not path.is_file():
        return {}
    text = path.read_text(encoding="utf-8")
    packages: dict[str, dict[str, str]] = {}
    for match in PACKAGE_BLOCK.finditer(text):
        block = match.group(1)
        name_match = NAME.search(block)
        version_match = VERSION.search(block)
        registry_match = REGISTRY.search(block)
        if name_match is None or version_match is None:
            diagnostics.append(_diag(path, "uv.lock package lacks name or version"))
            continue
        name = name_match.group(1)
        packages[name] = {
            "version": version_match.group(1),
            "registry": registry_match.group(1) if registry_match else "local",
        }
    return packages


def _project_name(path: Path) -> str:
    if not path.is_file():
        return ""
    text = path.read_text(encoding="utf-8")
    project = re.search(r'(?ms)^\[project\]\n.*?^name = "([^"]+)"$', text)
    return project.group(1) if project else ""


def _repository_role(manifest_path: Path) -> str | None:
    try:
        manifest = load(manifest_path)
    except (OSError, UnicodeError, YamlSubsetError):
        return None
    if not isinstance(manifest, dict):
        return None
    project = manifest.get("project")
    if not isinstance(project, dict):
        return None
    role = project.get("repository_role")
    return role if isinstance(role, str) else None


def _diag(path: Path, message: str) -> Diagnostic:
    return Diagnostic("DSET-E163", path, message)

from __future__ import annotations

import fnmatch
import json
import re
import subprocess
from datetime import date
from pathlib import Path, PurePosixPath
from typing import Any

from .diagnostics import Diagnostic
from .layout import discover_layout
from .yaml_subset import YamlSubsetError, load

PROFILE_SCHEMA_VERSION = "1.0"
GATE_IDS = (
    "conformance",
    "purity",
    "spec_sync",
    "typing_contracts",
    "lint_static_analysis",
    "secret_hygiene",
)
PROFILE_STATUSES = frozenset({"candidate", "active", "custom"})
PROFILE_ROLES = frozenset({"reference", "applied"})
REVISION_POLICIES = frozenset({"exact", "descendant"})
GATE_STATUSES = frozenset({"enforced", "ratcheted", "blocked", "not-applicable"})
_ID = re.compile(r"^[a-z][a-z0-9-]*$")
_SHA = re.compile(r"^[0-9a-f]{40}$")


def resolve_profile_path(root: Path, profile_id: str) -> Path:
    """Resolve an applied profile, with references limited to framework source."""

    layout = discover_layout(root.resolve())
    local = layout.structured_file(
        layout.layer_root("implementation") / "profiles", f"{profile_id}.toml"
    )
    if local.is_file():
        return local
    if _repository_role(layout.manifest_path) == "framework-source-and-adopter":
        try:
            return layout.find_template(
                Path("enforcement-profiles") / f"{profile_id}.toml"
            )
        except FileNotFoundError:
            pass
    raise FileNotFoundError(
        f"applied enforcement profile is missing: {profile_id}; "
        "framework references are not project-owned instances"
    )


def validate_profile_file(path: Path) -> tuple[dict[str, Any], list[Diagnostic]]:
    try:
        data = load(path)
    except (OSError, UnicodeError, YamlSubsetError) as error:
        return {}, [_diag(path, f"profile cannot be loaded: {error}")]
    if not isinstance(data, dict):
        return {}, [_diag(path, "profile must be a mapping")]
    return data, validate_profile_data(path, data)


def validate_profile_data(path: Path, data: dict[str, Any]) -> list[Diagnostic]:
    diagnostics: list[Diagnostic] = []
    profile_id = data.get("id")
    status = data.get("status")
    profile_role = data.get("profile_role")
    if data.get("schema_version") != PROFILE_SCHEMA_VERSION:
        diagnostics.append(_diag(path, "schema_version must be 1.0"))
    if not isinstance(profile_id, str) or _ID.fullmatch(profile_id) is None:
        diagnostics.append(_diag(path, "profile id must be kebab-case"))
    if status not in PROFILE_STATUSES:
        diagnostics.append(_diag(path, "profile status is invalid"))
    if profile_role not in PROFILE_ROLES:
        diagnostics.append(_diag(path, "profile_role is invalid"))
    derived_from = data.get("derived_from")
    if profile_role == "applied" and not _nonempty(derived_from):
        diagnostics.append(_diag(path, "applied profile requires derived_from"))
    if profile_role == "reference" and derived_from is not None:
        diagnostics.append(_diag(path, "reference profile cannot set derived_from"))
    if data.get("target_revision_policy") not in REVISION_POLICIES:
        diagnostics.append(_diag(path, "target_revision_policy is invalid"))
    for field in ("version", "language_family"):
        if not _nonempty(data.get(field)):
            diagnostics.append(_diag(path, f"{field} must be non-empty"))

    evidence = _mapping(data.get("evidence"))
    revision = evidence.get("revision")
    upstream = evidence.get("upstream_revision")
    if not _https(evidence.get("repository")):
        diagnostics.append(_diag(path, "evidence repository must be HTTPS"))
    if not isinstance(revision, str) or _SHA.fullmatch(revision) is None:
        diagnostics.append(_diag(path, "evidence revision must be a full SHA"))
    if upstream is not None and (
        not isinstance(upstream, str) or _SHA.fullmatch(upstream) is None
    ):
        diagnostics.append(_diag(path, "upstream_revision must be a full SHA"))
    if not _nonempty(evidence.get("license")):
        diagnostics.append(_diag(path, "evidence license must be non-empty"))
    try:
        date.fromisoformat(str(evidence.get("observed_on")))
    except ValueError:
        diagnostics.append(_diag(path, "observed_on must be an ISO date"))

    toolchain = _mapping(data.get("toolchain"))
    scripts = _string_mapping(toolchain.get("scripts"))
    if not scripts:
        diagnostics.append(_diag(path, "toolchain scripts must be a mapping"))
    for field in ("runtime", "runtime_range", "package_manager", "lockfile"):
        if not _nonempty(toolchain.get(field)):
            diagnostics.append(_diag(path, f"toolchain {field} is missing"))

    scope = _mapping(data.get("scope"))
    for field in (
        "source_roots",
        "test_roots",
        "required_files",
        "generated_outputs",
        "exclusions",
    ):
        values = _string_list(scope.get(field))
        if values is None or not values:
            diagnostics.append(_diag(path, f"scope {field} must be non-empty"))
            continue
        for value in values:
            if not _safe_relative(value):
                diagnostics.append(_diag(path, f"unsafe profile path: {value}"))

    counts = _int_mapping(_mapping(data.get("observed")).get("file_counts"))
    for field in ("source_typescript", "test_typescript", "lint_files"):
        if field not in counts:
            diagnostics.append(_diag(path, f"observed file count is missing: {field}"))

    baseline = _mapping(data.get("warning_baseline"))
    rules = _int_mapping(baseline.get("rules"))
    warning_count = baseline.get("warning_count")
    if baseline.get("revision") != revision:
        diagnostics.append(_diag(path, "warning baseline revision must match evidence"))
    if baseline.get("error_count") != 0:
        diagnostics.append(_diag(path, "hard errors cannot enter the warning baseline"))
    if not isinstance(warning_count, int) or warning_count < 0:
        diagnostics.append(_diag(path, "warning_count must be non-negative"))
    elif warning_count != sum(rules.values()):
        diagnostics.append(_diag(path, "warning_count must equal per-rule counts"))
    if baseline.get("policy") != "shrink-only":
        diagnostics.append(_diag(path, "warning baseline policy must be shrink-only"))

    sequence = _string_list(data.get("canonical_sequence"))
    if sequence is None or not sequence or len(sequence) != len(set(sequence)):
        diagnostics.append(
            _diag(path, "canonical_sequence must be unique and non-empty")
        )
        sequence = []
    gates = data.get("gates")
    seen: set[str] = set()
    blocked = False
    if not isinstance(gates, list):
        diagnostics.append(_diag(path, "gates must be a list"))
    else:
        for item in gates:
            if not isinstance(item, dict):
                diagnostics.append(_diag(path, "every gate must be a mapping"))
                continue
            gate_id = item.get("id")
            gate_status = item.get("status")
            if not isinstance(gate_id, str) or gate_id not in GATE_IDS:
                diagnostics.append(_diag(path, f"unknown gate id: {gate_id}"))
                continue
            if gate_id in seen:
                diagnostics.append(_diag(path, f"duplicate gate: {gate_id}"))
            seen.add(gate_id)
            if gate_status not in GATE_STATUSES:
                diagnostics.append(_diag(path, f"invalid gate status: {gate_id}"))
            commands = _string_list(item.get("commands"))
            if commands is None:
                diagnostics.append(_diag(path, f"gate commands are invalid: {gate_id}"))
                commands = []
            for command in commands:
                if command not in sequence:
                    diagnostics.append(
                        _diag(
                            path,
                            f"gate command is outside canonical sequence: {command}",
                        )
                    )
            if gate_status in {"enforced", "ratcheted"} and not commands:
                diagnostics.append(
                    _diag(path, f"enforced gate has no command: {gate_id}")
                )
            if gate_status in {"blocked", "not-applicable"} and not _nonempty(
                item.get("reason")
            ):
                diagnostics.append(_diag(path, f"gate reason is missing: {gate_id}"))
            if gate_status == "blocked":
                blocked = True
    if seen != set(GATE_IDS):
        missing = ", ".join(sorted(set(GATE_IDS) - seen))
        diagnostics.append(_diag(path, f"profile must define all six gates: {missing}"))

    blockers = _string_list(data.get("known_blockers"))
    if blockers is None:
        diagnostics.append(_diag(path, "known_blockers must be a list"))
        blockers = []
    if status == "active" and (blockers or blocked):
        diagnostics.append(_diag(path, "active profile cannot retain blockers"))
    promotion = _mapping(data.get("promotion"))
    if not _string_list(promotion.get("requires")):
        diagnostics.append(_diag(path, "promotion requirements must be non-empty"))
    return diagnostics


def inspect_target(
    profile_path: Path,
    profile: dict[str, Any],
    target: Path,
) -> dict[str, Any]:
    """Inspect pinned target structure without executing target-owned commands."""

    target = target.resolve()
    diagnostics = validate_profile_data(profile_path, profile)
    revision = _git(target, "rev-parse", "HEAD")
    expected_revision = _mapping(profile.get("evidence")).get("revision")
    revision_policy = profile.get("target_revision_policy")
    if revision_policy == "exact" and revision != expected_revision:
        diagnostics.append(
            _diag(target, f"target revision drift: {revision or 'unavailable'}")
        )
    elif revision_policy == "descendant" and (
        not isinstance(expected_revision, str)
        or not _git_is_ancestor(target, expected_revision)
    ):
        diagnostics.append(
            _diag(target, "target revision is not descended from profile evidence")
        )

    scope = _mapping(profile.get("scope"))
    required_files = _string_list(scope.get("required_files")) or []
    for relative in required_files:
        if not (target / relative).is_file():
            diagnostics.append(
                _diag(target / relative, "required profile file is missing")
            )

    package_path = target / "package.json"
    try:
        package = json.loads(package_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        diagnostics.append(_diag(package_path, f"package.json cannot be read: {error}"))
        package = {}
    actual_scripts = package.get("scripts", {}) if isinstance(package, dict) else {}
    expected_scripts = _string_mapping(
        _mapping(profile.get("toolchain")).get("scripts")
    )
    for name, command in expected_scripts.items():
        if not isinstance(actual_scripts, dict) or actual_scripts.get(name) != command:
            diagnostics.append(_diag(package_path, f"target script drift: {name}"))

    tracked = _git_files(target)
    source_roots = _string_list(scope.get("source_roots")) or []
    test_roots = _string_list(scope.get("test_roots")) or []
    counts = {
        "source_typescript": _count_typescript(tracked, source_roots),
        "test_typescript": _count_typescript(tracked, test_roots),
    }
    counts["lint_files"] = counts["source_typescript"] + counts["test_typescript"]
    expected_counts = _int_mapping(_mapping(profile.get("observed")).get("file_counts"))
    for name, expected in expected_counts.items():
        if counts.get(name) != expected:
            diagnostics.append(
                _diag(
                    target, f"target file population drift: {name}={counts.get(name)}"
                )
            )

    blockers = _string_list(profile.get("known_blockers")) or []
    return {
        "schema_version": PROFILE_SCHEMA_VERSION,
        "profile": profile.get("id"),
        "profile_role": profile.get("profile_role"),
        "profile_status": profile.get("status"),
        "target_revision_policy": revision_policy,
        "profile_path": profile_path.as_posix(),
        "target": target.as_posix(),
        "target_revision": revision,
        "file_counts": counts,
        "known_blockers": blockers,
        "promotion_eligible": not diagnostics and not blockers,
        "diagnostics": [item.render(target) for item in sorted(set(diagnostics))],
        "commands_executed": False,
    }


def _count_typescript(paths: list[str], roots: list[str]) -> int:
    return sum(
        1
        for path in paths
        if path.endswith((".ts", ".tsx"))
        and any(
            path == root or path.startswith(root.rstrip("/") + "/") for root in roots
        )
    )


def _git(root: Path, *args: str) -> str | None:
    result = subprocess.run(
        ["git", *args], cwd=root, check=False, capture_output=True, text=True
    )
    return result.stdout.strip() if result.returncode == 0 else None


def _git_is_ancestor(root: Path, ancestor: str) -> bool:
    result = subprocess.run(
        ["git", "merge-base", "--is-ancestor", ancestor, "HEAD"],
        cwd=root,
        check=False,
        capture_output=True,
        text=True,
    )
    return result.returncode == 0


def _repository_role(manifest_path: Path) -> str | None:
    try:
        manifest = load(manifest_path)
    except (OSError, UnicodeError, YamlSubsetError):
        return None
    if not isinstance(manifest, dict):
        return None
    project = manifest.get("project")
    if not isinstance(project, dict):
        return None
    role = project.get("repository_role")
    return role if isinstance(role, str) else None


def _git_files(root: Path) -> list[str]:
    result = subprocess.run(
        ["git", "ls-files", "-z"], cwd=root, check=False, capture_output=True
    )
    if result.returncode:
        return []
    return [item.decode("utf-8") for item in result.stdout.split(b"\0") if item]


def _safe_relative(value: str) -> bool:
    path = PurePosixPath(value)
    return (
        bool(value)
        and "\\" not in value
        and not path.is_absolute()
        and ".." not in path.parts
        and not fnmatch.fnmatchcase(value, "*/./*")
    )


def _mapping(value: object) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


def _string_mapping(value: object) -> dict[str, str]:
    if not isinstance(value, dict):
        return {}
    return {
        str(key): item
        for key, item in value.items()
        if isinstance(key, str) and isinstance(item, str) and item.strip()
    }


def _int_mapping(value: object) -> dict[str, int]:
    if not isinstance(value, dict):
        return {}
    return {
        str(key): item
        for key, item in value.items()
        if isinstance(key, str) and isinstance(item, int) and item >= 0
    }


def _string_list(value: object) -> list[str] | None:
    if not isinstance(value, list) or not all(
        isinstance(item, str) and item.strip() for item in value
    ):
        return None
    return list(value)


def _nonempty(value: object) -> bool:
    return isinstance(value, str) and bool(value.strip())


def _https(value: object) -> bool:
    return isinstance(value, str) and value.startswith("https://")


def _diag(path: Path, message: str) -> Diagnostic:
    return Diagnostic("DSET-E167", path, message)

from __future__ import annotations

import re
