ID_PATTERN = re.compile(r"^[A-Z0-9]+(?:-[A-Z0-9]+)+$")
SESSION_PATTERN = re.compile(r"^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$")
EVIDENCE_SUBTYPES = frozenset(
    {"test_result", "evaluation_result", "review_report", "run_record"}
)
POLARITIES = frozenset({"supports", "contradicts", "mixed", "inconclusive"})
CURRENTNESS = frozenset({"current", "stale", "superseded"})
REQUIRED_FIELDS = frozenset(
    {
        "schema_version",
        "artifact_type",
        "artifact_subtype",
        "artifact_id",
        "priority",
        "llm_session_ids",
        "subject",
        "producer",
        "method",
        "context",
        "evidence_location",
        "polarity",
        "currentness",
        "reopen_when",
        "relations",
    }
)
OPTIONAL_FIELDS = frozenset(
    {
        "observed_at",
        "validity_window",
        "independent_producer",
        "rival_explanations",
        "limitations",
        "rationale",
    }
)


def validate_evidence_records(
    root: Path,
    paths: Iterable[Path],
    legacy_paths: frozenset[str],
    *,
    allow_unversioned_legacy: bool = False,
) -> list[Diagnostic]:
    """Validate native Evidence Records while preserving a finite legacy set."""

    root = root.resolve()
    diagnostics: list[Diagnostic] = []
    for candidate in paths:
        path = candidate.resolve()
        if path.suffix.lower() != ".md" or has_logical_part(
            path.relative_to(root), {"templates"}
        ):
            continue
        relative = path.relative_to(root).as_posix()
        try:
            parsed = load_frontmatter(path)
        except (OSError, UnicodeError, FrontmatterError) as error:
            if relative in legacy_paths:
                continue
            diagnostics.append(_diag(path, str(error)))
            continue
        metadata = parsed[0] if parsed is not None else None
        artifact_type = metadata.get("artifact_type") if metadata is not None else None
        if relative in legacy_paths:
            if artifact_type not in {None, "evidence_record"}:
                diagnostics.append(
                    _diag(
                        path,
                        "legacy evidence compatibility path has a conflicting "
                        "artifact type",
                    )
                )
            continue
        if (
            allow_unversioned_legacy
            and artifact_type == "evidence_record"
            and metadata is not None
            and "schema_version" not in metadata
        ):
            continue
        if artifact_type != "evidence_record":
            continue
        if parsed is None or parsed[2] != "toml":
            diagnostics.append(
                _diag(path, "new Evidence Records require TOML frontmatter")
            )
            continue
        assert metadata is not None
        diagnostics.extend(_validate_native_record(path, metadata))
    return diagnostics


def _validate_native_record(path: Path, data: dict[str, Any]) -> list[Diagnostic]:
    diagnostics: list[Diagnostic] = []
    keys = set(data)
    missing = sorted(REQUIRED_FIELDS - keys)
    unknown = sorted(keys - REQUIRED_FIELDS - OPTIONAL_FIELDS)
    if missing:
        diagnostics.append(
            _diag(path, "Evidence Record is missing fields: " + ", ".join(missing))
        )
    if unknown:
        diagnostics.append(
            _diag(path, "Evidence Record has unknown fields: " + ", ".join(unknown))
        )
    if data.get("schema_version") != "1.0":
        diagnostics.append(_diag(path, "Evidence Record schema_version must be 1.0"))
    if data.get("artifact_type") != "evidence_record":
        diagnostics.append(_diag(path, "artifact_type must be evidence_record"))
    if data.get("artifact_subtype") not in EVIDENCE_SUBTYPES:
        diagnostics.append(_diag(path, "Evidence Record subtype is invalid"))
    _required_id(path, data.get("artifact_id"), "artifact_id", diagnostics)
    _nonempty(path, data.get("priority"), "priority", diagnostics)
    _sessions(path, data.get("llm_session_ids"), diagnostics)
    _subject(path, data.get("subject"), diagnostics)
    _producer(path, data.get("producer"), diagnostics)
    _method(path, data.get("method"), diagnostics)
    _nonempty_list(path, data.get("context"), "context", diagnostics)
    _nonempty(path, data.get("evidence_location"), "evidence_location", diagnostics)
    if data.get("polarity") not in POLARITIES:
        diagnostics.append(_diag(path, "Evidence Record polarity is invalid"))
    if data.get("currentness") not in CURRENTNESS:
        diagnostics.append(_diag(path, "Evidence Record currentness is invalid"))
    _nonempty(path, data.get("reopen_when"), "reopen_when", diagnostics)
    _observation_time(path, data, diagnostics)
    _relations(path, data.get("relations"), diagnostics)
    _optional_extensions(path, data, diagnostics)
    return diagnostics


def _subject(path: Path, value: object, diagnostics: list[Diagnostic]) -> None:
    if not isinstance(value, dict) or set(value) != {
        "id",
        "revision",
        "intended_use",
    }:
        diagnostics.append(
            _diag(path, "subject requires exactly id, revision, and intended_use")
        )
        return
    _required_id(path, value.get("id"), "subject.id", diagnostics)
    revision = value.get("revision")
    _nonempty(path, revision, "subject.revision", diagnostics)
    if isinstance(revision, str) and revision.strip().lower() == "pending":
        diagnostics.append(_diag(path, "subject.revision cannot be pending"))
    _nonempty(path, value.get("intended_use"), "subject.intended_use", diagnostics)


def _producer(path: Path, value: object, diagnostics: list[Diagnostic]) -> None:
    if not isinstance(value, dict) or set(value) != {"identity", "performed_work"}:
        diagnostics.append(
            _diag(path, "producer requires exactly identity and performed_work")
        )
        return
    _nonempty(path, value.get("identity"), "producer.identity", diagnostics)
    _nonempty(path, value.get("performed_work"), "producer.performed_work", diagnostics)


def _method(path: Path, value: object, diagnostics: list[Diagnostic]) -> None:
    if not isinstance(value, dict) or set(value) != {"description", "setup"}:
        diagnostics.append(_diag(path, "method requires exactly description and setup"))
        return
    _nonempty(path, value.get("description"), "method.description", diagnostics)
    _nonempty(path, value.get("setup"), "method.setup", diagnostics)


def _observation_time(
    path: Path, data: dict[str, Any], diagnostics: list[Diagnostic]
) -> None:
    has_observed = "observed_at" in data
    has_window = "validity_window" in data
    if has_observed == has_window:
        diagnostics.append(
            _diag(
                path,
                "Evidence Record requires exactly one observed_at or validity_window",
            )
        )
        return
    if has_observed:
        _timestamp(path, data.get("observed_at"), "observed_at", diagnostics)
        return
    window = data.get("validity_window")
    if not isinstance(window, dict) or set(window) != {"from", "through"}:
        diagnostics.append(
            _diag(path, "validity_window requires exactly from and through")
        )
        return
    _timestamp(path, window.get("from"), "validity_window.from", diagnostics)
    _timestamp(path, window.get("through"), "validity_window.through", diagnostics)


def _relations(path: Path, value: object, diagnostics: list[Diagnostic]) -> None:
    if not isinstance(value, list) or not value:
        diagnostics.append(_diag(path, "Evidence Record requires relations"))
        return
    evidence_targets: list[str] = []
    for relation in value:
        if not isinstance(relation, dict):
            diagnostics.append(_diag(path, "every evidence relation must be a table"))
            continue
        if relation.get("type") == "evidence_for":
            target = relation.get("target")
            if isinstance(target, str) and ID_PATTERN.fullmatch(target):
                evidence_targets.append(target)
    if not evidence_targets:
        diagnostics.append(
            _diag(path, "Evidence Record requires a canonical evidence_for relation")
        )


def _optional_extensions(
    path: Path, data: dict[str, Any], diagnostics: list[Diagnostic]
) -> None:
    if "independent_producer" in data and not isinstance(
        data["independent_producer"], bool
    ):
        diagnostics.append(_diag(path, "independent_producer must be boolean"))
    for field in ("rival_explanations", "limitations"):
        if field in data:
            _nonempty_list(path, data[field], field, diagnostics)
    if "rationale" in data:
        _nonempty(path, data["rationale"], "rationale", diagnostics)


def _sessions(path: Path, value: object, diagnostics: list[Diagnostic]) -> None:
    if not isinstance(value, list):
        diagnostics.append(_diag(path, "llm_session_ids must be a list"))
        return
    if len(value) != len(set(str(item) for item in value)) or any(
        not isinstance(item, str) or SESSION_PATTERN.fullmatch(item) is None
        for item in value
    ):
        diagnostics.append(_diag(path, "llm_session_ids are invalid or duplicated"))


def _required_id(
    path: Path, value: object, field: str, diagnostics: list[Diagnostic]
) -> None:
    if not isinstance(value, str) or ID_PATTERN.fullmatch(value) is None:
        diagnostics.append(_diag(path, f"{field} must be a canonical ID"))


def _nonempty(
    path: Path, value: object, field: str, diagnostics: list[Diagnostic]
) -> None:
    if not isinstance(value, str) or not value.strip():
        diagnostics.append(_diag(path, f"{field} must be non-empty text"))


def _nonempty_list(
    path: Path, value: object, field: str, diagnostics: list[Diagnostic]
) -> None:
    if (
        not isinstance(value, list)
        or not value
        or any(not isinstance(item, str) or not item.strip() for item in value)
    ):
        diagnostics.append(_diag(path, f"{field} must be a non-empty text list"))


def _timestamp(
    path: Path, value: object, field: str, diagnostics: list[Diagnostic]
) -> None:
    if not isinstance(value, str):
        diagnostics.append(_diag(path, f"{field} must be an ISO-8601 timestamp"))
        return
    try:
        parsed = datetime.fromisoformat(value.replace("Z", "+00:00"))
    except ValueError:
        diagnostics.append(_diag(path, f"{field} must be an ISO-8601 timestamp"))
        return
    if parsed.tzinfo is None:
        diagnostics.append(_diag(path, f"{field} must include a timezone"))


def _diag(path: Path, message: str) -> Diagnostic:
    return Diagnostic("DSET-E168", path, message)

from __future__ import annotations

import hashlib
import json
import re
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Any

from .frontmatter import FrontmatterError
from .frontmatter import parse as parse_frontmatter
from .frontmatter import render as render_frontmatter
from .identity import find_unique_name
from .layout import discover_layout
from .project_data import project_section
from .settings import load_project_settings
from .yaml_subset import load

ID_PATTERN = re.compile(r"^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$")
FINDING_PATTERN = re.compile(r"^[A-Z][A-Z0-9]*-REVIEW-FINDING-[0-9]{3,}$")
SESSION_PATTERN = re.compile(r"^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$")
SHA_PATTERN = re.compile(r"^[0-9a-f]{40}$")
DISPOSITIONS = frozenset(
    {
        "reject",
        "defer",
        "route_problem",
        "route_question",
        "route_decision",
        "route_change",
        "route_evergreen",
        "route_proof",
    }
)


def create_review_packet(
    root: Path,
    output: Path,
    *,
    packet_id: str,
    artifacts: list[str],
    criteria: list[str],
    scope: str,
) -> Path:
    root = root.resolve()
    if not ID_PATTERN.fullmatch(packet_id) or "REVIEW-PACKET" not in packet_id:
        raise ValueError("packet_id must be a canonical REVIEW-PACKET ID")
    if not artifacts or len(set(artifacts)) != len(artifacts):
        raise ValueError("packet requires unique reviewed artifacts")
    if not criteria or any(not item.strip() for item in criteria):
        raise ValueError("packet requires non-empty review criteria")
    if not scope.strip():
        raise ValueError("packet requires a bounded scope")
    reviewed = [_file_identity(root, raw) for raw in artifacts]
    registry = project_section(root, "governance_registry")
    raw_rules = registry.get("rules", []) if isinstance(registry, dict) else []
    rules: list[dict[str, str]] = []
    for item in raw_rules:
        if not isinstance(item, dict) or item.get("applicability") != "applicable":
            continue
        rule_path = item.get("document")
        rule_id = item.get("id")
        if not isinstance(rule_path, str) or not isinstance(rule_id, str):
            continue
        identity = _file_identity(root, rule_path)
        rules.append({"id": rule_id, **identity})
    packet = {
        "schema_version": "1.0",
        "artifact_type": "plan",
        "artifact_id": packet_id.replace("REVIEW-PACKET", "PLAN"),
        "packet_id": packet_id,
        "repository": _repository_identity(root),
        "commit": _head(root),
        "scope": scope,
        "criteria": criteria,
        "reviewed_inputs": reviewed,
        "resolved_rules": sorted(rules, key=lambda item: item["id"]),
        "allowed_effects": ["read_only_report"],
    }
    content = _markdown(packet, "External review packet", _packet_body())
    return _write_new(output, content)


def validate_review_report(
    root: Path, packet_path: Path, report_path: Path
) -> dict[str, Any]:
    root = root.resolve()
    packet, _ = _read_markdown(packet_path)
    report, body = _read_markdown(report_path)
    _validate_packet(root, packet)
    settings, issues = load_project_settings(root)
    if issues:
        raise ValueError(issues[0])
    allowed_priorities = {*settings.priority_scale, "unknown"}
    _validate_report(packet, report, body, allowed_priorities)
    return {
        "report_id": report["artifact_id"],
        "packet_id": report["packet_id"],
        "reviewed_commit": report["reviewed_commit"],
        "report_sha256": _sha256(report_path),
        "finding_ids": [item["id"] for item in report["findings"]],
        "implementation_authorized": False,
    }


def reconcile_review(
    root: Path,
    packet_path: Path,
    report_path: Path,
    candidate_path: Path,
) -> dict[str, Any]:
    validated = validate_review_report(root, packet_path, report_path)
    candidate = json.loads(candidate_path.read_text(encoding="utf-8"))
    if not isinstance(candidate, dict):
        raise ValueError("review reconciliation must be a JSON object")
    required = {
        "schema_version",
        "report_id",
        "report_sha256",
        "reconciled_at",
        "llm_session_ids",
        "findings",
    }
    if set(candidate) != required or candidate.get("schema_version") != "1.0":
        raise ValueError("review reconciliation envelope is invalid")
    if candidate.get("report_id") != validated["report_id"]:
        raise ValueError("reconciliation report_id does not match the report")
    if candidate.get("report_sha256") != validated["report_sha256"]:
        raise ValueError("reconciliation report digest does not match the report")
    _datetime(str(candidate.get("reconciled_at")), "reconciled_at")
    _sessions(candidate.get("llm_session_ids"))
    raw_findings = candidate.get("findings")
    if not isinstance(raw_findings, list):
        raise ValueError("reconciliation findings must be a list")
    reconciled = [_validate_disposition(item) for item in raw_findings]
    actual_ids = [item["finding_id"] for item in reconciled]
    expected_ids = list(validated["finding_ids"])
    if len(actual_ids) != len(set(actual_ids)):
        raise ValueError("reconciliation finding IDs must be unique")
    if set(actual_ids) != set(expected_ids):
        raise ValueError("every report finding requires exactly one disposition")
    ordered = sorted(
        reconciled, key=lambda item: expected_ids.index(item["finding_id"])
    )
    return {
        "schema_version": "1.0",
        "artifact_type": "evidence_record",
        "artifact_subtype": "review_report",
        "report_id": validated["report_id"],
        "report_sha256": validated["report_sha256"],
        "reconciled_at": candidate["reconciled_at"],
        "llm_session_ids": candidate["llm_session_ids"],
        "findings": ordered,
        "reopen_proof": sorted(
            {proof for item in ordered for proof in item.get("reopen_proof", [])}
        ),
        "implementation_authorized": False,
    }


def write_reconciliation(root: Path, output: Path, result: dict[str, Any]) -> Path:
    root = root.resolve()
    target = output.resolve()
    try:
        target.relative_to(root)
    except ValueError as error:
        raise ValueError(
            "reconciliation output must remain inside the repository"
        ) from error
    return _write_new(target, json.dumps(result, indent=2, sort_keys=True) + "\n")


def _validate_packet(root: Path, packet: dict[str, Any]) -> None:
    required = {
        "schema_version",
        "artifact_type",
        "artifact_id",
        "packet_id",
        "repository",
        "commit",
        "scope",
        "criteria",
        "reviewed_inputs",
        "resolved_rules",
        "allowed_effects",
    }
    if set(packet) != required or packet.get("schema_version") != "1.0":
        raise ValueError("review packet envelope is invalid")
    if packet.get("artifact_type") != "plan":
        raise ValueError("review packet must be classified as a plan")
    if packet.get("allowed_effects") != ["read_only_report"]:
        raise ValueError("review packet may authorize only a read-only report")
    if packet.get("repository") != _repository_identity(root):
        raise ValueError("review packet repository does not match the project")
    if not isinstance(packet.get("commit"), str) or not SHA_PATTERN.fullmatch(
        str(packet["commit"])
    ):
        raise ValueError("review packet requires an exact commit")
    reviewed_inputs = packet.get("reviewed_inputs")
    if not isinstance(reviewed_inputs, list) or not reviewed_inputs:
        raise ValueError("review packet requires exact input identities")
    for item in reviewed_inputs:
        if not _valid_identity(item, with_id=False):
            raise ValueError("review packet input identity is invalid")
    resolved_rules = packet.get("resolved_rules")
    if not isinstance(resolved_rules, list) or not resolved_rules:
        raise ValueError("review packet requires resolved governing rules")
    for item in resolved_rules:
        if not _valid_identity(item, with_id=True):
            raise ValueError("review packet rule identity is invalid")


def _validate_report(
    packet: dict[str, Any],
    report: dict[str, Any],
    body: str,
    allowed_priorities: set[str],
) -> None:
    required = {
        "schema_version",
        "artifact_type",
        "artifact_subtype",
        "artifact_id",
        "packet_id",
        "priority",
        "reviewer",
        "llm_session_ids",
        "reviewed_commit",
        "reviewed_inputs",
        "method",
        "observed_at",
        "limitations",
        "findings",
    }
    if set(report) != required or report.get("schema_version") != "1.0":
        raise ValueError("review report envelope is invalid")
    if (report.get("artifact_type"), report.get("artifact_subtype")) != (
        "evidence_record",
        "review_report",
    ):
        raise ValueError("review report classification is invalid")
    if report.get("packet_id") != packet.get("packet_id"):
        raise ValueError("review report packet_id does not match")
    if report.get("reviewed_commit") != packet.get("commit"):
        raise ValueError("review report commit does not match the packet")
    if report.get("reviewed_inputs") != packet.get("reviewed_inputs"):
        raise ValueError("review report inputs do not match the packet")
    if report.get("priority") not in allowed_priorities:
        raise ValueError("review report priority is invalid")
    reviewer = report.get("reviewer")
    reviewer_keys = {"identity", "host", "model", "tool_version"}
    if not isinstance(reviewer, dict) or set(reviewer) != reviewer_keys:
        raise ValueError("reviewer identity envelope is invalid")
    if any(
        not isinstance(value, str) or not value.strip() for value in reviewer.values()
    ):
        raise ValueError("reviewer identity values must be non-empty")
    _sessions(report.get("llm_session_ids"))
    if not isinstance(report.get("method"), str) or not report["method"].strip():
        raise ValueError("review report method is required")
    _datetime(str(report.get("observed_at")), "observed_at")
    limitations = report.get("limitations")
    if not isinstance(limitations, list) or not all(
        isinstance(item, str) and item.strip() for item in limitations
    ):
        raise ValueError("review report limitations must be an explicit list")
    findings = report.get("findings")
    if not isinstance(findings, list):
        raise ValueError("review report findings must be a list")
    finding_ids: list[str] = []
    for finding in findings:
        _validate_finding(finding, allowed_priorities)
        assert isinstance(finding, dict)
        finding_ids.append(str(finding["id"]))
    if len(finding_ids) != len(set(finding_ids)):
        raise ValueError("review finding IDs must be unique")
    if not body.strip():
        raise ValueError("review report requires a findings body")


def _validate_finding(finding: object, allowed_priorities: set[str]) -> None:
    fields = {
        "id",
        "priority",
        "evidence",
        "confidence",
        "impact",
        "proposed_disposition",
    }
    if not isinstance(finding, dict) or set(finding) != fields:
        raise ValueError("review finding envelope is invalid")
    identifier = finding.get("id")
    if not isinstance(identifier, str) or not FINDING_PATTERN.fullmatch(identifier):
        raise ValueError("review finding ID is invalid")
    if finding.get("priority") not in allowed_priorities:
        raise ValueError("review finding priority is invalid")
    if finding.get("confidence") not in {"low", "medium", "high"}:
        raise ValueError("review finding confidence is invalid")
    if finding.get("proposed_disposition") not in DISPOSITIONS:
        raise ValueError("review finding proposed disposition is invalid")
    for key in ("evidence", "impact"):
        if not isinstance(finding.get(key), str) or not finding[key].strip():
            raise ValueError(f"review finding {key} is required")


def _validate_disposition(value: object) -> dict[str, Any]:
    if not isinstance(value, dict):
        raise ValueError("every reconciliation finding must be an object")
    allowed = {
        "finding_id",
        "disposition",
        "rationale",
        "target_id",
        "reopen_proof",
    }
    if not set(value).issubset(allowed):
        raise ValueError("reconciliation finding contains unknown fields")
    finding_id = value.get("finding_id")
    disposition = value.get("disposition")
    rationale = value.get("rationale")
    if not isinstance(finding_id, str) or not FINDING_PATTERN.fullmatch(finding_id):
        raise ValueError("reconciliation finding_id is invalid")
    if disposition not in DISPOSITIONS:
        raise ValueError("reconciliation disposition is invalid")
    if not isinstance(rationale, str) or not rationale.strip():
        raise ValueError("every reconciliation disposition requires rationale")
    routed = str(disposition).startswith("route_")
    target_id = value.get("target_id")
    valid_target = isinstance(target_id, str) and bool(ID_PATTERN.fullmatch(target_id))
    if routed != valid_target:
        raise ValueError("routed findings require one canonical target_id")
    reopen = value.get("reopen_proof", [])
    if not isinstance(reopen, list) or not all(
        isinstance(item, str) and ID_PATTERN.fullmatch(item) for item in reopen
    ):
        raise ValueError("reopen_proof must contain canonical IDs")
    result = {
        "finding_id": finding_id,
        "disposition": disposition,
        "rationale": rationale,
        "reopen_proof": sorted(set(reopen)),
    }
    if routed:
        result["target_id"] = target_id
    return result


def _read_markdown(path: Path) -> tuple[dict[str, Any], str]:
    try:
        parsed = parse_frontmatter(path.read_text(encoding="utf-8"))
    except FrontmatterError as error:
        raise ValueError(
            f"review artifact frontmatter is invalid: {path}: {error}"
        ) from error
    if parsed is None:
        raise ValueError(f"review artifact requires TOML or YAML frontmatter: {path}")
    data, body, _format = parsed
    return data, body


def _file_identity(root: Path, raw: str) -> dict[str, str]:
    candidate = find_unique_name(root, raw)
    return {"carrier": candidate.name, "sha256": _sha256(candidate)}


def _valid_identity(value: object, *, with_id: bool) -> bool:
    if not isinstance(value, dict):
        return False
    fields = {"carrier", "sha256"}
    if with_id:
        fields.add("id")
    if set(value) != fields:
        return False
    carrier = value.get("carrier")
    digest = value.get("sha256")
    identifier = value.get("id")
    return (
        isinstance(carrier, str)
        and bool(carrier)
        and Path(carrier).name == carrier
        and isinstance(digest, str)
        and bool(re.fullmatch(r"[0-9a-f]{64}", digest))
        and (
            not with_id
            or (isinstance(identifier, str) and bool(ID_PATTERN.fullmatch(identifier)))
        )
    )


def _repository_identity(root: Path) -> str:
    manifest = load(discover_layout(root).manifest_path)
    project = manifest.get("project", {}) if isinstance(manifest, dict) else {}
    value = project.get("repository_slug") or project.get("id")
    if not isinstance(value, str) or not value:
        raise ValueError("project manifest requires repository identity")
    return value


def _head(root: Path) -> str:
    completed = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=root,
        check=False,
        capture_output=True,
        text=True,
    )
    value = completed.stdout.strip()
    if completed.returncode or not SHA_PATTERN.fullmatch(value):
        raise ValueError("review packet requires a Git repository with an exact HEAD")
    return value


def _sessions(value: object) -> None:
    if not isinstance(value, list) or len(value) != len(set(map(str, value))):
        raise ValueError("llm_session_ids must be a unique list")
    if not all(
        isinstance(item, str) and SESSION_PATTERN.fullmatch(item) for item in value
    ):
        raise ValueError("llm_session_ids must use host-prefixed identities")


def _datetime(value: str, field: str) -> None:
    try:
        datetime.fromisoformat(value.replace("Z", "+00:00"))
    except ValueError as error:
        raise ValueError(f"{field} must be an ISO 8601 timestamp") from error


def _sha256(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()


def _markdown(metadata: dict[str, Any], title: str, body: str) -> str:
    return render_frontmatter(metadata, f"\n# {title}\n\n{body.rstrip()}\n")


def _packet_body() -> str:
    return (
        "Review only the exact commit, input digests, rules, scope, and criteria "
        "in the envelope. Return a report; do not edit the project or authorize repair."
    )


def _write_new(path: Path, content: str) -> Path:
    path = path.resolve()
    if path.exists():
        raise FileExistsError(f"refusing existing review artifact: {path}")
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
    return path

"""Shared dual-format Markdown frontmatter codec.

Legacy DSET documents use YAML between ``---`` delimiters.  TOML authority
documents use ``+++``.  Reading accepts both so the migration has a clean
compatibility boundary; rendering defaults to TOML for all DSET-owned output.
"""

from __future__ import annotations

from pathlib import Path
from typing import Any

from .toml_codec import TomlCodecError
from .toml_codec import dumps as dump_toml
from .toml_codec import loads as load_toml
from .yaml_subset import YamlSubsetError
from .yaml_subset import loads as load_yaml


class FrontmatterError(ValueError):
    """A Markdown frontmatter envelope is malformed or unsupported."""


def parse(text: str) -> tuple[dict[str, Any], str, str] | None:
    """Return ``(metadata, body, format)`` or ``None`` without frontmatter."""

    lines = text.splitlines(keepends=True)
    if not lines:
        return None
    delimiter = lines[0].strip()
    if delimiter not in {"---", "+++"}:
        return None
    for index, line in enumerate(lines[1:], start=1):
        if line.strip() != delimiter:
            continue
        payload = "".join(lines[1:index])
        try:
            value = load_yaml(payload) if delimiter == "---" else load_toml(payload)
        except (YamlSubsetError, TomlCodecError) as error:
            raise FrontmatterError(str(error)) from error
        if not isinstance(value, dict):
            raise FrontmatterError("frontmatter root must be a mapping")
        return (
            value,
            "".join(lines[index + 1 :]),
            ("yaml" if delimiter == "---" else "toml"),
        )
    raise FrontmatterError("frontmatter opening delimiter has no closing delimiter")


def load(path: Path) -> tuple[dict[str, Any], str, str] | None:
    """Read frontmatter from a Markdown path."""

    return parse(path.read_text(encoding="utf-8"))


def metadata(path: Path) -> dict[str, Any] | None:
    """Read only a frontmatter mapping, returning ``None`` when absent."""

    parsed = load(path)
    return parsed[0] if parsed is not None else None


def format_for_path(path: Path, *, default: str = "toml") -> str:
    """Preserve an existing envelope during compatibility-mode regeneration."""

    try:
        parsed = load(path)
    except (OSError, UnicodeError, FrontmatterError):
        return default
    return parsed[2] if parsed is not None else default


def render(metadata: dict[str, Any], body: str, *, format: str = "toml") -> str:
    """Render a complete Markdown envelope in the requested format."""

    if format == "toml":
        return f"+++\n{dump_toml(metadata)}+++\n{body}"
    if format == "yaml":
        from .yaml_subset import dump as dump_yaml

        return f"---\n{dump_yaml(metadata)}---\n{body}"
    raise FrontmatterError(f"unsupported frontmatter format: {format}")

