ID_PATTERN = re.compile(r"^[A-Z0-9]+(?:-[A-Z0-9]+)+$")


def build_legacy_authority_ledger(root: Path) -> dict[str, Any]:
    """Digest-seal legacy Decision authority without freezing shared carriers."""
    from .semantic_types import build_semantic_classification_index

    root = root.resolve()
    records: list[dict[str, Any]] = []
    for row in build_semantic_classification_index(root):
        origins = [
            str(origin)
            for origin in row["origins"]
            if origin == "legacy_decision" or str(origin).startswith("package:")
        ]
        if row["type"] != "decision" or not origins:
            continue
        fragments: list[dict[str, str]] = []
        for origin in origins:
            for relative in row["carriers"]:
                path = root / str(relative)
                fragment = _authority_fragment(root, path, str(row["id"]), origin)
                if fragment is not None:
                    fragments.append(fragment)
        if not fragments:
            raise ValueError(f"legacy authority has no sealable fragment: {row['id']}")
        records.append(
            {
                "semantic_id": row["id"],
                "type": row["type"],
                "subtype": row["subtype"],
                "fragments": sorted(
                    fragments,
                    key=lambda item: (item["path"], item["selector"]),
                ),
            }
        )
    return {
        "schema_version": "1.0",
        "records": sorted(records, key=lambda item: str(item["semantic_id"])),
    }


def write_legacy_authority_ledger(root: Path) -> Path:
    root = root.resolve()
    path = legacy_authority_ledger_path(root)
    content = dump(build_legacy_authority_ledger(root), path)
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_suffix(path.suffix + ".tmp")
    temporary.write_text(content, encoding="utf-8")
    temporary.replace(path)
    return path


def validate_legacy_authority_ledger(root: Path) -> list[Diagnostic]:
    root = root.resolve()
    path = legacy_authority_ledger_path(root)
    if not path.is_file():
        try:
            expected = build_legacy_authority_ledger(root)
        except (OSError, ValueError) as error:
            return [Diagnostic("DSET-E167", path, str(error))]
        if expected["records"]:
            if not (root / ".git").exists():
                return []
            return [Diagnostic("DSET-E167", path, "legacy authority ledger is missing")]
        return []
    try:
        actual = load(path)
    except (OSError, UnicodeError, YamlSubsetError) as error:
        return [Diagnostic("DSET-E167", path, f"invalid legacy ledger: {error}")]
    if _recorded_fragment_errors(root, actual):
        return [
            Diagnostic(
                "DSET-E167",
                path,
                "legacy Decision authority changed without native successors",
            )
        ]
    return []


def legacy_shared_package_paths(root: Path) -> tuple[Path, ...]:
    """Return package carriers trusted as selector-sealed historical input."""

    root = root.resolve()
    ledger = _load_recorded_ledger(root)
    records = ledger.get("records") if isinstance(ledger, dict) else None
    if not isinstance(records, list):
        return ()
    paths: set[Path] = set()
    for record in records:
        fragments = record.get("fragments") if isinstance(record, dict) else None
        if not isinstance(fragments, list):
            continue
        for fragment in fragments:
            if not isinstance(fragment, dict):
                continue
            raw_path = fragment.get("path")
            current_path = fragment.get("current_path")
            selector = fragment.get("selector")
            if not isinstance(raw_path, str) or selector == "whole-carrier":
                continue
            active = current_path if isinstance(current_path, str) else raw_path
            candidate = (root / active).resolve()
            if (
                _within(root, candidate)
                and (
                    candidate.name in {"package.yaml", "package.yml"}
                    or candidate.name.endswith("package.legacy.toml")
                )
                and candidate.is_file()
            ):
                paths.add(candidate)
    return tuple(sorted(paths))


def legacy_authority_ids(root: Path) -> set[str]:
    """Expose historical IDs without making them current package ownership."""

    identifiers: set[str] = set()
    for path in legacy_shared_package_paths(root):
        try:
            data = _load_fragment_carrier(path)
        except (OSError, UnicodeError, YamlSubsetError):
            continue
        if not isinstance(data, dict):
            continue
        for value in data.values():
            if isinstance(value, list):
                identifiers.update(
                    item
                    for item in value
                    if isinstance(item, str) and ID_PATTERN.fullmatch(item)
                )
    ledger = _load_recorded_ledger(root)
    records = ledger.get("records") if isinstance(ledger, dict) else None
    if isinstance(records, list):
        identifiers.update(
            str(record["semantic_id"])
            for record in records
            if isinstance(record, dict) and isinstance(record.get("semantic_id"), str)
        )
    return identifiers


def legacy_authority_ledger_path(root: Path) -> Path:
    layout = discover_layout(root.resolve())
    return layout.structured_file(layout.project_state_root, "legacy-authority.toml")


def _load_recorded_ledger(root: Path) -> dict[str, Any] | None:
    path = legacy_authority_ledger_path(root)
    if not path.is_file():
        return None
    try:
        data = load(path)
    except (OSError, UnicodeError, YamlSubsetError):
        return None
    return data if isinstance(data, dict) else None


def _recorded_fragment_errors(root: Path, ledger: object) -> list[str]:
    if not isinstance(ledger, dict) or str(ledger.get("schema_version")) != "1.0":
        return ["legacy authority ledger schema_version must be 1.0"]
    records = ledger.get("records")
    if not isinstance(records, list):
        return ["legacy authority ledger records must be a list"]
    errors: list[str] = []
    seen: set[str] = set()
    for record in records:
        if not isinstance(record, dict) or not isinstance(
            record.get("semantic_id"), str
        ):
            errors.append("legacy authority record is malformed")
            continue
        semantic_id = str(record["semantic_id"])
        if semantic_id in seen:
            errors.append(f"duplicate legacy authority ID: {semantic_id}")
        seen.add(semantic_id)
        fragments = record.get("fragments")
        if not isinstance(fragments, list) or not fragments:
            errors.append(f"legacy authority has no fragments: {semantic_id}")
            continue
        for fragment in fragments:
            error = _validate_recorded_fragment(root, semantic_id, fragment)
            if error is not None:
                errors.append(error)
    return errors


def _validate_recorded_fragment(
    root: Path, semantic_id: str, fragment: object
) -> str | None:
    if not isinstance(fragment, dict):
        return f"legacy authority fragment is malformed: {semantic_id}"
    raw_path = fragment.get("path")
    selector = fragment.get("selector")
    expected = fragment.get("sha256")
    if not all(isinstance(item, str) for item in (raw_path, selector, expected)):
        return f"legacy authority fragment seal is incomplete: {semantic_id}"
    assert isinstance(raw_path, str)
    assert isinstance(selector, str)
    assert isinstance(expected, str)
    raw_current = fragment.get("current_path")
    current_digest = fragment.get("current_sha256")
    transition_id = fragment.get("transition_id")
    transitioned = isinstance(raw_current, str)
    if transitioned and not all(
        isinstance(item, str) for item in (current_digest, transition_id)
    ):
        return f"legacy authority current seal is incomplete: {semantic_id}"
    active = str(raw_current) if transitioned else raw_path
    path = (root / active).resolve()
    if not _within(root, path) or not path.is_file():
        return f"legacy authority carrier is missing: {raw_path}"
    if selector == "whole-carrier":
        payload = path.read_bytes()
        expected = current_digest if transitioned else expected
    else:
        if (
            transitioned
            and hashlib.sha256(path.read_bytes()).hexdigest() != current_digest
        ):
            return f"legacy authority current carrier digest changed: {semantic_id}"
        field, separator, selected_id = selector.partition(":")
        if not separator or selected_id != semantic_id:
            return f"legacy authority selector is invalid: {semantic_id}"
        try:
            data = _load_fragment_carrier(path)
        except (OSError, UnicodeError, YamlSubsetError):
            return f"legacy authority carrier is invalid: {raw_path}"
        values = data.get(field) if isinstance(data, dict) else None
        if not isinstance(values, list) or semantic_id not in values:
            return f"legacy authority selector is missing: {semantic_id}"
        payload = f"{selector}\n".encode()
    if hashlib.sha256(payload).hexdigest() != expected:
        return f"legacy authority fragment digest changed: {semantic_id}"
    return None


def _load_fragment_carrier(path: Path) -> Any:
    if path.name.endswith(".legacy.toml"):
        return decode_historical_envelope(path.read_text(encoding="utf-8"))
    return load(path)


def _within(root: Path, path: Path) -> bool:
    try:
        path.relative_to(root)
    except ValueError:
        return False
    return True


def _authority_fragment(
    root: Path, path: Path, semantic_id: str, origin: str
) -> dict[str, str] | None:
    if origin == "legacy_decision":
        if path.suffix != ".md" or not path.is_file():
            return None
        payload = path.read_bytes()
        selector = "whole-carrier"
    else:
        field = origin.partition(":")[2]
        try:
            data = load(path)
        except (OSError, UnicodeError, YamlSubsetError):
            return None
        values = data.get(field, []) if isinstance(data, dict) else []
        if semantic_id not in values:
            return None
        selector = f"{field}:{semantic_id}"
        payload = f"{selector}\n".encode()
    return {
        "path": path.relative_to(root).as_posix(),
        "selector": selector,
        "sha256": hashlib.sha256(payload).hexdigest(),
    }

from __future__ import annotations

import copy
import hashlib
import json
from collections.abc import Mapping
from typing import Any

IMPLEMENT_CRITERIA = (
    "decisions_reconciled",
    "evergreen_current",
    "proof_plan_complete",
    "implementation_plan_complete",
    "implementation_authorized",
    "implementation_complete",
)
IMPLEMENT_WORKFLOWS = (
    "decisions",
    "compile",
    "plan-proof",
    "plan-implementation",
    "implement",
)
IMPLEMENTATION_MODES = frozenset({"lazy", "strict"})
WORKFLOW_PROGRESS = {
    "decisions": "decisions_reconciled",
    "compile": "evergreen_current",
    "plan-proof": "proof_plan_complete",
    "plan-implementation": "implementation_plan_complete",
    "implement": "implementation_complete",
}


class LifecycleClosureError(ValueError):
    pass


def initial_closure(
    public_entrypoint: str,
    mode_id: str | None,
    *,
    implementation_mode: str = "lazy",
) -> dict[str, Any]:
    if public_entrypoint != "dset-implement":
        return {
            "schema_version": "1.0",
            "requested_mode": mode_id,
            "status": "direct",
            "criteria": {},
            "next_workflow": mode_id,
            "reason_code": "DSET-RUNTIME-DIRECT",
            "history": [],
            "visited_states": [],
        }
    if implementation_mode not in IMPLEMENTATION_MODES:
        raise LifecycleClosureError(
            "implementation preparation mode must be lazy or strict"
        )
    if implementation_mode == "strict":
        return _strict_closure()

    closure = {
        "schema_version": "1.0",
        "requested_mode": "implement",
        "implementation_mode": "lazy",
        "status": "active",
        "criteria": {
            "decisions_reconciled": False,
            "evergreen_current": None,
            "proof_plan_complete": None,
            "implementation_plan_complete": None,
            "implementation_authorized": None,
            "implementation_complete": False,
        },
        "next_workflow": "decisions",
        "reason_code": "DSET-RUNTIME-DECISIONS-FIRST",
        "history": [],
        "visited_states": [],
    }
    closure["visited_states"] = [_state_fingerprint(closure)]
    return closure


def advance_closure(
    raw: Mapping[str, Any],
    *,
    workflow_id: str | None = None,
    child_status: str = "succeeded",
    observations: Mapping[str, bool | None] | None = None,
) -> dict[str, Any]:
    closure = _validated_copy(raw)
    if closure["requested_mode"] != "implement":
        raise LifecycleClosureError("direct workflow has no prerequisite closure")
    if closure["implementation_mode"] == "strict":
        return _advance_strict_closure(
            closure,
            workflow_id=workflow_id,
            child_status=child_status,
            observations=observations,
        )
    if closure["status"] in {"completed", "stopped"}:
        raise LifecycleClosureError("closure is terminal")
    expected = closure.get("next_workflow")
    if workflow_id is not None and workflow_id != expected:
        raise LifecycleClosureError(
            f"workflow mismatch: expected {expected}, received {workflow_id}"
        )
    if workflow_id is None and not observations:
        raise LifecycleClosureError("an observation or completed workflow is required")
    if child_status not in {"succeeded", "failed", "stopped", "ambiguous"}:
        raise LifecycleClosureError("invalid child status")
    if workflow_id is not None and child_status != "succeeded":
        closure["status"] = "stopped"
        closure["next_workflow"] = None
        closure["reason_code"] = {
            "failed": "DSET-RUNTIME-CHILD-FAILED",
            "stopped": "DSET-RUNTIME-CHILD-STOPPED",
            "ambiguous": "DSET-RUNTIME-AMBIGUOUS",
        }[child_status]
        closure["history"].append(
            {"workflow_id": workflow_id, "status": child_status, "progress": []}
        )
        return closure

    before = copy.deepcopy(closure["criteria"])
    if observations:
        for key, value in observations.items():
            if key not in IMPLEMENT_CRITERIA:
                raise LifecycleClosureError(f"unknown entry criterion: {key}")
            if value not in {True, False, None}:
                raise LifecycleClosureError(f"invalid criterion value: {key}")
            closure["criteria"][key] = value
    if workflow_id is not None:
        if workflow_id not in IMPLEMENT_WORKFLOWS:
            raise LifecycleClosureError(f"workflow is outside closure: {workflow_id}")
        closure["criteria"][WORKFLOW_PROGRESS[workflow_id]] = True

    progress = [
        key
        for key in IMPLEMENT_CRITERIA
        if before.get(key) != closure["criteria"].get(key)
    ]
    if not progress:
        closure["status"] = "stopped"
        closure["next_workflow"] = None
        closure["reason_code"] = "DSET-RUNTIME-NO-PROGRESS"
    else:
        _select_next(closure)
    if workflow_id is not None:
        closure["history"].append(
            {"workflow_id": workflow_id, "status": child_status, "progress": progress}
        )

    fingerprint = _state_fingerprint(closure)
    if fingerprint in closure["visited_states"]:
        closure["status"] = "stopped"
        closure["next_workflow"] = None
        closure["reason_code"] = "DSET-RUNTIME-REPEATED-STATE"
    else:
        closure["visited_states"].append(fingerprint)
    return closure


def _select_next(closure: dict[str, Any]) -> None:
    criteria = closure["criteria"]
    if criteria["decisions_reconciled"] is not True:
        _set_next(closure, "active", "decisions", "DSET-RUNTIME-DECISIONS-FIRST")
    elif criteria["evergreen_current"] is None:
        _set_next(closure, "blocked", None, "DSET-RUNTIME-CRITERIA-UNKNOWN")
    elif criteria["evergreen_current"] is False:
        _set_next(closure, "active", "compile", "DSET-RUNTIME-COMPILE")
    elif criteria["proof_plan_complete"] is None:
        _set_next(closure, "blocked", None, "DSET-RUNTIME-CRITERIA-UNKNOWN")
    elif criteria["proof_plan_complete"] is False:
        _set_next(closure, "active", "plan-proof", "DSET-RUNTIME-PROOF-PLAN")
    elif criteria["implementation_plan_complete"] is None:
        _set_next(closure, "blocked", None, "DSET-RUNTIME-CRITERIA-UNKNOWN")
    elif criteria["implementation_plan_complete"] is False:
        _set_next(
            closure,
            "active",
            "plan-implementation",
            "DSET-RUNTIME-IMPLEMENTATION-PLAN",
        )
    elif criteria["implementation_authorized"] is not True:
        _set_next(
            closure,
            "authorization-required",
            None,
            "DSET-RUNTIME-AUTHORIZATION-REQUIRED",
        )
    elif criteria["implementation_complete"] is not True:
        _set_next(closure, "ready", "implement", "DSET-RUNTIME-IMPLEMENT")
    else:
        _set_next(closure, "completed", None, "DSET-RUNTIME-COMPLETE")


def _strict_closure() -> dict[str, Any]:
    """Return the implementation-only boundary without a prerequisite chain.

    Readiness is deliberately determined by the selected local implementation
    workflow.  A caller can record a failed authoritative check as an
    observation, but this runtime never substitutes decisions or planning
    work for that stop.
    """

    closure = {
        "schema_version": "1.0",
        "requested_mode": "implement",
        "implementation_mode": "strict",
        "status": "ready",
        "criteria": {
            "decisions_reconciled": None,
            "evergreen_current": None,
            "proof_plan_complete": None,
            "implementation_plan_complete": None,
            "implementation_authorized": None,
            "implementation_complete": False,
        },
        "next_workflow": "implement",
        "reason_code": "DSET-RUNTIME-STRICT-IMPLEMENT",
        "history": [],
        "visited_states": [],
    }
    closure["visited_states"] = [_state_fingerprint(closure)]
    return closure


def _advance_strict_closure(
    closure: dict[str, Any],
    *,
    workflow_id: str | None,
    child_status: str,
    observations: Mapping[str, bool | None] | None,
) -> dict[str, Any]:
    """Advance only the direct implementation or record an exact stop.

    Strict mode accepts no prerequisite child workflow.  The governing
    implementation workflow reports any missing/ambiguous accepted input as
    an observation, preserving its detail in the caller's handoff while this
    runtime provides a stable, machine-readable stop class.
    """

    if closure["status"] in {"completed", "stopped"}:
        raise LifecycleClosureError("closure is terminal")
    if child_status not in {"succeeded", "failed", "stopped", "ambiguous"}:
        raise LifecycleClosureError("invalid child status")
    if workflow_id not in {None, "implement"}:
        raise LifecycleClosureError(
            f"strict implementation accepts only implement, received {workflow_id}"
        )
    if workflow_id == "implement" and child_status != "succeeded":
        closure["status"] = "stopped"
        closure["next_workflow"] = None
        closure["reason_code"] = {
            "failed": "DSET-RUNTIME-CHILD-FAILED",
            "stopped": "DSET-RUNTIME-CHILD-STOPPED",
            "ambiguous": "DSET-RUNTIME-AMBIGUOUS",
        }[child_status]
        closure["history"].append(
            {"workflow_id": workflow_id, "status": child_status, "progress": []}
        )
        return closure

    before = copy.deepcopy(closure["criteria"])
    if observations:
        for key, value in observations.items():
            if key not in IMPLEMENT_CRITERIA:
                raise LifecycleClosureError(f"unknown entry criterion: {key}")
            if value not in {True, False, None}:
                raise LifecycleClosureError(f"invalid criterion value: {key}")
            closure["criteria"][key] = value

    if _strict_inputs_insufficient(closure["criteria"]):
        _set_next(
            closure,
            "stopped",
            None,
            "DSET-RUNTIME-STRICT-INPUTS-INSUFFICIENT",
        )
    elif closure["criteria"]["implementation_authorized"] is False:
        _set_next(
            closure,
            "authorization-required",
            None,
            "DSET-RUNTIME-AUTHORIZATION-REQUIRED",
        )
    elif workflow_id == "implement":
        closure["criteria"]["implementation_complete"] = True
        _set_next(closure, "completed", None, "DSET-RUNTIME-COMPLETE")
    elif observations:
        _set_next(
            closure,
            "ready",
            "implement",
            "DSET-RUNTIME-STRICT-IMPLEMENT",
        )
    else:
        raise LifecycleClosureError("an observation or completed workflow is required")

    progress = [
        key
        for key in IMPLEMENT_CRITERIA
        if before.get(key) != closure["criteria"].get(key)
    ]
    if workflow_id is not None:
        closure["history"].append(
            {"workflow_id": workflow_id, "status": child_status, "progress": progress}
        )
    fingerprint = _state_fingerprint(closure)
    if closure["status"] != "stopped" and fingerprint in closure["visited_states"]:
        closure["status"] = "stopped"
        closure["next_workflow"] = None
        closure["reason_code"] = "DSET-RUNTIME-REPEATED-STATE"
    elif fingerprint not in closure["visited_states"]:
        closure["visited_states"].append(fingerprint)
    return closure


def _strict_inputs_insufficient(criteria: Mapping[str, object]) -> bool:
    return any(
        criteria.get(name) is False
        for name in (
            "decisions_reconciled",
            "evergreen_current",
            "proof_plan_complete",
            "implementation_plan_complete",
        )
    )


def _set_next(
    closure: dict[str, Any], status: str, workflow: str | None, reason: str
) -> None:
    closure["status"] = status
    closure["next_workflow"] = workflow
    closure["reason_code"] = reason


def _validated_copy(raw: Mapping[str, Any]) -> dict[str, Any]:
    closure = copy.deepcopy(dict(raw))
    if closure.get("schema_version") != "1.0":
        raise LifecycleClosureError("unsupported closure schema")
    criteria = closure.get("criteria")
    history = closure.get("history")
    visited = closure.get("visited_states")
    if not isinstance(criteria, dict):
        raise LifecycleClosureError("closure criteria are invalid")
    if not isinstance(history, list) or not isinstance(visited, list):
        raise LifecycleClosureError("closure history is invalid")
    implementation_mode = closure.setdefault("implementation_mode", "lazy")
    if implementation_mode not in IMPLEMENTATION_MODES:
        raise LifecycleClosureError("invalid implementation preparation mode")
    return closure


def _state_fingerprint(closure: Mapping[str, Any]) -> str:
    payload = {
        "requested_mode": closure["requested_mode"],
        "implementation_mode": closure.get("implementation_mode", "lazy"),
        "criteria": closure["criteria"],
        "status": closure["status"],
        "next_workflow": closure["next_workflow"],
        "reason_code": closure["reason_code"],
    }
    encoded = json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return f"state:{hashlib.sha256(encoded).hexdigest()}"

