@dataclass(frozen=True)
class MethodologyDrift:
    carrier: str
    status: str


def methodology_drift(root: Path) -> tuple[MethodologyDrift, ...]:
    """Compare reusable source with the installed project-local methodology."""

    root = root.resolve()
    target = _installed_root(root)
    drift: list[MethodologyDrift] = []
    for source_name, installed_name in ALL_SOURCE_TO_INSTALLED:
        source_root = root / source_name
        installed_root = target / installed_name
        _require_directory(source_root, source_name)
        source_files = _files(source_root)
        installed_files = (
            _files(
                installed_root,
                excluded=IMPLEMENTATION_EXECUTABLE_SUBTREES
                if source_name == "15_layer_implementation"
                else (),
            )
            if installed_root.is_dir()
            else {}
        )
        for relative, source in source_files.items():
            if source.name in SOURCE_ONLY_CARRIERS:
                continue
            destination = installed_root / relative
            if not destination.is_file():
                drift.append(MethodologyDrift(source.name, "missing"))
            elif _sha256(source) != _sha256(destination):
                drift.append(MethodologyDrift(source.name, "changed"))
        for relative, installed in installed_files.items():
            if installed.name in SOURCE_ONLY_CARRIERS:
                continue
            if relative not in source_files:
                drift.append(MethodologyDrift(installed.name, "unexpected"))
    return tuple(sorted(drift, key=lambda item: (item.carrier, item.status)))


def sync_methodology(root: Path, *, execute: bool = False) -> tuple[str, ...]:
    """Preview or materialize source carriers into the installed methodology."""

    root = root.resolve()
    drift = methodology_drift(root)
    unexpected = [item.carrier for item in drift if item.status == "unexpected"]
    if unexpected:
        raise ValueError(
            "installed methodology contains source-less carriers: "
            + ", ".join(unexpected)
        )
    changed = tuple(item.carrier for item in drift)
    if not execute:
        return changed
    target = _installed_root(root)
    for source_name, installed_name in ALL_SOURCE_TO_INSTALLED:
        source_root = root / source_name
        installed_root = target / installed_name
        installed_root.mkdir(parents=True, exist_ok=True)
        for relative, source in _files(source_root).items():
            if source.name in SOURCE_ONLY_CARRIERS:
                continue
            destination = installed_root / relative
            if destination.is_file() and _sha256(source) == _sha256(destination):
                continue
            destination.parent.mkdir(parents=True, exist_ok=True)
            shutil.copyfile(source, destination)
    if methodology_drift(root):
        raise ValueError("installed methodology remains out of sync")
    return changed


def _installed_root(root: Path) -> Path:
    layout = discover_layout(root)
    if not layout.separated:
        raise ValueError("methodology synchronization requires schema 1.5")
    return layout.dset_root / METHODOLOGY_ROOT


def _files(
    root: Path,
    *,
    excluded: tuple[Path, ...] = (),
) -> dict[Path, Path]:
    files: dict[Path, Path] = {}
    for path in sorted(root.rglob("*")):
        if not path.is_file():
            continue
        relative = path.relative_to(root)
        if (
            path.name.startswith(".")
            or path.suffix == ".pyc"
            or "__pycache__" in relative.parts
            or any(relative.is_relative_to(prefix) for prefix in excluded)
        ):
            continue
        files[relative] = path
    return files


def _require_directory(path: Path, identity: str) -> None:
    if not path.is_dir():
        raise FileNotFoundError(f"methodology area is missing: {identity}")


def _sha256(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()

from __future__ import annotations

import re
from collections.abc import Iterator
from pathlib import Path
from typing import Any

from .layout import LAYERS, RepositoryLayout, discover_layout
from .toml_codec import dumps as dump_toml
from .yaml_subset import dump as dump_structured
from .yaml_subset import load


def project_section(root: Path, name: str) -> dict[str, Any]:
    """Read a project registry from settings or its pre-1.4 carrier."""

    layout = discover_layout(root)
    current = layout.recursive or layout.separated
    path = layout.settings_path if current else _legacy_path(layout, name)
    data = load(path)
    if not isinstance(data, dict):
        raise ValueError(f"project carrier must be a mapping: {path}")
    if current:
        value = data.get(name)
        if not isinstance(value, dict):
            raise ValueError(f"settings section is missing or invalid: {name}")
        return value
    return data


def write_project_section(root: Path, name: str, value: dict[str, Any]) -> Path:
    """Replace one registry without discarding documented settings comments."""

    layout = discover_layout(root)
    if not (layout.recursive or layout.separated):
        path = _legacy_path(layout, name)
        path.write_text(dump_structured(value, path), encoding="utf-8")
        return path

    path = layout.settings_path
    text = path.read_text(encoding="utf-8")
    rendered = dump_toml({name: value}).strip()
    start, end = _section_bounds(text, name)
    separator = "\n\n" if start > 0 else ""
    replacement = f"{separator}{rendered}\n"
    updated = f"{text[:start].rstrip()}{replacement}{text[end:].lstrip()}"
    path.write_text(updated, encoding="utf-8")
    return path


def lifecycle_event_files(root: Path) -> Iterator[Path]:
    """Yield atomized lifecycle carriers, or the historical aggregate carrier."""

    layout = discover_layout(root)
    if not (layout.recursive or layout.separated):
        path = layout.structured_file(layout.project_state_root, "lifecycle.toml")
        if path.is_file():
            yield path
        return
    roots = (layout.project_root, *(layout.layer_root(layer) for layer in LAYERS))
    for owner in roots:
        lifecycle = owner / "lifecycle"
        if lifecycle.is_dir():
            yield from sorted(lifecycle.glob("*.toml"))


def lifecycle_events(root: Path) -> list[dict[str, Any]]:
    """Load lifecycle events independent of aggregate or atomized storage."""

    layout = discover_layout(root)
    events: list[dict[str, Any]] = []
    for path in lifecycle_event_files(root):
        data = load(path)
        if not isinstance(data, dict):
            raise ValueError(f"lifecycle carrier must be a mapping: {path}")
        if layout.recursive or layout.separated:
            if isinstance(data.get("event"), dict):
                event = dict(data["event"])
            else:
                event = {
                    key: value
                    for key, value in data.items()
                    if key not in {"schema_version", "artifact_type", "artifact_id"}
                }
                event["id"] = str(data.get("artifact_id", event.get("id", "")))
            events.append(event)
            continue
        raw = data.get("events", [])
        if not isinstance(raw, list):
            raise ValueError(f"lifecycle events must be a list: {path}")
        events.extend(dict(item) for item in raw if isinstance(item, dict))
    return sorted(events, key=lambda item: str(item.get("id", "")))


def _legacy_path(layout: RepositoryLayout, name: str) -> Path:
    paths = {
        "artifact_catalog": layout.artifact_type_registry_path,
        "artifact_structure": layout.artifact_registry_path,
        "governance_registry": layout.governance_path,
        "source_provenance": layout.provenance_path,
        "version_registry": layout.version_path,
    }
    try:
        return paths[name]
    except KeyError as error:
        raise ValueError(f"unknown project registry: {name}") from error


def _section_bounds(text: str, name: str) -> tuple[int, int]:
    header = re.compile(r"(?m)^\[([^\[\]\n]+)\]\s*$")
    matches = list(header.finditer(text))
    start_match = next((match for match in matches if match.group(1) == name), None)
    if start_match is None:
        return len(text), len(text)
    end = len(text)
    prefix = f"{name}."
    for match in matches:
        if match.start() <= start_match.start():
            continue
        section = match.group(1)
        if section != name and not section.startswith(prefix):
            end = match.start()
            break
    return start_match.start(), end

from __future__ import annotations

import json
import os
import re
import tempfile
from collections.abc import Mapping
from contextlib import suppress
from dataclasses import dataclass
from pathlib import Path
from typing import Any

from .frontmatter import FrontmatterError
from .frontmatter import parse as parse_frontmatter
from .layout import RepositoryLayout, discover_layout
from .project_data import project_section, write_project_section
from .yaml_subset import dump, load

_SEMVER = re.compile(
    r"^(0|[1-9][0-9]*)\.(0|[1-9][0-9]*)\.(0|[1-9][0-9]*)"
    r"(?:-rc\.(0|[1-9][0-9]*))?$"
)
RELEASE_CLASSES = {"bootstrap", "small", "normal", "rc", "final", "breaking"}
_FULL_SHA = re.compile(r"^[0-9a-f]{40}$")
_PROJECT_VERSION = re.compile(
    r'(?ms)(^\[project\]\s*$.*?^version\s*=\s*")([^"]+)("\s*$)'
)
_MODULE_VERSION = re.compile(r'(?m)^__version__\s*=\s*"([^"]+)"\s*$')


class ReleaseError(ValueError):
    """A release transaction is incomplete, inconsistent, or unsafe."""


@dataclass(frozen=True, order=True)
class ProductVersion:
    major: int
    minor: int
    patch: int
    rc: int | None = None

    @classmethod
    def parse(cls, raw: str) -> ProductVersion:
        match = _SEMVER.fullmatch(raw)
        if match is None:
            raise ValueError(f"invalid DSET product version: {raw}")
        major, minor, patch, rc = match.groups()
        return cls(int(major), int(minor), int(patch), int(rc) if rc else None)

    @property
    def semver(self) -> str:
        base = f"{self.major}.{self.minor}.{self.patch}"
        return f"{base}-rc.{self.rc}" if self.rc is not None else base

    @property
    def python(self) -> str:
        base = f"{self.major}.{self.minor}.{self.patch}"
        return f"{base}rc{self.rc}" if self.rc is not None else base


def expected_target(
    base: str | None,
    release_class: str,
    *,
    bootstrap_target: str | None = None,
    readiness_passed: bool = False,
) -> ProductVersion:
    if release_class not in RELEASE_CLASSES:
        raise ValueError(f"unknown release class: {release_class}")
    if release_class == "bootstrap":
        if base not in {None, "unversioned"}:
            raise ValueError("bootstrap requires an unversioned base")
        if bootstrap_target is None:
            raise ValueError("bootstrap requires an explicit target")
        target = ProductVersion.parse(bootstrap_target)
        if target.major != 0 or target.rc is not None:
            raise ValueError("bootstrap target must be a stable pre-1.0 version")
        return target
    if base in {None, "unversioned"}:
        raise ValueError(f"{release_class} requires a versioned base")

    current = ProductVersion.parse(base)
    if release_class == "rc":
        if current.rc is not None:
            return ProductVersion(1, 0, 0, current.rc + 1)
        if current.major != 0 or not readiness_passed:
            raise ValueError("the first 1.0 RC requires a passing pre-1.0 base")
        return ProductVersion(1, 0, 0, 1)
    if release_class == "final":
        if current != ProductVersion(1, 0, 0, current.rc) or current.rc is None:
            raise ValueError("final requires a 1.0.0 RC base")
        if not readiness_passed:
            raise ValueError("final requires passing readiness")
        return ProductVersion(1, 0, 0)
    if current.rc is not None:
        raise ValueError("published RCs advance only to a higher RC or final")
    if release_class == "small":
        return ProductVersion(current.major, current.minor, current.patch + 1)
    if release_class == "normal":
        return ProductVersion(current.major, current.minor + 1, 0)
    if release_class == "breaking" and current.major >= 1:
        return ProductVersion(current.major + 1, 0, 0)
    raise ValueError("breaking releases require a stable post-1.0 base")


def validate_coordinated_identity(product: str, python_package: str) -> None:
    version = ProductVersion.parse(product)
    if python_package != version.python:
        raise ValueError(
            "Python package version must be the exact PEP 440 serialization "
            f"of {version.semver}: {version.python}"
        )


@dataclass(frozen=True)
class ReleasePlan:
    owner_change: str
    owner_manifest: str
    release_class: str
    base_ref: str
    base_commit: str
    base_version: str
    candidate_commit: str
    target: str
    python_target: str
    tag: str
    publisher: str
    integration_branch: str
    protected_branch: str
    readiness: str
    surfaces: dict[str, str]
    changes: tuple[str, ...]

    def to_dict(self) -> dict[str, Any]:
        return {
            "owner_change": self.owner_change,
            "owner_manifest": self.owner_manifest,
            "release_class": self.release_class,
            "base": {
                "ref": self.base_ref,
                "commit": self.base_commit,
                "version": self.base_version,
            },
            "candidate_commit": self.candidate_commit,
            "target": self.target,
            "python_target": self.python_target,
            "tag": self.tag,
            "publisher": self.publisher,
            "integration_branch": self.integration_branch,
            "protected_branch": self.protected_branch,
            "readiness": self.readiness,
            "surfaces": dict(self.surfaces),
            "changes": list(self.changes),
            "prepared": not self.changes,
        }


@dataclass(frozen=True)
class ReleasePreparation:
    plan: ReleasePlan
    executed: bool
    changed: tuple[str, ...]

    def to_dict(self) -> dict[str, Any]:
        data = self.plan.to_dict()
        data.update({"executed": self.executed, "changed": list(self.changed)})
        return data


def plan_release(root: Path) -> ReleasePlan:
    """Build one deterministic, read-only plan from the committed declaration."""

    root = root.resolve()
    layout = discover_layout(root)
    manifest = _mapping(load(layout.manifest_path), "project manifest")
    project_release = _mapping(manifest.get("release"), "project release config")
    if project_release.get("status") != "applicable":
        raise ReleaseError("release is not applicable to this project")
    integration = _required_string(project_release, "integration_branch")
    protected = _required_string(project_release, "protected_branch")
    publisher = _required_string(project_release, "publisher")
    tag_pattern = _required_string(project_release, "tag_pattern")
    if publisher != "github":
        raise ReleaseError(f"unsupported release publisher: {publisher}")
    if tag_pattern.count("{product_version}") != 1:
        raise ReleaseError(
            "release tag pattern must contain exactly one {product_version} placeholder"
        )

    prepared_version = _current_product_version(root)
    owner_path, owner, references = _release_owner(
        layout.active_change_roots,
        layout.archive_change_roots,
        prepared_version,
    )
    owner_id = _required_string(owner, "id")
    declaration = _mapping(owner.get("release"), "release declaration")
    release_class = _required_string(declaration, "class")
    if release_class not in RELEASE_CLASSES:
        raise ReleaseError(f"unknown release class: {release_class}")
    for reference_id, target in references:
        if target != owner_id:
            raise ReleaseError(
                "release owner reference must target "
                f"{owner_id}: {reference_id}/{target}"
            )

    base = _mapping(declaration.get("base"), "release base")
    base_ref = _required_string(base, "ref")
    base_commit = _required_string(base, "commit")
    base_version = _required_string(base, "version")
    candidate_commit = _required_string(declaration, "candidate_commit")
    target = _required_string(declaration, "target")
    readiness_relative = _required_string(declaration, "readiness")
    if base_ref != protected:
        raise ReleaseError(
            f"release base ref must be the protected branch {protected}: {base_ref}"
        )
    if _FULL_SHA.fullmatch(base_commit) is None:
        raise ReleaseError("release base commit must be a full SHA")
    if _FULL_SHA.fullmatch(candidate_commit) is None:
        raise ReleaseError("release candidate commit must be a full SHA")
    readiness = _contained_file(owner_path, readiness_relative, "readiness")
    readiness_passed = _readiness_passed(readiness, candidate_commit)

    try:
        computed = expected_target(
            base_version,
            release_class,
            bootstrap_target=target if release_class == "bootstrap" else None,
            readiness_passed=readiness_passed,
        )
    except ValueError as error:
        raise ReleaseError(str(error)) from error
    if computed.semver != target:
        raise ReleaseError(
            f"declared target does not match {release_class} transition: "
            f"{target} != {computed.semver}"
        )
    tag = tag_pattern.replace("{product_version}", computed.semver)
    if re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]*", tag) is None:
        raise ReleaseError(f"rendered release tag is not supported safely: {tag}")

    surfaces = _read_version_surfaces(root)
    changes = tuple(
        sorted(
            {
                _surface_path(root, name)
                for name, value in surfaces.items()
                if value != _surface_target(name, computed)
            }
        )
    )
    return ReleasePlan(
        owner_change=owner_id,
        owner_manifest=RepositoryLayout.structured_file(owner_path, "change.toml")
        .relative_to(root)
        .as_posix(),
        release_class=release_class,
        base_ref=base_ref,
        base_commit=base_commit,
        base_version=base_version,
        candidate_commit=candidate_commit,
        target=computed.semver,
        python_target=computed.python,
        tag=tag,
        publisher=publisher,
        integration_branch=integration,
        protected_branch=protected,
        readiness=readiness.relative_to(root).as_posix(),
        surfaces=surfaces,
        changes=changes,
    )


def check_release(root: Path) -> ReleasePlan:
    """Require every committed release mirror to match its declaration."""

    plan = plan_release(root)
    if plan.changes:
        raise ReleaseError(
            "release is not prepared; mismatched version surfaces: "
            + ", ".join(plan.changes)
        )
    validate_coordinated_identity(plan.target, plan.python_target)
    return plan


def prepare_release(root: Path, *, execute: bool = False) -> ReleasePreparation:
    """Preview or atomically synchronize the declared version surfaces.

    The default is read-only. ``execute=True`` is the explicit repository-write
    boundary. Every file replacement is atomic and a repeated preparation is a
    no-op. Publication is intentionally outside this function.
    """

    root = root.resolve()
    plan = plan_release(root)
    if not execute or not plan.changes:
        return ReleasePreparation(plan, execute, ())
    _require_safe_prepare_inputs(plan)
    layout = discover_layout(root)
    changed: list[str] = []
    version_path = layout.version_path
    if version_path.relative_to(root).as_posix() in plan.changes:
        version_data = _mapping(
            project_section(root, "version_registry"), "version contract"
        )
        framework = _mapping(version_data.get("framework"), "framework version")
        package = _mapping(version_data.get("python_package"), "package version")
        framework["version"] = plan.target
        package["version"] = plan.python_target
        if layout.recursive or layout.separated:
            write_project_section(root, "version_registry", version_data)
        else:
            _atomic_replace_text(version_path, dump(version_data, version_path))
        changed.append(version_path.relative_to(root).as_posix())
    pyproject = root / "pyproject.toml"
    if pyproject.relative_to(root).as_posix() in plan.changes:
        text = pyproject.read_text(encoding="utf-8")
        updated, count = _PROJECT_VERSION.subn(
            lambda match: f"{match.group(1)}{plan.python_target}{match.group(3)}",
            text,
            count=1,
        )
        if count != 1:
            raise ReleaseError("pyproject project version is not uniquely writable")
        _atomic_replace_text(pyproject, updated)
        changed.append(pyproject.relative_to(root).as_posix())
    module = root / "dset_toolchain" / "__init__.py"
    if module.relative_to(root).as_posix() in plan.changes:
        text = module.read_text(encoding="utf-8")
        updated, count = _MODULE_VERSION.subn(
            f'__version__ = "{plan.python_target}"', text, count=1
        )
        if count != 1:
            raise ReleaseError("Python module version is not uniquely writable")
        _atomic_replace_text(module, updated)
        changed.append(module.relative_to(root).as_posix())
    prepared = check_release(root)
    return ReleasePreparation(prepared, True, tuple(changed))


def _release_owner(
    active_roots: tuple[Path, ...],
    archive_roots: tuple[Path, ...],
    prepared_version: str,
) -> tuple[Path, dict[str, Any], list[tuple[str, str]]]:
    declarations: list[tuple[Path, dict[str, Any]]] = []
    references: list[tuple[str, str]] = []
    for root in active_roots:
        if not root.is_dir():
            continue
        for path in sorted(root.iterdir()):
            manifest_path = RepositoryLayout.structured_file(path, "change.toml")
            if path.name == "archive" or not manifest_path.is_file():
                continue
            data = _mapping(load(manifest_path), f"Change manifest {manifest_path}")
            release = data.get("release")
            if not isinstance(release, dict):
                continue
            if "class" in release:
                declarations.append((path, data))
            elif isinstance(release.get("owner_change"), str):
                references.append(
                    (str(data.get("id", path.name)), release["owner_change"])
                )
    if not declarations:
        for root in archive_roots:
            if not root.is_dir():
                continue
            for path in sorted(root.iterdir()):
                manifest_path = RepositoryLayout.structured_file(path, "change.toml")
                if not manifest_path.is_file():
                    continue
                data = _mapping(load(manifest_path), f"Change manifest {manifest_path}")
                release = data.get("release")
                if (
                    isinstance(release, dict)
                    and release.get("target") == prepared_version
                    and "class" in release
                ):
                    declarations.append((path, data))
    if len(declarations) != 1:
        raise ReleaseError(
            f"release preparation requires exactly one owner declaration; "
            f"found {len(declarations)}"
        )
    owner_path, owner = declarations[0]
    return owner_path, owner, references


def _current_product_version(root: Path) -> str:
    version_data = _mapping(
        project_section(root, "version_registry"), "version contract"
    )
    framework = _mapping(version_data.get("framework"), "framework version")
    return _required_string(framework, "version")


def _readiness_passed(path: Path, candidate_commit: str) -> bool:
    try:
        parsed = parse_frontmatter(path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError) as error:
        raise ReleaseError(f"cannot read Readiness Record: {path}") from error
    except FrontmatterError as error:
        raise ReleaseError("Readiness Record frontmatter is invalid") from error
    if parsed is None:
        raise ReleaseError("Readiness Record requires TOML or YAML frontmatter")
    data, _body, _format = parsed
    if (
        not isinstance(data, dict)
        or data.get("artifact_type") != "version"
        or data.get("artifact_subtype") != "readiness_record"
    ):
        raise ReleaseError("release readiness must use a Readiness Record")
    if data.get("candidate_sha") != candidate_commit:
        raise ReleaseError(
            "Readiness Record candidate does not match release candidate"
        )
    for field in ("artifact_id", "version_scope_ref", "release_plan_ref"):
        value = data.get(field)
        if not isinstance(value, str) or not value or value == "pending":
            raise ReleaseError(f"Readiness Record field is incomplete: {field}")
    disposition = data.get("disposition")
    if disposition not in {"ready", "blocked"}:
        raise ReleaseError("Readiness Record disposition must be ready or blocked")
    if disposition != "ready":
        raise ReleaseError("Readiness Record blocks this release candidate")
    return True


def _read_version_surfaces(root: Path) -> dict[str, str]:
    version_data = _mapping(
        project_section(root, "version_registry"), "version contract"
    )
    framework = _mapping(version_data.get("framework"), "framework version")
    package = _mapping(version_data.get("python_package"), "package version")
    pyproject = (root / "pyproject.toml").read_text(encoding="utf-8")
    project_matches = list(_PROJECT_VERSION.finditer(pyproject))
    if len(project_matches) != 1:
        raise ReleaseError("pyproject must contain one [project] version")
    module_text = (root / "dset_toolchain" / "__init__.py").read_text(encoding="utf-8")
    module_matches = _MODULE_VERSION.findall(module_text)
    if len(module_matches) != 1:
        raise ReleaseError("Python module must contain one __version__")
    return {
        "framework": _required_string(framework, "version"),
        "python_package": _required_string(package, "version"),
        "pyproject": project_matches[0].group(2),
        "module": module_matches[0],
    }


def _surface_target(name: str, target: ProductVersion) -> str:
    return target.semver if name == "framework" else target.python


def _surface_path(root: Path, name: str) -> str:
    if name in {"framework", "python_package"}:
        return discover_layout(root).version_path.relative_to(root).as_posix()
    if name == "pyproject":
        return "pyproject.toml"
    if name == "module":
        return "dset_toolchain/__init__.py"
    raise ReleaseError(f"unknown version surface: {name}")


def _require_safe_prepare_inputs(plan: ReleasePlan) -> None:
    target = ProductVersion.parse(plan.target)
    if plan.base_version == "unversioned":
        allowed_products = {target.semver}
        allowed_python = {target.python}
    else:
        base = ProductVersion.parse(plan.base_version)
        allowed_products = {base.semver, target.semver}
        allowed_python = {base.python, target.python}
    for name, current in plan.surfaces.items():
        allowed = allowed_products if name == "framework" else allowed_python
        if current not in allowed:
            raise ReleaseError(
                f"refusing to overwrite unexpected {name} version: {current}"
            )


def _contained_file(root: Path, raw: str, kind: str) -> Path:
    path = (root / raw).resolve()
    try:
        path.relative_to(root.resolve())
    except ValueError as error:
        raise ReleaseError(f"{kind} path escapes the release owner") from error
    if not path.is_file():
        raise ReleaseError(f"{kind} artifact is missing: {raw}")
    return path


def _mapping(raw: Any, name: str) -> dict[str, Any]:
    if not isinstance(raw, dict):
        raise ReleaseError(f"{name} must be a mapping")
    return raw


def _required_string(data: Mapping[str, Any], key: str) -> str:
    value = data.get(key)
    if not isinstance(value, str) or not value:
        raise ReleaseError(f"{key} must be a non-empty string")
    return value


def _atomic_replace_text(path: Path, text: str) -> None:
    descriptor, raw = tempfile.mkstemp(
        prefix=f".{path.name}.", suffix=".tmp", dir=path.parent
    )
    temporary = Path(raw)
    try:
        with os.fdopen(descriptor, "w", encoding="utf-8", newline="") as stream:
            stream.write(text)
            stream.flush()
            os.fsync(stream.fileno())
        os.chmod(temporary, path.stat().st_mode)
        os.replace(temporary, path)
    except Exception:
        with suppress(FileNotFoundError):
            temporary.unlink()
        raise


def rendered_plan(plan: ReleasePlan) -> str:
    return json.dumps(plan.to_dict(), indent=2, sort_keys=True)

from __future__ import annotations

import re
from collections.abc import Sequence
from pathlib import Path

from .layout import (
    LAYER_ID_TOKENS,
    discover_layout,
    normalize_layer_id_token,
)
from .profiles import VALID_PROFILES, required_artifacts
from .settings import load_project_settings
from .yaml_subset import dump, load

TRACE_LAYERS = tuple(LAYER_ID_TOKENS.values())


def create_change(
    root: Path,
    change_id: str,
    package_id: str,
    profile: str,
    title: str | None = None,
    layer: str | None = None,
    stable_id: str | None = None,
    work_areas: Sequence[str] | None = None,
    workspace_mode: str | None = None,
) -> Path:
    if not re.fullmatch(r"[a-z0-9]+(?:-[a-z0-9]+)*", change_id):
        raise ValueError("change ID must be lowercase kebab-case")
    if profile not in VALID_PROFILES:
        raise ValueError(f"unknown profile: {profile}")
    layout = discover_layout(root)
    if layout.layered and layer is None:
        raise ValueError("schema 1.2 changes require an owning DSET layer")
    change_target = _change_target(root, work_areas)
    canonical_id = change_id
    if layout.layered:
        canonical_id = stable_id or _next_change_id(root, str(layer))
        expected = (
            rf"{re.escape(_project_key(root))}-CHANGE-{str(layer).upper()}-[0-9]{{3,}}"
        )
        if re.fullmatch(expected, canonical_id) is None:
            raise ValueError("stable Change ID must match its project and owning layer")
    destination = layout.active_change_root(layer) / change_id
    if destination.exists():
        raise FileExistsError(f"change already exists: {destination}")
    files, directories = required_artifacts(root, profile)
    display_title = title or change_id.replace("-", " ").title()
    project_key = _project_key(root)
    id_layer = _id_layer(root, layer)
    replacements = {
        "{{change_id}}": canonical_id,
        "{{change_slug}}": change_id,
        "{{package_id}}": package_id,
        "{{profile}}": profile,
        "{{title}}": display_title,
        "{{project_key}}": project_key,
        "{{id_layer}}": id_layer,
        "{{layer}}": str(layer).lower() if layer is not None else "",
        "{{repository}}": _repository(root),
    }
    destination.mkdir(parents=True)
    try:
        for directory in sorted(directories):
            (destination / directory).mkdir(parents=True, exist_ok=True)
        for relative in sorted(files):
            template_relative = Path("change") / relative
            relative_path = Path(relative)
            if relative_path.stem == "change" and relative_path.suffix in {
                ".toml",
                ".yaml",
                ".yml",
            }:
                template_family = "layered" if layout.layered else "legacy"
                template_relative = Path("change") / template_family / relative_path
            source = layout.find_template(template_relative)
            target = destination / relative
            _copy_template(source, target, replacements)
        if "specs" in directories:
            source = layout.find_template("change/specs/package.md")
            target = destination / "specs" / f"{package_id}.md"
            _copy_template(source, target, replacements)
        if "proofs" in directories:
            source = layout.find_template("change/proofs/README.md")
            target = destination / "proofs" / "README.md"
            _copy_template(source, target, replacements)
        if "proofs/candidate-fit" in directories:
            source = layout.find_template("change/proofs/candidate-fit/README.md")
            target = destination / "proofs" / "candidate-fit" / "README.md"
            _copy_template(source, target, replacements)
        if layout.layered:
            _materialize_layered_manifest(
                root,
                destination,
                canonical_id,
                change_id,
                str(layer),
                change_target,
                workspace_mode,
            )
    except Exception:
        _remove_tree(destination)
        raise
    return destination


def _copy_template(source: Path, target: Path, replacements: dict[str, str]) -> None:
    if not source.is_file():
        raise FileNotFoundError(f"template is missing: {source}")
    structured = {".toml", ".yaml", ".yml"}
    if target.suffix in structured and source.suffix in structured:
        data = _replace_values(load(source), replacements)
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(dump(data, target), encoding="utf-8")
        return
    text = source.read_text(encoding="utf-8")
    for old, new in replacements.items():
        text = text.replace(old, new)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(text, encoding="utf-8")


def _replace_values(value: object, replacements: dict[str, str]) -> object:
    if isinstance(value, dict):
        return {key: _replace_values(item, replacements) for key, item in value.items()}
    if isinstance(value, list):
        return [_replace_values(item, replacements) for item in value]
    if isinstance(value, str):
        for old, new in replacements.items():
            value = value.replace(old, new)
    return value


def _project_key(root: Path) -> str:
    data = load(discover_layout(root).manifest_path)
    project = data.get("project", {}) if isinstance(data, dict) else {}
    key = project.get("key") if isinstance(project, dict) else None
    if not isinstance(key, str) or not re.fullmatch(r"[A-Z][A-Z0-9]*", key):
        raise ValueError("project.key must be an uppercase ID segment")
    return key


def _id_layer(root: Path, layer: str | None) -> str:
    if layer is None:
        return ""
    normalized = normalize_layer_id_token(layer)
    layout = discover_layout(root)
    if layout.layered:
        return f"-{normalized}"
    data = load(layout.intake_path)
    raw_scopes = data.get("scopes", []) if isinstance(data, dict) else []
    registered = {
        item.get("id_segment")
        for item in raw_scopes
        if isinstance(item, dict) and item.get("kind") == "layer"
    }
    if normalized not in registered:
        raise ValueError(f"unregistered ID layer: {normalized}")
    return f"-{normalized}"


def _repository(root: Path) -> str:
    history = load(discover_layout(root).history_path)
    return str(history["repository"])


def _change_target(
    root: Path, work_areas: Sequence[str] | None
) -> dict[str, object] | None:
    layout = discover_layout(root)
    requested = list(work_areas or ())
    if not layout.layered:
        if requested:
            raise ValueError("work-area targets require schema 1.2")
        return None
    if any(
        not isinstance(identifier, str)
        or re.fullmatch(r"[a-z0-9]+(?:-[a-z0-9]+)*", identifier) is None
        for identifier in requested
    ):
        raise ValueError("work-area targets must be kebab-case IDs")
    if len(requested) != len(set(requested)):
        raise ValueError("work-area targets must be unique")
    manifest = load(layout.manifest_path)
    if not isinstance(manifest, dict):
        raise ValueError("project manifest must be a mapping")
    raw_declared = manifest.get("work_areas", [])
    declared = {
        item.get("id")
        for item in (raw_declared if isinstance(raw_declared, list) else [])
        if isinstance(item, dict) and isinstance(item.get("id"), str)
    }
    unknown = sorted(set(requested) - declared)
    if unknown:
        raise ValueError(f"undeclared work-area target: {', '.join(unknown)}")
    selected = sorted(requested)
    return {"repository": not selected, "work_areas": selected}


def _next_change_id(root: Path, layer: str) -> str:
    layout = discover_layout(root)
    normalized = normalize_layer_id_token(layer)
    prefix = f"{_project_key(root)}-CHANGE-{normalized}-"
    highest = 0
    for change_root in (*layout.active_change_roots, *layout.archive_change_roots):
        if not change_root.is_dir():
            continue
        for directory in change_root.iterdir():
            manifest = layout.structured_file(directory, "change.toml")
            if not directory.is_dir() or not manifest.is_file():
                continue
            data = load(manifest)
            identifier = data.get("id") if isinstance(data, dict) else None
            if isinstance(identifier, str) and identifier.startswith(prefix):
                suffix = identifier.removeprefix(prefix)
                if suffix.isdigit():
                    highest = max(highest, int(suffix))
    return f"{prefix}{highest + 1:03d}"


def _materialize_layered_manifest(
    root: Path,
    destination: Path,
    stable_id: str,
    slug: str,
    layer: str,
    target: dict[str, object] | None,
    workspace_mode: str | None,
) -> None:
    path = discover_layout(root).structured_file(destination, "change.toml")
    data = load(path)
    if not isinstance(data, dict):
        raise ValueError("change template root must be a mapping")
    normalized = layer.lower()
    workspace = _workspace_for_change(root, slug, workspace_mode)
    data.update(
        {
            "schema_version": "1.2",
            "id": stable_id,
            "slug": slug,
            "primary_layer": normalized,
            "affected_layers": [normalized],
            "target": target,
            "workspace": workspace,
            "dependencies": [],
        }
    )
    release = data.get("release")
    if isinstance(release, dict):
        if "policy" in release:
            release["policy"] = ".dset/000_dset_methodology/06_ops/procedure-release.md"
        if "owner_change" in release:
            release["owner_change"] = stable_id
    path.write_text(dump(data, path), encoding="utf-8")


def _workspace_for_change(
    root: Path, slug: str, requested_mode: str | None
) -> dict[str, str]:
    manifest = load(discover_layout(root).manifest_path)
    if not isinstance(manifest, dict):
        raise ValueError("project manifest must be a mapping")
    settings, settings_issues = load_project_settings(root)
    if settings_issues:
        raise ValueError("; ".join(settings_issues))
    mode = requested_mode or settings.change_workspace_mode
    if mode not in {"integration-branch", "branch-worktree"}:
        raise ValueError("workspace mode must be integration-branch or branch-worktree")
    release = manifest.get("release", {})
    integration = (
        release.get("integration_branch") if isinstance(release, dict) else None
    )
    protected = release.get("protected_branch") if isinstance(release, dict) else None
    if not isinstance(integration, str) or not integration:
        integration = "pending"
    if not isinstance(protected, str) or not protected:
        protected = "pending"
    branch = integration if mode == "integration-branch" else f"dset/{slug}"
    base_ref = protected if mode == "integration-branch" else integration
    return {
        "isolation": mode,
        "branch": branch,
        "base_ref": base_ref,
        "base_commit": "pending",
        "head_commit": "pending",
    }


def _remove_tree(path: Path) -> None:
    import shutil

    if path.exists():
        shutil.rmtree(path)

