from __future__ import annotations

import unittest

from dset_toolchain.release import (
    ProductVersion,
    expected_target,
    validate_coordinated_identity,
)


class ReleasePolicyTests(unittest.TestCase):
    def test_transition_matrix(self) -> None:
        cases: tuple[tuple[str, str, bool, str], ...] = (
            ("0.2.4", "small", False, "0.2.5"),
            ("0.2.4", "normal", False, "0.3.0"),
            ("0.9.0", "normal", False, "0.10.0"),
            ("1.4.9", "small", False, "1.4.10"),
            ("1.4.9", "normal", False, "1.5.0"),
            ("1.4.9", "breaking", False, "2.0.0"),
            ("0.9.0", "rc", True, "1.0.0-rc.1"),
            ("1.0.0-rc.4", "rc", False, "1.0.0-rc.5"),
            ("1.0.0-rc.4", "final", True, "1.0.0"),
        )
        for base, release_class, readiness, target in cases:
            with self.subTest(base=base, release_class=release_class):
                self.assertEqual(
                    expected_target(
                        base, release_class, readiness_passed=readiness
                    ).semver,
                    target,
                )

    def test_bootstrap_is_explicit_and_pre_one(self) -> None:
        self.assertEqual(
            expected_target(
                "unversioned", "bootstrap", bootstrap_target="0.3.1"
            ).semver,
            "0.3.1",
        )
        for base, target in (("0.1.0", "0.3.1"), (None, "1.0.0")):
            with self.subTest(base=base, target=target), self.assertRaises(ValueError):
                expected_target(base, "bootstrap", bootstrap_target=target)

    def test_invalid_progressions_fail(self) -> None:
        cases: tuple[tuple[str, str, bool], ...] = (
            ("0.9.0", "rc", False),
            ("1.0.0-rc.1", "small", False),
            ("1.0.0-rc.1", "normal", False),
            ("1.0.0-rc.1", "final", False),
            ("0.4.0", "breaking", False),
            ("1.2.0", "final", True),
        )
        for base, release_class, readiness in cases:
            with (
                self.subTest(base=base, release_class=release_class),
                self.assertRaises(ValueError),
            ):
                expected_target(base, release_class, readiness_passed=readiness)

    def test_rc_identity_has_one_exact_python_mapping(self) -> None:
        version = ProductVersion.parse("1.0.0-rc.12")
        self.assertEqual(version.python, "1.0.0rc12")
        validate_coordinated_identity(version.semver, "1.0.0rc12")
        with self.assertRaises(ValueError):
            validate_coordinated_identity(version.semver, "1.0.0-rc.12")

    def test_semver_parser_rejects_noncanonical_versions(self) -> None:
        for version in ("v1.2.3", "01.2.3", "1.2", "1.0.0-rc0"):
            with self.subTest(version=version), self.assertRaises(ValueError):
                ProductVersion.parse(version)


if __name__ == "__main__":
    unittest.main()

from __future__ import annotations

import unittest
from pathlib import Path
from typing import Any

from dset_toolchain.frontmatter import metadata as frontmatter_metadata
from tests import repository_root

ROOT = repository_root(Path(__file__))
TEMPLATES = ROOT / ".dset/05_layer_ops/templates/release"
PLANNING = ROOT / "10_versions"


class ReleaseArtifactTests(unittest.TestCase):
    def test_release_templates_share_version_classification(self) -> None:
        expected = {
            "version-scope.md": ("version", "version_scope"),
            "roadmap.md": ("version", "roadmap"),
            "release-plan.md": ("version", "release_plan"),
            "readiness-record.md": ("version", "readiness_record"),
            "release-record.md": ("version", "release_record"),
        }
        self.assertEqual(
            {path.name for path in TEMPLATES.glob("*.md") if path.name != "README.md"},
            set(expected),
        )
        for name, classification in expected.items():
            with self.subTest(name=name):
                metadata = self._frontmatter(TEMPLATES / name)
                self.assertEqual(
                    (metadata["artifact_type"], metadata.get("artifact_subtype")),
                    classification,
                )

    def test_dset_self_applies_type_first_release_names(self) -> None:
        expected = {
            "DSET-VERSION-001-0-3-foundation.md": (
                "DSET-VERSION-001",
                "version_scope",
            ),
            "DSET-VERSION-002-0-4-self-hosted-core.md": (
                "DSET-VERSION-002",
                "version_scope",
            ),
            "DSET-VERSION-003-0-5-adopter-ready.md": (
                "DSET-VERSION-003",
                "version_scope",
            ),
            "DSET-VERSION-004-1-0-stable.md": (
                "DSET-VERSION-004",
                "version_scope",
            ),
            "DSET-VERSION-005-0-4-core-vertical-cut.md": (
                "DSET-VERSION-005",
                "roadmap",
            ),
        }
        actual = {path.name for path in PLANNING.glob("DSET-VERSION-00[1-5]-*.md")}
        self.assertEqual(actual, set(expected))
        for name, (artifact_id, subtype) in expected.items():
            with self.subTest(name=name):
                metadata = self._frontmatter(PLANNING / name)
                self.assertEqual(metadata["artifact_id"], artifact_id)
                self.assertEqual(metadata["artifact_subtype"], subtype)

    def test_dset_version_sequence_covers_current_release_carriers(self) -> None:
        expected = {
            PLANNING / "DSET-VERSION-006-0-3-1-release.md": (
                "DSET-VERSION-006",
                "release_plan",
            ),
            PLANNING / "DSET-VERSION-007-0-3-1-readiness.md": (
                "DSET-VERSION-007",
                "readiness_record",
            ),
        }
        for path, (artifact_id, subtype) in expected.items():
            with self.subTest(path=path.name):
                metadata = self._frontmatter(path)
                self.assertEqual(metadata["artifact_type"], "version")
                self.assertEqual(metadata["artifact_id"], artifact_id)
                self.assertEqual(metadata["artifact_subtype"], subtype)

        all_version_ids = [
            self._frontmatter(path)["artifact_id"]
            for path in sorted(PLANNING.glob("DSET-VERSION-*.md"))
        ]
        self.assertEqual(
            all_version_ids,
            [f"DSET-VERSION-{sequence:03d}" for sequence in range(1, 8)],
        )

    def test_release_reference_chain_and_gate_boundaries_are_explicit(self) -> None:
        release_plan = (TEMPLATES / "release-plan.md").read_text(encoding="utf-8")
        readiness = (TEMPLATES / "readiness-record.md").read_text(encoding="utf-8")
        release_record = (TEMPLATES / "release-record.md").read_text(encoding="utf-8")
        self.assertIn("version_scope_ref", release_plan)
        self.assertIn("release_plan_ref", readiness)
        self.assertIn("candidate_sha", readiness)
        self.assertIn("Use exactly `ready` or `blocked`", readiness)
        for field in (
            "version_scope_ref",
            "release_plan_ref",
            "readiness_record_ref",
            "Protected merge SHA",
            "Publisher/forge release",
        ):
            self.assertIn(field, release_record)

    def test_milestone_is_only_a_roadmap_entry(self) -> None:
        roadmap = (TEMPLATES / "roadmap.md").read_text(encoding="utf-8")
        self.assertIn("Milestones are entries in this Roadmap", roadmap)
        self.assertEqual(list(TEMPLATES.glob("*milestone*.md")), [])
        self.assertEqual(list(PLANNING.glob("*MILESTONE*.md")), [])

    def test_live_release_rule_matches_distributed_template(self) -> None:
        live = ROOT / ".dset/05_layer_ops/procedure-release.md"
        template = ROOT / ".dset/05_layer_ops/templates/governance/core-v1/release.md"
        self.assertEqual(
            live.read_text(encoding="utf-8"),
            template.read_text(encoding="utf-8"),
        )

    @staticmethod
    def _frontmatter(path: Path) -> dict[str, Any]:
        metadata = frontmatter_metadata(path)
        if metadata is None:
            raise AssertionError(f"missing frontmatter: {path}")
        return metadata


if __name__ == "__main__":
    unittest.main()

